  CREATE OR REPLACE PACKAGE "CASEMAN"."CDR_PACKAGE" IS

PROCEDURE process_case_data_requests;

END; -- end of cdr_package
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."CDR_PACKAGE" IS

/******************************************************************************************************************/
/* TYPE            : PROCEDURE                                                                                     */
/* NAME            : p_create_case_reset_event                                                                         */
/* DESCRIPTION     : Inserts a case level reset event                                                                   */
/******************************************************************************************************************/
PROCEDURE p_create_case_reset_event
    (
    p_case_no       IN  cases.case_number%TYPE,
    p_cred_code     IN  cases.cred_code%TYPE,
    p_valid         IN OUT VARCHAR2,
    p_reason        IN OUT case_data_request.reason@CCBC_MCOL_LINK%TYPE
    )
IS

CURSOR cur_event_data IS
SELECT
    ce.case_number,
    ce.std_event_id
FROM    case_events ce
WHERE   ce.case_number     = p_case_no
AND     ce.deleted_flag = 'N'
AND     ce.std_event_id IN (72,73,74,75,76,78,79)
AND     ce.case_flag = 'Y'
AND     ce.event_seq =
            (
            SELECT  MAX(ce2.event_seq)
            FROM    case_events ce2
            WHERE   ce2.case_number = p_case_no
            AND     ce2.deleted_flag = 'N'
            AND        ce.case_flag = 'Y'
            AND     ce2.std_event_id IN (72,73,74,75,76,78,79)
            );

BEGIN

    FOR event_rec    IN cur_event_data
        LOOP
            BEGIN

                INSERT INTO mcol_mig_event_data@CCBC_MCOL_LINK
                            (
                            case_number,
                            cred_code,
                            mcol_event_type,
                            event_date,
                            case_party_no,
                            warrant_number,
                            return_code,
                            return_info
                            )
                        VALUES
                        (
                            event_rec.case_number,
                            p_cred_code,
                            DECODE(event_rec.std_event_id,72,'K0',73,'H0',74,'B0',75,'H0',76,'H0',78,'M0',79,'M0'),
                            TRUNC(SYSDATE),
                            NULL,
                            NULL,
                            NULL,
                            NULL
                        );

            EXCEPTION
                WHEN OTHERS THEN
                    BEGIN
                        p_valid     := 'F';
                        p_reason    := 'Oracle Error';
                        DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                        DBMS_OUTPUT.PUT_LINE('while passing warrants to MCOL for case '||p_case_no);
                    END;
            END;
    END LOOP;

END p_create_case_reset_event;

/******************************************************************************************************************/
/* TYPE            : PROCEDURE                                                                                     */
/* NAME            : p_create_def_reset_event                                                                         */
/* DESCRIPTION     : Inserts a defendant level reset event                                                                   */
/******************************************************************************************************************/
PROCEDURE p_create_def_reset_event
    (
    p_case_no       IN  cases.case_number%TYPE,
    p_cred_code     IN  cases.cred_code%TYPE,
    f_case_party_no IN  case_events.case_party_no%TYPE,
    p_valid         IN OUT VARCHAR2,
    p_reason        IN OUT case_data_request.reason@CCBC_MCOL_LINK%TYPE
    )
IS

CURSOR cur_event_data IS
SELECT
    ce.case_number,
    ce.std_event_id
FROM    case_events ce
WHERE   ce.case_number     = p_case_no
AND     ce.deleted_flag = 'N'
AND     ce.std_event_id IN (72,73,74,75,76,78,79)
AND     ce.case_party_no = f_case_party_no
AND     ce.event_seq =
            (
            SELECT  MAX(ce2.event_seq)
            FROM    case_events ce2
            WHERE   ce2.case_number = p_case_no
            AND     ce2.deleted_flag = 'N'
            AND     ce2.std_event_id IN (72,73,74,75,76,78,79)
            AND     ce2.case_party_no = f_case_party_no
            );

BEGIN

    FOR event_rec    IN cur_event_data
        LOOP
            BEGIN

                INSERT INTO mcol_mig_event_data@CCBC_MCOL_LINK
                            (
                            case_number,
                            cred_code,
                            mcol_event_type,
                            event_date,
                            case_party_no,
                            warrant_number,
                            return_code,
                            return_info
                            )
                        VALUES
                        (
                            event_rec.case_number,
                            p_cred_code,
                            DECODE(event_rec.std_event_id,72,'K0',73,'H0',74,'B0',75,'H0',76,'H0',78,'M0',79,'M0'),
                            TRUNC(SYSDATE),
                            f_case_party_no,
                            NULL,
                            NULL,
                            NULL
                        );

       EXCEPTION
            WHEN OTHERS THEN
                BEGIN
                    p_valid     := 'F';
                    p_reason    := 'Oracle Error';
                    DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                    DBMS_OUTPUT.PUT_LINE('while passing warrants to MCOL for case '||p_case_no);
                END;
        END;
    END LOOP;
END p_create_def_reset_event;

/******************************************************************************************************************/
/* TYPE            : PROCEDURE                                                                                    */
/* NAME            : p_status_reset_event_required                                                                */
/* DESCRIPTION    : decides whether or not the case status has been changed via an event 72,73,74,75,76,78,79     */
/*                  but the status has since been reset to NULL.                                                  */
/******************************************************************************************************************/
    PROCEDURE p_status_reset_event_required
        (
        p_case_number   IN cases.case_number%TYPE,
        p_cred_code     IN cases.cred_code%TYPE,
        p_valid         IN OUT VARCHAR2,
        p_reason        IN OUT case_data_request.reason@CCBC_MCOL_LINK%TYPE
        )
    IS

        l_case_status       cases.status%TYPE;
        l_status_set        VARCHAR2(1);
        l_reset_event       BOOLEAN;
        l_defendant_count    NUMBER := 0;

    BEGIN

        l_reset_event := FALSE;

        -- retrieve number of defendants on case
        SELECT     count(*)
        INTO     l_defendant_count
        FROM     case_party_roles cpr
        WHERE     cpr.party_role_code = 'DEFENDANT'
        AND     cpr.case_number     = p_case_number;

        -- Retrieve Case Status
        SELECT     status
        INTO     l_case_status
        FROM     cases
        WHERE     case_number = p_case_number;

        IF  l_case_status IS NULL THEN

            -- Check if a valid status changing event exists for whole event
            SELECT  DECODE(COUNT(*),0,'N','Y')
            INTO    l_status_set
            FROM    case_events ce
            WHERE   ce.case_number = p_case_number
            AND     ce.std_event_id IN (72,73,74,75,76,78,79)
            AND     ce.deleted_flag = 'N'
            AND        ce.case_flag = 'Y'
            AND     ROWNUM = 1;

            IF l_status_set = 'Y' THEN
                -- insert a case level reset event
                p_create_case_reset_event ( p_case_number, p_cred_code, p_valid, p_reason );
            ELSE
                -- if no case level eveny, check that all defendants on case have
                -- an event in the range 72-79

                -- Check if a valid status changing event exists
                -- for defendant 1
                SELECT  DECODE(COUNT(*),0,'N','Y')
                INTO    l_status_set
                FROM    case_events ce
                WHERE   ce.case_number = p_case_number
                AND     ce.std_event_id IN (72,73,74,75,76,78,79)
                AND     ce.deleted_flag = 'N'
                AND        ce.party_role_code = 'DEFENDANT'
                AND        ce.case_party_no = 1
                AND     ROWNUM = 1;

                IF  l_defendant_count = 2     AND
                    l_status_set = 'Y'        THEN
                    -- two defendants
                    -- Check if a valid status changing event exists for both defendants
                    SELECT  DECODE(COUNT(*),0,'N','Y')
                    INTO    l_status_set
                    FROM    case_events ce
                    WHERE   ce.case_number = p_case_number
                    AND     ce.std_event_id IN (72,73,74,75,76,78,79)
                    AND     ce.deleted_flag = 'N'
                    AND        ce.party_role_code = 'DEFENDANT'
                    AND     ce.case_party_no = 2
                    AND     ROWNUM = 1;
                END IF; -- 2nd defendant check.

                IF  l_status_set        = 'Y' THEN
                    IF  l_defendant_count   = 1 THEN
                        -- create reset event for defendant 1
                        p_create_def_reset_event ( p_case_number, p_cred_code, 1, p_valid, p_reason );
                    ELSIF l_defendant_count = 2 THEN
                        -- create reset event for both defendants
                        p_create_def_reset_event ( p_case_number, p_cred_code, 1, p_valid, p_reason );
                        IF p_valid = 'C' THEN
                            -- only insert event for second defendant if 1st insert succeeded
                            p_create_def_reset_event ( p_case_number, p_cred_code, 2, p_valid, p_reason );
                        END IF;
                    END IF; -- no of defendants check
                END IF; -- check for status_set

            END IF; -- check all defendants on case have events
        END IF; -- null status check

    END p_status_reset_event_required;


/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : p_validate_claim                                                                          *
* DESCRIPTION   : Validates the case data request                                                           *
*               : Returns TRUE if case data request is valid with a null reason                             *
*               : Returns False with a failure reason for invalid case data request                 *
\***********************************************************************************************************/
    PROCEDURE p_validate_claim
        (
        p_case_number   IN  cases.case_number%TYPE,
        p_cred_code     OUT cases.cred_code%TYPE,
        p_valid         OUT VARCHAR2,
        p_reason        OUT case_data_request.reason@CCBC_MCOL_LINK%TYPE
        )
    IS

    l_cred_code             cases.cred_code%TYPE;
    l_court_code            cases.admin_crt_code%TYPE;
    l_case_status           cases.status%TYPE;
    l_case_type             cases.case_type%TYPE;
    l_amount                cases.amount_claimed%TYPE;
    l_date                  cases.date_of_issue%TYPE;
    l_partic_length         NUMBER;
    l_invalid_warrant       VARCHAR2(1);
    l_number_claimants      NUMBER;
    l_number_defendants     NUMBER;
    l_claimant_judgments    NUMBER;

    l_error_loc             VARCHAR2(20) := NULL;

    BEGIN

        -- Assume case is valid
        p_valid := 'C';

        BEGIN
            -- check case exists and get basic data for validation checks
            SELECT  c.cred_code, c.admin_crt_code,c.status, c.case_type, c.amount_claimed, c.date_of_issue, length(c.particulars_of_claim)
            INTO    p_cred_code, l_court_code, l_case_status, l_case_type, l_amount, l_date, l_partic_length
            FROM    cases c
            WHERE   c.case_number = p_case_number;

            -- check case belongs to a bulk customer
            IF  p_valid = 'C' AND
                (p_cred_code = 1999 OR p_cred_code IS NULL )    THEN
                -- not a bulk claim customer
                p_valid     := 'F';
                p_reason    := 'NOT BULK CUSTOMER';
            END IF;

            -- check case belongs to a northampton bulk code
/*  commented out for trac #5358
            IF p_valid = 'C' AND l_court_code != 335 THEN
                -- not a bulk claim customer
                p_valid     := 'F';
                p_reason    := 'INVALID COURT';
            END IF;
*/
            -- Check case is not stuck in transfer limbo
            IF  p_valid = 'C' AND l_case_status = 'TRANSFERRED' THEN
                p_valid     := 'F';
                p_reason    := 'TRANSFER ISSUE';
            END IF;

            -- Check the case type - must be equal to CLAIM - SPEC ONLY
            IF  p_valid = 'C' AND l_case_type != 'CLAIM - SPEC ONLY' THEN
                p_valid     := 'F';
                p_reason    := 'INVALID CLAIM TYPE';
            END IF;

            -- Amount claimed on the case cannot exceed 99,999.99
            IF  p_valid = 'C' AND l_amount >= 100000 THEN
                p_valid     := 'F';
                p_reason    := 'INVALID AMOUNT CLAIMED';
            END IF;

            -- Date of Issue cannot be NULL
            IF  p_valid = 'C' AND l_date IS NULL THEN
                p_valid     := 'F';
                p_reason    := 'BLANK ISSUE DATE';
            END IF;

            -- Particulars of Claim cannot exceed 1080 characters in length
            IF  p_valid = 'C' AND l_partic_length > 1080 THEN
                p_valid     := 'F';
                p_reason    := 'INVALID PARTICULARS OF CLAIM';
            END IF;

        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                -- case not found
                p_valid     := 'F';
                p_reason    := 'NON-EXISTANT CASE';
            WHEN OTHERS THEN
                p_valid     := 'F';
                p_reason    := 'Oracle Error';
                DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                DBMS_OUTPUT.PUT_LINE('while checking case');
        END;

        BEGIN
            IF p_valid = 'C' THEN

                l_error_loc := 'warrant';

                SELECT  DECODE(COUNT(*),0,'N','Y')
                INTO    l_invalid_warrant
                FROM    warrants w
                WHERE   w.case_number = p_case_number
                AND     w.issued_by = 335
                AND     w.currently_owned_by = 335
                AND     w.local_warrant_number IS NULL
                AND     w.original_warrant_number IS NULL
                AND     w.defendant2 IS NOT NULL;

                -- Warrants cannot have two parties against recorded on them
                IF  l_invalid_warrant = 'Y' THEN
                    p_valid     := 'F';
                    p_reason    := 'WARRANT AGAINST TWO DEFENDANTS';
                END IF;
            END IF;

            IF p_valid = 'C' THEN

                l_error_loc := 'claimants';

                SELECT  COUNT(*)
                INTO    l_number_claimants
                FROM    case_party_roles cpr, parties p, given_addresses ga
                WHERE   cpr.case_number = p_case_number
                AND     cpr.party_role_code = 'CLAIMANT'
                AND     p.party_id = cpr.party_id
                AND     ga.party_id = cpr.party_id
                AND ga.address_type_code = 'SERVICE'
                AND     ga.valid_to IS NULL;

                -- There can only be one claimant party on the case
                IF  p_valid = 'C' AND l_number_claimants != 1 THEN
                    p_valid     := 'F';
                    p_reason    := 'INVALID NUMBERS OF CLAIMANT PARTIES';
                END IF;
            END IF;

            IF p_valid = 'C' THEN

                l_error_loc := 'defendants';

                SELECT    COUNT(*)
                INTO    l_number_defendants
                FROM    case_party_roles cpr, parties p, given_addresses ga
                WHERE   cpr.case_number = p_case_number
                AND     cpr.party_role_code = 'DEFENDANT'
                AND     p.party_id = cpr.party_id
                AND     ga.party_id = cpr.party_id
                AND ga.address_type_code = 'SERVICE'
                AND     ga.valid_to IS NULL;

                -- There can only be one or two defendant parties on the case
                IF  p_valid = 'C' AND l_number_defendants NOT IN (1,2) THEN
                    p_valid     := 'F';
                    p_reason    := 'INVALID NUMBERS OF DEFENDANT PARTIES';
                END IF;
            END IF;

            IF p_valid = 'C' THEN

                l_error_loc := 'defendants';

                SELECT  COUNT(*)
                INTO    l_claimant_judgments
                FROM    judgments
                WHERE   case_number = p_case_number
                AND     against_party_role_code != 'DEFENDANT';

                -- MCOL does not allow cases with a judgment against the claimant
                IF  p_valid = 'C' AND l_number_defendants NOT IN (1,2) THEN
                    p_valid     := 'F';
                    p_reason    := 'INVALID CASE - Judgment against claimant found';
                END IF;

            END IF;


        END;
    EXCEPTION
        WHEN OTHERS THEN
            BEGIN
                p_valid     := 'F';
                p_reason    := 'Oracle Error';
                DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                DBMS_OUTPUT.PUT_LINE('while checking '||l_error_loc);
            END;
    END p_validate_claim;

/*********** ************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : get_case_data                                                                             *
* DESCRIPTION   : Obtains the requested case data from the caseman application tables                       *
*               : and passes it to the MCOL proxy database migration staging tables                         *
\***********************************************************************************************************/
PROCEDURE get_case_data
        (
        p_case_number   IN cases.case_number%TYPE,
        p_cred_code     IN cases.cred_code%TYPE,
        p_valid         IN OUT VARCHAR2,
        p_reason        OUT case_data_request.reason@CCBC_MCOL_LINK%TYPE
        )
    IS

CURSOR cur_claim_data IS
SELECT  c.case_number,
        c.cred_code,
        ts.mcol_type,
        c.amount_claimed,
        c.court_fee,
        c.solicitors_costs,
        c.date_of_issue,
        c.particulars_of_claim
FROM    cases c,
        cdr_mcol_status_mapping ts
WHERE   c.case_number   = p_case_number
AND     ts.claim_status = NVL(c.status, 'BLANK');

CURSOR cur_party_data IS
SELECT  cpr.case_number,
        cpr.party_role_code,
        cpr.case_party_no,
        cpr.deft_bar_judgment,
        cpr.reference,
        cpr.deft_date_of_service,
        p.person_requested_name,
        p.person_dob,
        ga.address_line1,
        ga.address_line2,
        ga.address_line3,
        ga.address_line4,
        ga.address_line5,
        ga.postcode
FROM    case_party_roles cpr,
    parties p,
    given_addresses ga
WHERE   cpr.case_number = p_case_number
AND     cpr.party_role_code IN ('CLAIMANT','DEFENDANT')
AND     p.party_id = cpr.party_id
AND     ga.party_id = cpr.party_id
AND     ga.address_type_code = 'SERVICE'
AND     ga.valid_to IS NULL;

CURSOR cur_creditor_data IS
SELECT  cpr.case_number,
        cpr.party_role_code,
        cpr.case_party_no,
        cpr.deft_bar_judgment,
        cpr2cpr.personal_reference,
        cpr.deft_date_of_service,
        p.person_requested_name,
        p.person_dob,
        ga.address_line1,
        ga.address_line2,
        ga.address_line3,
        ga.address_line4,
        ga.address_line5,
        ga.postcode,
        p2.person_requested_name as payee_name,
        ga2.address_line1 as payee_address_line1,
        ga2.address_line2 as payee_address_line2,
        ga2.address_line3 as payee_address_line3,
        ga2.address_line4 as payee_address_line4,
        ga2.address_line5 as payee_address_line5,
        ga2.postcode as payee_postcode
FROM    case_party_roles cpr,
        parties p,
        given_addresses ga,
        cpr_to_cpr_relationship cpr2cpr,
        parties p2,
        given_addresses ga2,
        party_to_party_relationship ptpr
WHERE      cpr.case_number = p_case_number
AND        cpr.party_role_code = 'SOLICITOR'
AND        cpr2cpr.cpr_a_case_number = cpr.case_number
AND        cpr2cpr.cpr_a_party_role_code = 'CLAIMANT'
AND        cpr2cpr.cpr_b_case_party_no = cpr.case_party_no
AND        cpr2cpr.deleted_flag = 'N'
AND        p.party_id = cpr.party_id
AND        ga.party_id = cpr.party_id
AND        ga.address_type_code = 'CODED PARTY'
AND        ga.valid_to IS NULL
AND        ptpr.party_a_id (+)= cpr.party_id
AND        ptpr.party_a_role_code (+)= 'SOLICITOR'
AND        ptpr.party_b_role_code (+)= 'NCP PAYEE'
AND        p2.party_id (+)= ptpr.party_b_id
AND        ga2.party_id (+)= ptpr.party_b_id;

CURSOR cur_judg_data IS
SELECT
    j.case_number,
    j.against_case_party_no,
    j.judgment_type,
    j.judgment_date,
    j.status,
    j.joint_judgment,
    NVL(j.judgment_amount, 0) + NVL(j.total_costs,0) - NVL(j.paid_before_judgment,0) as judgment_amount,
    j.paid_before_judgment,
    j.total_costs,
    NVL(v.determination_amount,v.offer_amount) as instalment_amount,
    NVL(v.determination_period,v.offer_period) as instalment_period,
    j.first_payment_date
FROM    judgments j, variations v
WHERE   j.case_number = p_case_number
AND     j.against_party_role_code = 'DEFENDANT'
AND     j.judg_seq =
            (
            SELECT  MAX(j2.judg_seq)
            FROM    judgments j2
            WHERE   j2.case_number = j.case_number
            AND     j2.against_party_role_code = j.against_party_role_code
            AND     j2.against_case_party_no = j.against_case_party_no
            )
AND   v.judg_seq = j.judg_seq
AND   v.vary_seq =
            (
            SELECT MAX(v2.vary_seq)
            FROM variations v2
            WHERE v2.judg_seq = j.judg_seq
            AND   v2.result IN ('GRANTED','DETERMINED')
            )
UNION
SELECT
    j.case_number,
    j.against_case_party_no,
    j.judgment_type,
    j.judgment_date,
    j.status,
    j.joint_judgment,
    NVL(j.judgment_amount, 0) + NVL(j.total_costs,0) - NVL(j.paid_before_judgment,0) as judgment_amount,
    j.paid_before_judgment,
    j.total_costs,
    j.instalment_amount,
    j.instalment_period,
    j.first_payment_date
FROM    judgments j
WHERE   j.case_number = p_case_number -- '9JS00023'
AND     j.against_party_role_code = 'DEFENDANT'
AND     j.judg_seq =
            (
            SELECT   MAX(j2.judg_seq)
            FROM   judgments j2
            WHERE   j2.case_number = j.case_number
            AND    j2.against_party_role_code = j.against_party_role_code
            AND    j2.against_case_party_no = j.against_case_party_no
            )
AND NOT EXISTS
            (
            SELECT     NULL
            FROM     variations v
            WHERE     v.judg_seq = j.judg_seq
            AND     v.result IN ('GRANTED','DETERMINED')
            );

CURSOR cur_warrant_data IS
SELECT  w.case_number,
        w.warrant_number,
        w.balance_after_paid,
        w.warrant_amount,
        w.warrant_fee,
        w.solicitor_costs,
        w.notes,
        w.executed_by,
        w.def1_case_party_no,
        w.warrant_issue_date
FROM    warrants w
WHERE   w.case_number = p_case_number
AND     w.local_warrant_number IS NULL
AND     w.original_warrant_number IS NULL
AND     w.warrant_type IN ('EXECUTION','CONTROL')
AND     w.issued_by = 335
AND     w.currently_owned_by = 335;

CURSOR  cur_event_data IS
SELECT  ce.case_number,
        t.mcol_type,
        ce.event_date,
        ce.case_party_no,
        NULL as warrant_number,
        NULL as return_code,
        NULL as additional_information,
        DECODE( ce.std_event_id, 78, ce.event_date , NULL)  as paid_date
FROM    case_events ce,
        cdr_mcol_event_mapping t
WHERE   ce.case_number = p_case_number
AND     ce.deleted_flag = 'N'
AND     ce.result IS NULL
AND     ce.std_event_id IN
             (
             SELECT   tm.std_event_id
             FROM     cdr_mcol_event_mapping tm
             WHERE    tm.std_event_id NOT IN ( 620, 79 )
             )
AND     t.std_event_id = ce.std_event_id
UNION
SELECT
        ce.case_number,
        t.mcol_type,
        ce.event_date,
        ce.case_party_no,
        w.warrant_number,
        wr.return_code,
        wr.additional_information,
        NULL as paid_date
FROM    case_events ce,
        warrants w,
        warrant_returns wr,
        cdr_mcol_event_mapping t
WHERE   ce.case_number = p_case_number
AND     ce.deleted_flag = 'N'
AND     ce.std_event_id = 620
AND     t.std_event_id = ce.std_event_id
AND     w.warrant_id (+)= ce.warrant_id
AND     w.local_warrant_number IS NULL
AND     w.original_warrant_number IS NULL
AND     w.warrant_type IN ('EXECUTION','CONTROL')
AND     wr.event_seq (+)= ce.event_seq
UNION
SELECT  ce.case_number,
        t.mcol_type,
        ce.event_date,
        ce.case_party_no,
        NULL as warrant_number,
        NULL as return_code,
        NULL as additional_information,
        NVL(j.date_of_final_payment, ce.event_date)  AS paid_date
FROM    case_events ce,
        judgments j,
        cdr_mcol_event_mapping t
WHERE   ce.case_number            = p_case_number
AND     ce.deleted_flag           = 'N'
AND     ce.std_event_id          =  79
AND     t.std_event_id            = ce.std_event_id
AND     j.case_number             = p_case_number
AND     j.against_party_role_code = 'DEFENDANT'
AND     j.judg_seq = ce.judg_seq;

BEGIN

    -- pass the claims data to mcol

    FOR claim_rec    IN cur_claim_data
        LOOP

            BEGIN

                INSERT INTO mcol_mig_claim_data@CCBC_MCOL_LINK
                    (
                    case_number,
                    cred_code,
                    status,
                    amount_claimed,
                    court_fee,
                    solicitors_costs,
                    date_of_issue,
                    particulars_of_claim
                    )
                VALUES
                    (
                    claim_rec.case_number,
                    claim_rec.cred_code,
                    claim_rec.mcol_type,
                    claim_rec.amount_claimed,
                    claim_rec.court_fee,
                    claim_rec.solicitors_costs,
                    claim_rec.date_of_issue,
                    claim_rec.particulars_of_claim
                    );

            EXCEPTION
                WHEN OTHERS THEN
                    BEGIN
                        p_valid     := 'F';
                        p_reason    := 'Oracle Error';
                        DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                        DBMS_OUTPUT.PUT_LINE('while passing data to MCOL for case '||p_case_number);
                    END;
            END;
    END LOOP;

    -- pass the claimant and defendants parties for this case to MCOL
    -- DBMS_OUTPUT.PUT_LINE('case after claims = '||p_valid|| 'inserted '||SQL%ROWCOUNT);
    IF p_valid = 'C' THEN

        FOR party_rec    IN cur_party_data
            LOOP

                BEGIN
                    INSERT INTO mcol_mig_party_data@CCBC_MCOL_LINK
                        (
                        case_number,
                        cred_code,
                        party_role_code,
                        case_party_no,
                        bar_judgment,
                        reference,
                        date_of_service,
                        person_requested_name,
                        person_dob,
                        address_line1,
                        address_line2,
                        address_line3,
                        address_line4,
                        address_line5,
                        postcode,
                        payee_name,
                        payee_address_line1,
                        payee_address_line2,
                        payee_address_line3,
                        payee_address_line4,
                        payee_address_line5,
                        payee_postcode
                        )
                    VALUES
                        (
                        party_rec.case_number,
                        p_cred_code,
                        party_rec.party_role_code,
                        party_rec.case_party_no,
                        party_rec.deft_bar_judgment,
                        party_rec.reference,
                        party_rec.deft_date_of_service,
                        party_rec.person_requested_name,
                        party_rec.person_dob,
                        SUBSTR(party_rec.address_line1,1,30),
                        SUBSTR(party_rec.address_line2,1,30),
                        SUBSTR(party_rec.address_line3,1,30),
                        SUBSTR(party_rec.address_line4,1,30),
                        SUBSTR(party_rec.address_line5,1,30),
                        party_rec.postcode,
                        NULL,
                        NULL,
                        NULL,
                        NULL,
                        NULL,
                        NULL,
                        NULL
                        );

                EXCEPTION
                    WHEN OTHERS THEN
                        BEGIN
                            p_valid     := 'F';
                            p_reason    := 'Oracle Error';
                            DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                            DBMS_OUTPUT.PUT_LINE('while passing claimant and defendants to MCOL for case '||p_case_number);
                        END;
                END;
        END LOOP;

    END IF;

    -- DBMS_OUTPUT.PUT_LINE('case after party data = '||p_valid|| 'inserted '||SQL%ROWCOUNT);

    -- pass the National Coded Party Solicitor party to MCOL
    IF p_valid = 'C' THEN

        FOR creditor_rec    IN cur_creditor_data
            LOOP

                BEGIN
                    INSERT INTO mcol_mig_party_data@CCBC_MCOL_LINK
                        (
                        case_number,
                        cred_code,
                        party_role_code,
                        case_party_no,
                        bar_judgment,
                        reference,
                        date_of_service,
                        person_requested_name,
                        person_dob,
                        address_line1,
                        address_line2,
                        address_line3,
                        address_line4,
                        address_line5,
                        postcode,
                        payee_name,
                        payee_address_line1,
                        payee_address_line2,
                        payee_address_line3,
                        payee_address_line4,
                        payee_address_line5,
                        payee_postcode
                        )
                    VALUES
                        (
                        creditor_rec.case_number,
                        p_cred_code,
                        creditor_rec.party_role_code,
                        creditor_rec.case_party_no,
                        creditor_rec.deft_bar_judgment,
                        creditor_rec.personal_reference,
                        creditor_rec.deft_date_of_service,
                        creditor_rec.person_requested_name,
                        creditor_rec.person_dob,
                        SUBSTR(creditor_rec.address_line1,1,30),
                        SUBSTR(creditor_rec.address_line2,1,30),
                        SUBSTR(creditor_rec.address_line3,1,30),
                        SUBSTR(creditor_rec.address_line4,1,30),
                        SUBSTR(creditor_rec.address_line5,1,30),
                        creditor_rec.postcode,
                        creditor_rec.payee_name,
                        SUBSTR(creditor_rec.payee_address_line1,1,30),
                        SUBSTR(creditor_rec.payee_address_line2,1,30),
                        SUBSTR(creditor_rec.payee_address_line3,1,30),
                        SUBSTR(creditor_rec.payee_address_line4,1,30),
                        SUBSTR(creditor_rec.payee_address_line5,1,30),
                        creditor_rec.payee_postcode
                        );

                EXCEPTION
                    WHEN OTHERS THEN
                        BEGIN
                            p_valid     := 'F';
                            p_reason    := 'Oracle Error';
                            DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                            DBMS_OUTPUT.PUT_LINE('while passing NCP solicitor to MCOL for case '||p_case_number);
                        END;
                END;
        END LOOP;
    END IF;

    -- DBMS_OUTPUT.PUT_LINE('case after NCP = '||p_valid|| 'inserted '||SQL%ROWCOUNT);

    -- pass the judgments for the current case ( if any ) to MCOL.
    IF p_valid = 'C' THEN

        FOR judg_rec    IN cur_judg_data
            LOOP

                BEGIN

                    INSERT INTO mcol_mig_judgment_data@CCBC_MCOL_LINK
                        (
                        case_number,
                        cred_code,
                        against_case_party_no,
                        judgment_type,
                        judgment_date,
                        status,
                        joint_judgment,
                        judgment_amount,
                        paid_before_judgment,
                        total_costs,
                        instalment_amount,
                        instalment_period,
                        first_payment_date
                        )
                    VALUES
                        (
                        judg_rec.case_number,
                        p_cred_code,
                        judg_rec.against_case_party_no,
                        judg_rec.judgment_type,
                        judg_rec.judgment_date,
                        judg_rec.status,
                        judg_rec.joint_judgment,
                        judg_rec.judgment_amount,
                        judg_rec.paid_before_judgment,
                        judg_rec.total_costs,
                        judg_rec.instalment_amount,
                        judg_rec.instalment_period,
                        judg_rec.first_payment_date
                        );

                EXCEPTION
                    WHEN OTHERS THEN
                        BEGIN
                            p_valid     := 'F';
                            p_reason    := 'Oracle Error';
                            DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                            DBMS_OUTPUT.PUT_LINE('while passing judgments to MCOL for case '||p_case_number);
                        END;
                END;
        END LOOP;
    END IF;

    -- DBMS_OUTPUT.PUT_LINE('case after judgments = '||p_valid|| 'inserted '||SQL%ROWCOUNT);

    -- pass the warrants for the current case ( if any ) to MCOL.
    IF p_valid = 'C' THEN

        FOR warrant_rec    IN cur_warrant_data
            LOOP

                BEGIN
                    INSERT INTO mcol_mig_warrant_data@CCBC_MCOL_LINK
                        (
                        case_number,
                        warrant_number,
                        cred_code,
                        balance_after_paid,
                        warrant_amount,
                        warrant_fee,
                        solicitor_costs,
                        notes,
                        executing_court,
                        def1_case_party_no,
                        warrant_issue_date
                        )
                    VALUES
                        (
                        warrant_rec.case_number,
                        warrant_rec.warrant_number,
                        p_cred_code,
                        warrant_rec.balance_after_paid,
                        warrant_rec.warrant_amount,
                        warrant_rec.warrant_fee,
                        warrant_rec.solicitor_costs,
                        warrant_rec.notes,
                        warrant_rec.executed_by,
                        warrant_rec.def1_case_party_no,
                        warrant_rec.warrant_issue_date
                        );

                EXCEPTION
                    WHEN OTHERS THEN
                        BEGIN
                            p_valid     := 'F';
                            p_reason    := 'Oracle Error';
                            DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                            DBMS_OUTPUT.PUT_LINE('while passing warrants to MCOL for case '||p_case_number);
                        END;
                END;
        END LOOP;
    END IF;

    -- DBMS_OUTPUT.PUT_LINE('case after warrants = '||p_valid|| 'inserted '||SQL%ROWCOUNT);

    -- pass the events for the current case ( if any ) to MCOL.
    IF p_valid = 'C' THEN

        FOR event_rec    IN cur_event_data
            LOOP
                BEGIN
                    INSERT INTO mcol_mig_event_data@CCBC_MCOL_LINK
                        (
                        case_number,
                        cred_code,
                        mcol_event_type,
                        event_date,
                        case_party_no,
                        warrant_number,
                        return_code,
                        return_info,
                        paid_date
                        )
                    VALUES
                        (
                        event_rec.case_number,
                        p_cred_code,
                        event_rec.mcol_type,
                        event_rec.event_date,
                        event_rec.case_party_no,
                        event_rec.warrant_number,
                        event_rec.return_code,
                        event_rec.additional_information,
                        event_rec.paid_date
                        );

                EXCEPTION
                    WHEN OTHERS THEN
                        BEGIN
                            p_valid     := 'F';
                            p_reason    := 'Oracle Error';
                            DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                            DBMS_OUTPUT.PUT_LINE('while passing warrants to MCOL for case '||p_case_number);
                        END;
                END;
        END LOOP;
    END IF;

    -- DBMS_OUTPUT.PUT_LINE('case after events = '||p_valid|| 'inserted '||SQL%ROWCOUNT);

    -- Check if an additional event or events for the case status reset is required
    IF  p_valid = 'C'  THEN
        p_status_reset_event_required(p_case_number, p_cred_code, p_valid, p_reason );
    END IF;

    -- DBMS_OUTPUT.PUT_LINE('case after reset events = '||p_valid|| 'inserted '||SQL%ROWCOUNT);

    -- Remove any events linked to final returns 147 or 156
    IF p_valid = 'C' THEN
        DELETE FROM mcol_mig_event_data@CCBC_MCOL_LINK
        WHERE       mcol_event_type = 'FR'
        AND         (return_code IN ('147','156') OR return_code IS NULL);
    END IF;
    -- DBMS_OUTPUT.PUT_LINE('case after delete events = '||p_valid|| 'inserted '||SQL%ROWCOUNT);

END ; -- end of get_case_data

/*********** ************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : process_case_data_requests                                                                *
* DESCRIPTION   : Checks to see if any waiting case data requests                                           *
*               : If the case date request is valid, get the case data and pass it to MCOL                  *
*               : If defence is not valid, tell MCOL the case data request has failed                       *
*               : Returns TRUE if judgement be found                                                        *
\***********************************************************************************************************/

PROCEDURE process_case_data_requests IS

CURSOR cur_get_requests IS
SELECT  request_id,
        case_number,
        caseman_status,
        mcol_populated,
        last_updated,
        reason
FROM    case_data_request@CCBC_MCOL_LINK
WHERE   caseman_status = 'R';

l_failure_reason        VARCHAR2(4000)  := NULL;

l_claim_valid           VARCHAR2(1)     := 'C';

l_completed_requests    NUMBER := 0;
l_failed_requests       NUMBER := 0;

l_cred_code             cases.cred_code%TYPE;

    BEGIN

        -- set application context
        SET_SUPS_APP_CTX('CCBC_BATCH', 335,'process_case_data_requests' );

        -- check for waiting case data requests
        FOR cdr_rec IN cur_get_requests
            LOOP
                -- validate the request
                -- DBMS_OUTPUT.PUT_LINE('Processing CDR for case '||cdr_rec.case_number||
                --                     ' started at '||TO_CHAR(SYSTIMESTAMP,  'DD-MM-YY HH:MI:SS.FF4'));
                p_validate_claim(cdr_rec.case_number, l_cred_code, l_claim_valid, l_failure_reason);

                -- DBMS_OUTPUT.PUT_LINE('case number '||cdr_rec.case_number||' valid = '||l_claim_valid||' reason = '||l_failure_reason);

                IF l_claim_valid = 'C' THEN
                    -- valid claim so get the case data requested
                    get_case_data(cdr_rec.case_number, l_cred_code, l_claim_valid, l_failure_reason);
                END IF;

                IF l_claim_valid = 'F' THEN
                    -- claim has failed
                    cdr_rec.caseman_status  := l_claim_valid;
                    cdr_rec.reason          := l_failure_reason;
                    l_failed_requests       := l_failed_requests + 1;
                ELSE
                    -- claim data has been sent to MCOL
                    cdr_rec.caseman_status  := l_claim_valid;
                    l_completed_requests    := l_completed_requests + 1;
                END IF;

                -- update case data request with results
                UPDATE case_data_request@CCBC_MCOL_LINK
                    SET caseman_status  = cdr_rec.caseman_status,
                        reason          = cdr_rec.reason,
                        last_updated    = SYSTIMESTAMP
                WHERE   request_id      = cdr_rec.request_id;

                -- commit the changes
                COMMIT;
                DBMS_OUTPUT.PUT_LINE('Processed CDR for case '||cdr_rec.case_number||
                                     ' finished at '||TO_CHAR(SYSTIMESTAMP,  'DD-MM-YY HH:MI:SS.FF4'));

            END LOOP;

        DBMS_OUTPUT.PUT_LINE('Completed '||l_completed_requests||' Case Data Requests');
        DBMS_OUTPUT.PUT_LINE('Failed '||l_failed_requests||' Case Data Requests');

        EXCEPTION
            WHEN OTHERS THEN
                DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
                DBMS_OUTPUT.PUT_LINE('while processing case data requests.');
                DBMS_OUTPUT.PUT_LINE('Rolling Back changes');
                ROLLBACK;
                -- re-raise exception so autosys picks up the failure
                RAISE;
    END; -- end of process_case_data_requests
END; -- end of cdr_package
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."CPT_CLAIMS_PACK" IS

/***********************************************************************************************************\
*                                                 P A C K A G E                                            *
\***********************************************************************************************************/

/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : cpt_process_claims                                                                        *
* DESCRIPTION   : Moves claims from MCOL to CASEMAN and generates N1 claims pack and MCOL Issue reports     *
\***********************************************************************************************************/
PROCEDURE cpt_process_claims;

/***********************************************************************************************************\
* TYPE          : FUNCTION                                                                                  *
* NAME          : generate_password                                                                         *
* DESCRIPTION   : Generates MCOL passwords                                                                  *
*                 Note: reuse of CPC code from SP_MCOL_P1.sql (mcol_sups_cpc_package)                       *
\***********************************************************************************************************/
FUNCTION generate_password (in_string VARCHAR2) RETURN VARCHAR2;

/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : format_court_seal                                                                         *
* DESCRIPTION   : formats court name into two centered lines for use on court seal for N1 claims pack       *
*                 Note: reuses code from the CPC SP_BO_U1 shellscript                                       *
\***********************************************************************************************************/
PROCEDURE format_court_seal (
                            court_name  IN  VARCHAR2,
                            seal_1      OUT VARCHAR2,
                            seal_2      OUT VARCHAR2
                            );

END cpt_claims_pack;
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."CPT_CLAIMS_PACK" IS



PROCEDURE format_court_seal (
                            court_name  IN  VARCHAR2,
                            seal_1      OUT VARCHAR2,
                            seal_2      OUT VARCHAR2
                            ) IS

cv_crt_name        VARCHAR2(30);

-- cursor copied from SP_BO_U1 shell script

CURSOR c_crt_name IS
    SELECT decode(ltrim(translate
                        (cv_crt_name,'''ABCDEFGHIJKLMNOPQRSTUVWXYZ()&.,',' ')),
           null,
             lpad(substr(cv_crt_name,1,instr(rpad(cv_crt_name,30),' ',-15)),
               (15 - length(substr(cv_crt_name,1,instr
                                          (rpad(cv_crt_name,30),' ',-15)))) / 2
                   + length(substr(cv_crt_name,1,instr
                                             (rpad(cv_crt_name,30),' ',-15)))),
           lpad(substr(cv_crt_name,1,instr(rpad(cv_crt_name,30),'-',-15)),
             (15 - length(substr(cv_crt_name,1,instr
                                          (rpad(cv_crt_name,30),'-',-15)))) / 2
                 + length(substr(cv_crt_name,1,instr
                                            (rpad(cv_crt_name,30),'-',-15))))),
         decode(ltrim(translate
                        (cv_crt_name,'''ABCDEFGHIJKLMNOPQRSTUVWXYZ()&.,',' ')),
           null,
             lpad(substr(cv_crt_name,instr(rpad(cv_crt_name,30),' ',-15) + 1),
               (15 - length(substr(cv_crt_name,instr
                                      (rpad(cv_crt_name,30),' ',-15) + 1))) / 2
                   + length(substr(cv_crt_name,instr
                                         (rpad(cv_crt_name,30),' ',-15) + 1))),
             lpad(substr(cv_crt_name,instr(rpad(cv_crt_name,30),'-',-15) + 1),
               (15 - length(substr(cv_crt_name,instr
                                      (rpad(cv_crt_name,30),'-',-15) + 1))) / 2
                   + length(substr(cv_crt_name,instr
                                         (rpad(cv_crt_name,30),'-',-15) + 1))))
  FROM DUAL;

/* old version of code retained, as safety measure
    SELECT decode(ltrim(translate
                        (cv_crt_name,'''ABCDEFGHIJKLMNOPQRSTUVWXYZ()&.,',' ')),
           null,
             lpad(substr(cv_crt_name,1,instr(rpad(cv_crt_name,28),' ',-14)),
               (14 - length(substr(cv_crt_name,1,instr
                                          (rpad(cv_crt_name,28),' ',-14)))) / 2
                   + length(substr(cv_crt_name,1,instr
                                             (rpad(cv_crt_name,28),' ',-14)))),
           lpad(substr(cv_crt_name,1,instr(rpad(cv_crt_name,28),'-',-14)),
             (14 - length(substr(cv_crt_name,1,instr
                                          (rpad(cv_crt_name,28),'-',-14)))) / 2
                 + length(substr(cv_crt_name,1,instr
                                            (rpad(cv_crt_name,28),'-',-14))))),
         decode(ltrim(translate
                        (cv_crt_name,'''ABCDEFGHIJKLMNOPQRSTUVWXYZ()&.,',' ')),
           null,
             lpad(substr(cv_crt_name,instr(rpad(cv_crt_name,28),' ',-14) + 1),
               (14 - length(substr(cv_crt_name,instr
                                      (rpad(cv_crt_name,28),' ',-14) + 1))) / 2
                   + length(substr(cv_crt_name,instr
                                         (rpad(cv_crt_name,28),' ',-14) + 1))),
             lpad(substr(cv_crt_name,instr(rpad(cv_crt_name,28),'-',-14) + 1),
               (14 - length(substr(cv_crt_name,instr
                                      (rpad(cv_crt_name,28),'-',-14) + 1))) / 2
                   + length(substr(cv_crt_name,instr
                                         (rpad(cv_crt_name,28),'-',-14) + 1))))
  FROM DUAL;
*/

BEGIN

    cv_crt_name := court_name;
    OPEN    c_crt_name;
    FETCH   c_crt_name INTO seal_1, seal_2;
    CLOSE   c_crt_name;

    -- if second seal is blank, only print the 1st seal line
    -- at the second seal line position.
    IF  seal_2 IS NULL THEN
        seal_2 := seal_1;
        seal_1 := NULL;
    END IF;

END format_court_seal;

FUNCTION generate_password (in_string VARCHAR2) RETURN VARCHAR2 IS

/* 8-character input string is used as a seed to generate a random
 * 8 characters and returns it
 */

    nv_1        NUMBER        := 0;
    cv_str      VARCHAR2(8);
    cv_upper    VARCHAR2(8);
    cv_result   VARCHAR2(8)   := NULL;

  BEGIN

    cv_str := lpad(in_string,8,'vT7kQ3sP');

    dbms_random.seed(cv_str);
    cv_upper := dbms_random.string('X',8);

    FOR i IN 1 .. 8
    LOOP
       nv_1 := floor(dbms_random.value(0,2));
       IF nv_1 > 0 THEN
          cv_result := cv_result||lower(substr(cv_upper,i,1));
       ELSE
          cv_result := cv_result||substr(cv_upper,i,1);
       END IF;
    END LOOP;

    cv_result := replace(cv_result,'1','2');
    cv_result := replace(cv_result,'l','L');
    cv_result := replace(cv_result,'0','9');
    cv_result := replace(cv_result,'O','P');
    RETURN cv_result;
  END generate_password;

PROCEDURE cpt_process_claims
AS

-- count number of claims
CURSOR      cur_claim_count IS
  SELECT      COUNT(*)
  FROM      claim_requests@cpt_mcol_link cr,
            tape_files@cpt_mcol_link tf
  WHERE     cr.tape_file_seq = tf.tape_file_seq
  AND       tf.status = 'L'
  ORDER BY  cr.tape_file_seq;

  -- get claim details for processing

  CURSOR    cur_requests IS
    SELECT  cr.tape_file_seq,
            cr.coded_creditor,
            cr.claim_number,
            cr.court_code,
            cr.claim_amount,
            cr.court_fee,
            cr.solicitors_costs,
            cr.total_amount,
            cr.claimant_name_1,
            cr.claimant_name_2,
            cr.claimant_addr_1,
            cr.claimant_addr_2,
            cr.claimant_addr_3,
            cr.claimant_addr_4,
            cr.claimant_addr_5,
            cr.claimant_postcode,
            cr.solicitor_reference,
            cr.def1_name_1,
            cr.def1_name_2,
            cr.def1_addr_1,
            cr.def1_addr_2,
            cr.def1_addr_3,
            cr.def1_addr_4,
            cr.def1_addr_5,
            cr.def1_postcode,
            cr.def2_name_1,
            cr.def2_name_2,
            cr.def2_addr_1,
            cr.def2_addr_2,
            cr.def2_addr_3,
            cr.def2_addr_4,
            cr.def2_addr_5,
            cr.def2_postcode,
            cr.def1_password,
            cr.def2_password,
            cr.claim_particulars_1,
            cr.claim_particulars_2,
            cr.claim_particulars_3,
            cr.claim_particulars_4,
            cr.claim_particulars_5,
            cr.claim_particulars_6,
            cr.claim_particulars_7,
            cr.claim_particulars_8,
            cr.claim_particulars_9,
            cr.claim_particulars_10,
            cr.claim_particulars_11,
            cr.claim_particulars_12,
            cr.claim_particulars_13,
            cr.claim_particulars_14,
            cr.claim_particulars_15,
            cr.claim_particulars_16,
            cr.claim_particulars_17,
            cr.claim_particulars_18,
            cr.claim_particulars_19,
            cr.claim_particulars_20,
            cr.claim_particulars_21,
            cr.claim_particulars_22,
            cr.claim_particulars_23,
            cr.claim_particulars_24,
            cr.corres_rep_name,
            cr.corres_rep_addr_1,
            cr.corres_rep_addr_2,
            cr.corres_rep_addr_3,
            cr.corres_rep_addr_4,
            cr.corres_rep_addr_5,
            cr.corres_rep_postcode,
            cr.solicitor,
            cr.name_on_partics,
            cr.claimant_rep_fax_no,
            cr.claimant_rep_email,
            cr.status
  FROM      claim_requests@cpt_mcol_link cr,
            tape_files@cpt_mcol_link tf
  WHERE     cr.tape_file_seq = tf.tape_file_seq
  AND       tf.status = 'L'
  ORDER BY  cr.tape_file_seq;

-- declare table of records for bulk fetch of claims
TYPE requests_tab IS TABLE OF cur_requests%ROWTYPE
INDEX BY PLS_INTEGER;

lst_requests    requests_tab;
empty_requests  requests_tab;



-- declare table of records for tape_file_seq numbers
TYPE tape_seq_tab IS TABLE OF tape_files.tape_file_seq@cpt_mcol_link%TYPE
INDEX BY PLS_INTEGER;

lst_tape_seq    tape_seq_tab;
empty_tape_seq    tape_seq_tab;

-- index used for accessing above array
tape_idx    NUMBER    := 1;

--cursor to check that coded_creditor exists in CASEMAN
CURSOR cur_party_chk (creditor NUMBER) IS
    SELECT ncp.code
    FROM   national_coded_parties ncp
    WHERE  ncp.code = creditor;

n_ncp_code   national_coded_parties.code%TYPE;

CURSOR  cur_get_dates IS
SELECT  TRUNC(SYSDATE) issue_date,
        TRUNC(SYSDATE + 5 ) service_date
FROM    dual;

rec_date    cur_get_dates%ROWTYPE;

-- cursor to get the number of records to be loaded from the
-- mcol tape files table

CURSOR  cur_get_tape_file_seq IS
SELECT  SUM(no_records)
FROM    tape_files@cpt_mcol_link tf
WHERE   STATUS = 'L';

-- cursor to get mcol address
CURSOR cur_get_mcol_addr IS
    SELECT  'Money Claims Online' name,
        cp.address_line1,
        cp.address_line2,
        cp.address_line3,
        cp.address_line4,
        cp.address_line5,
        cp.postcode,
        p.tel_no
    FROM    coded_parties cp,
            parties p
    WHERE   p.party_id = cp.party_id
    AND     code = 1999;

-- cursor to get bulk address

CURSOR cur_get_bulk_addr IS
    SELECT  c.name,
        ga.address_line1,
        ga.address_line2,
        ga.address_line3,
        ga.address_line4,
        ga.address_line5,
        ga.postcode,
        c.tel_no
    FROM    courts c,
            given_addresses ga
    WHERE   ga.court_code = c.code
    AND     ga.address_type_code = 'OFFICE'
    AND     c.code = 335;

-- cursor get claimant phone for bulk claims
CURSOR cur_get_claimant_tel (coded_party VARCHAR2) IS
    SELECT p.tel_no
    FROM    parties p,
            coded_parties cp
    WHERE   p.party_id = cp.party_id
    AND     cp.code = coded_party;

n_rejected_count    NUMBER  := 0;
n_accepted_count    NUMBER  := 0;
n_rej_code          NUMBER  := 24;  -- new rejected code indicating that coded creditor is not
                                    -- found in CASEMAN

n_accepted_court_fees_total NUMBER  := 0;
n_rejected_court_fees_total NUMBER  := 0;

v_password_1          VARCHAR2(8);
v_password_2          VARCHAR2(8);

-- Declare collections to store records which will be inserted into database
-- using bulk collection inserts
-- Note: empty collections are created to be used in clearing the main collections
--       for reuse

-- Declare collections to store records which will be inserted into database
-- using bulk collection inserts

TYPE mcol_data_tab IS TABLE OF mcol_data@cpt_mcol_link%ROWTYPE
INDEX BY PLS_INTEGER;

lst_mcol    mcol_data_tab;
empty_mcol    mcol_data_tab;

TYPE statistics_tab IS TABLE OF cpt_statistics%ROWTYPE
INDEX BY PLS_INTEGER;

lst_statistics      statistics_tab;
empty_statistics    statistics_tab;

TYPE claims_tab IS TABLE OF cpt_claims%ROWTYPE
INDEX BY PLS_INTEGER;

lst_claims          claims_tab;
empty_claims        claims_tab;

TYPE defendants_tab IS TABLE OF cpt_defendants%ROWTYPE
INDEX BY PLS_INTEGER;

lst_defendants      defendants_tab;
empty_defendants    defendants_tab;

TYPE caseman_tab IS TABLE OF load_cases%ROWTYPE
INDEX BY PLS_INTEGER;

lst_cases           caseman_tab;
empty_cases         caseman_tab;

TYPE printed_tab IS TABLE OF cpt_print_claims%ROWTYPE
INDEX BY PLS_INTEGER;

lst_printed         printed_tab;
empty_printed       printed_tab;

-- declare address record

TYPE address_rec IS RECORD
    (
    name                courts.name%TYPE,
    address_line1       given_addresses.address_line1%TYPE,
    address_line2       given_addresses.address_line2%TYPE,
    address_line3       given_addresses.address_line3%TYPE,
    address_line4       given_addresses.address_line4%TYPE,
    address_line5       given_addresses.address_line5%TYPE,
    postcode            given_addresses.postcode%TYPE,
    telephone_no        courts.tel_no%TYPE
    );

mcol_address    address_rec;
bulk_address    address_rec;

-- offset and index used to store second defendant in lst_defendants
-- without overwriting 1st defendant

deft2_index_offset  NUMBER := 0;
deft2_idx           NUMBER := 0;

-- strings used to store current operation details
-- used in writing error messages

current_statement     VARCHAR2(200)     := NULL;
current_claim         VARCHAR2(10)      :=NULL;

claim_count            NUMBER            := NULL;
expected_claims     NUMBER          := NULL;
nv_omr_code         NUMBER          := 1;
nv_rec_no            NUMBER            := 1;

-- court seal variables

court_seal_1         VARCHAR2(15)       := NULL;
court_seal_2         VARCHAR2(15)       := NULL;

BEGIN

    DBMS_OUTPUT.ENABLE(1000000);
    DBMS_OUTPUT.PUT_LINE('Starting to process claims at '||TO_CHAR(SYSDATE, 'DD/MM/YYYY HH24:MI:SS'));
    DBMS_OUTPUT.PUT_LINE('.');

    current_statement := 'getting count of claims';

    OPEN    cur_claim_count;
    FETCH   cur_claim_count INTO claim_count;
    CLOSE   cur_claim_count;

    -- get expected  no of records from the MCOL tape files table.

    current_statement := 'getting expected claims';

    OPEN    cur_get_tape_file_seq;
    FETCH   cur_get_tape_file_seq INTO expected_claims;
    CLOSE   cur_get_tape_file_seq;

    current_statement := 'Comparing expected claims to actual claims found';

    IF claim_count != expected_claims THEN
        -- We have a mismatch so raise an error and exit
        DBMS_OUTPUT.PUT_LINE('ERROR Expected Claims '||expected_claims||' Actual Claims '||claim_count);
        RAISE_APPLICATION_ERROR(-20001,'Expected Number of Claims not found');
    END IF;

    current_statement := 'Setting dates';

    OPEN  cur_get_dates;
    FETCH cur_get_dates INTO rec_date;
    CLOSE cur_get_dates;

    DBMS_OUTPUT.PUT_LINE('issue date   is  '||TO_CHAR(rec_date.issue_date, 'DD/MM/YYYY HH24:MI:SS'));
    DBMS_OUTPUT.PUT_LINE('Service date is  '||TO_CHAR(rec_date.service_date, 'DD/MM/YYYY HH24:MI:SS'));
    DBMS_OUTPUT.PUT_LINE('.');

    -- populate the MCOL Claims addresses.
    -- using MCOL party id of 1999

    OPEN    cur_get_mcol_addr;
    FETCH   cur_get_mcol_addr INTO mcol_address;
    CLOSE   cur_get_mcol_addr;

    -- populate the bulk claims address
    -- using court code of 335 for northampton bulk claims court

    OPEN    cur_get_bulk_addr;
    FETCH   cur_get_bulk_addr INTO bulk_address;
    CLOSE   cur_get_bulk_addr;

    -- generate the court seal lines
    -- Note: Both MCOL and the BULK claims use the same court name
    -- for court 335

    format_court_seal   (
                        bulk_address.name,
                        court_seal_1,
                        court_seal_2
                        );

    -- get all unprocessed claims,

    current_statement := 'Bulk collect fetch of claims';

    OPEN cur_requests;
    LOOP
        -- this will process all claims in batchs of up to 5000 claims at time.
        -- This value may need to be adjusted depending on memory available and
        -- performance on the live environment. It is currently set to 5000 which
        -- should process all the claims we expect to get in a day in a single batch.
        FETCH cur_requests BULK COLLECT INTO lst_requests LIMIT 5000;

        deft2_index_offset := lst_requests.count + 100;

        -- process the claims we found
        FOR request_idx IN 1..lst_requests.COUNT
            LOOP
                -- record tape_file_seq

                IF      lst_tape_seq.EXISTS(tape_idx) = FALSE THEN
                        -- record the 1st tape file sequence
                        current_statement := 'recording 1st tape file seq tape idx = '||tape_idx;
                        lst_tape_seq(tape_idx) := lst_requests(request_idx).tape_file_seq;
                ELSIF   lst_tape_seq(tape_idx) != lst_requests(request_idx).tape_file_seq THEN
                        -- when the tape file seq changes record the new tape file seq
                        current_statement := 'recording new tape file seq tape idx = '||tape_idx;
                        tape_idx := tape_idx + 1;
                        lst_tape_seq(tape_idx) := lst_requests(request_idx).tape_file_seq;
                END IF;

                -- record claim for use in exception handler.
                current_claim := TO_CHAR(lst_requests(request_idx).claim_number);

                -- make sure the coded creditor is known to CASEMAN

                current_statement := 'Checking coded creditor for claim '||TO_CHAR(lst_requests(request_idx).claim_number);

                OPEN cur_party_chk ( lst_requests(request_idx).coded_creditor);
                FETCH cur_party_chk INTO n_ncp_code;
                IF cur_party_chk%FOUND THEN
                    --coded creditor has been found on CASEMAN, so process the claim

                    -- clear any old passwords
                    v_password_1 := NULL;
                    v_password_2 := NULL;

                    -- generate new passwords for the 1st mandatory defendant
                    v_password_1 := generate_password
                                        (substr(lst_requests(request_idx).def1_name_1||lst_requests(request_idx).def1_name_2,4,4)||
                                        substr(lst_requests(request_idx).claim_number,6,3)||'1');
                    lst_requests(request_idx).def1_password := v_password_1;
                    -- generate password for optional second defendant if they exist
                    IF lst_requests(request_idx).def2_name_1||lst_requests(request_idx).def2_name_2 IS NOT NULL THEN
                        v_password_2 := generate_password
                                        (substr(lst_requests(request_idx).def2_name_1||lst_requests(request_idx).def2_name_2,4,4)||
                                        substr(lst_requests(request_idx).claim_number,6,3)||'2');
                        lst_requests(request_idx).def2_password := v_password_2;
                    END IF; -- def2 if statement

                    -- add the claim to the statistics collection

                    current_statement := 'Storing Statistics for '||TO_CHAR(lst_requests(request_idx).claim_number);

