                    lst_printed(request_idx).help_text_1            :=  'Important Note';
                    lst_printed(request_idx).help_text_2            :=  '.';
                    lst_printed(request_idx).help_text_3            :=  'You have a limited time in which to reply to';
                    lst_printed(request_idx).help_text_4            :=  'this claim form';
                    lst_printed(request_idx).help_text_5            :=  '.';
                    lst_printed(request_idx).help_text_6            :=  'Please read all the guidance notes on the';
                    lst_printed(request_idx).help_text_7            :=  'back of this form - they set out the time limits';
                    lst_printed(request_idx).help_text_8            :=  'and tell you what you can do about the claim';
                    lst_printed(request_idx).help_text_9            :=  '.';
                    lst_printed(request_idx).help_text_10           :=  'You can respond to this claim online. Log on';
                    lst_printed(request_idx).help_text_11           :=  'to' ;
                    lst_printed(request_idx).help_text_12           :=  'www.moneyclaim.gov.uk';
                    lst_printed(request_idx).help_text_13           :=  '.' ;
                    lst_printed(request_idx).help_text_14           :=  'You will need the claim number';
                    lst_printed(request_idx).help_text_15           :=  '(see above)';
                    lst_printed(request_idx).help_text_16           :=  'and the following password';
                    lst_printed(request_idx).help_text_17           :=  lst_requests(request_idx).def1_password;
                    lst_printed(request_idx).p2_claimant_name_1     :=  lst_requests(request_idx).claimant_name_1;
                    lst_printed(request_idx).p2_claimant_name_2     :=  lst_requests(request_idx).claimant_name_2;
                    lst_printed(request_idx).p2_deft_name_1         :=  lst_requests(request_idx).def1_name_1;
                    lst_printed(request_idx).p2_deft_name_2         :=  lst_requests(request_idx).def1_name_2;
                    lst_printed(request_idx).p2_help_text_1         := 'If you want to defend all or part of this claim or request';
                    lst_printed(request_idx).p2_help_text_2         := 'additional time to prepare your defence you can respond';
                    lst_printed(request_idx).p2_help_text_3         := 'online, by logging on to';
                    lst_printed(request_idx).p2_help_text_4         := 'www.moneyclaim.gov.uk';
                    lst_printed(request_idx).p2_help_text_5         := 'You will need the claim number and password from the';
                    lst_printed(request_idx).p2_help_text_6         := 'front of the claim form.';
                    lst_printed(request_idx).p2_help_text_7         := 'More help and information can be found online or by';
                    lst_printed(request_idx).p2_help_text_8         := 'telephoning the court on the number shown on the front';
                    lst_printed(request_idx).p2_help_text_9         := 'of the claim form.';
                    -- calculate N1 page counts
                    lst_printed(request_idx).page_1_count           := (request_idx * 4) - 3;
                    lst_printed(request_idx).page_2_count           := (request_idx * 4) - 2;
                    lst_printed(request_idx).page_3_count           := (request_idx * 4) - 1;
                    lst_printed(request_idx).page_4_count           := (request_idx * 4);

                    -- set court address to either the MCOL address if the coded_creditor is 1999
                    -- or the bulk claims court. Note: legacy code puts postcode in address 5 so
                    -- we have to do the same
                    IF lst_requests(request_idx).coded_creditor = 1999 THEN
                        -- use the mcol address
                        lst_printed(request_idx).court_address_1        :=  mcol_address.name;
                        lst_printed(request_idx).court_address_2        :=  mcol_address.address_line1;
                        lst_printed(request_idx).court_address_3        :=  mcol_address.address_line2;
                        lst_printed(request_idx).court_address_4        :=  mcol_address.address_line3;
                        lst_printed(request_idx).court_address_5        :=  mcol_address.postcode;
                        lst_printed(request_idx).court_postcode         :=  NULL;
                        lst_printed(request_idx).p2_court_address       :=  mcol_address.name||' '||
                                                                            mcol_address.address_line1||' '||
                                                                            mcol_address.address_line2||' '||
                                                                            mcol_address.address_line3||' '||
                                                                            mcol_address.postcode;
                        lst_printed(request_idx).court_tel_number       :=  mcol_address.telephone_no;
                        -- no claimant telephone for MCOL claims
                        lst_printed(request_idx).claimant_tel_number    := NULL;
                    ELSE
                        -- use the bulk claims address
                        lst_printed(request_idx).court_address_1        :=  bulk_address.name;
                        lst_printed(request_idx).court_address_2        :=  bulk_address.address_line1;
                        lst_printed(request_idx).court_address_3        :=  bulk_address.address_line2;
                        lst_printed(request_idx).court_address_4        :=  bulk_address.address_line3;
                        lst_printed(request_idx).court_address_5        :=  bulk_address.postcode;
                        lst_printed(request_idx).court_postcode         :=  NULL;
                        lst_printed(request_idx).p2_court_address       :=  bulk_address.name||' '||
                                                                            bulk_address.address_line1||' '||
                                                                            bulk_address.address_line2||' '||
                                                                            bulk_address.address_line3||' '||
                                                                            mcol_address.postcode;
                        lst_printed(request_idx).court_tel_number       :=  bulk_address.telephone_no;
                        -- claimant telephone is set for  bulk claims
                        OPEN cur_get_claimant_tel (lst_requests(request_idx).coded_creditor);
                        FETCH cur_get_claimant_tel INTO lst_printed(request_idx).claimant_tel_number;
                        CLOSE cur_get_claimant_tel;

                    END IF;

                    -- increment omr code and rec_no in preparation for
                    -- inserting the next print claims record
                    nv_rec_no := nv_rec_no + 1;
                    IF nv_omr_code = 7 THEN
                        nv_omr_code := 1;
                    ELSE
                        nv_omr_code := nv_omr_code + 1;
                    END IF;

                    IF lst_requests(request_idx).def2_name_1||lst_requests(request_idx).def2_name_2 IS NOT NULL THEN
                        -- if there is a second defendant, insert a second record with the 1st and 2nd defendant details
                        -- swapped over. use the deft2_idx offset to avoid overwriting the 1st printed_claim record
                        lst_printed(deft2_idx).rec_no                 :=  nv_rec_no;
                        lst_printed(deft2_idx).omr_code               :=  nv_omr_code;
                        -- note: Welsh language message is no longer printed
                        lst_printed(deft2_idx).welsh_1                :=  NULL;
                        lst_printed(deft2_idx).welsh_2                :=  NULL;
                        lst_printed(deft2_idx).welsh_3                :=  NULL;
                        lst_printed(deft2_idx).welsh_4                :=  NULL;
                        lst_printed(deft2_idx).creditor_code          :=  lst_requests(request_idx).coded_creditor;
                        lst_printed(deft2_idx).bar_code               :=  lst_requests(request_idx).claim_number||TO_CHAR(2);
                        lst_printed(deft2_idx).claim_number           :=  lst_requests(request_idx).claim_number;
                        lst_printed(deft2_idx).court_code             :=  lst_requests(request_idx).court_code;
                        lst_printed(deft2_idx).court_name             :=  bulk_address.name;
                        lst_printed(deft2_idx).court_name_seal_1      :=  court_seal_1;
                        lst_printed(deft2_idx).court_name_seal_2      :=  court_seal_2;
                        lst_printed(deft2_idx).amount                 :=  LPAD(TO_CHAR(lst_requests(request_idx).claim_amount,'fm99990.00'),8);
                        lst_printed(deft2_idx).fee                    :=  LPAD(TO_CHAR(lst_requests(request_idx).court_fee,'fm990.00'),6);
                        lst_printed(deft2_idx).costs                  :=  LPAD(TO_CHAR(lst_requests(request_idx).solicitors_costs,'fm990.00'),6);
                        lst_printed(deft2_idx).total                  :=  LPAD(TO_CHAR(lst_requests(request_idx).total_amount,'fm999990.00'),9);
                        lst_printed(deft2_idx).issue_date             :=  rec_date.issue_date;
                        lst_printed(deft2_idx).court_section          :=  lst_requests(request_idx).coded_creditor;
                        lst_printed(deft2_idx).claimant_dets_1        :=  lst_requests(request_idx).claimant_name_1;
                        lst_printed(deft2_idx).claimant_dets_2        :=  lst_requests(request_idx).claimant_name_2;
                        lst_printed(deft2_idx).claimant_dets_3        :=  lst_requests(request_idx).claimant_addr_1;
                        lst_printed(deft2_idx).claimant_dets_4        :=  lst_requests(request_idx).claimant_addr_2;
                        lst_printed(deft2_idx).claimant_dets_5        :=  lst_requests(request_idx).claimant_addr_3;
                        lst_printed(deft2_idx).claimant_dets_6        :=  lst_requests(request_idx).claimant_addr_4;
                        lst_printed(deft2_idx).claimant_dets_7        :=  lst_requests(request_idx).claimant_addr_5;
                        lst_printed(deft2_idx).claimant_postcode      :=  lst_requests(request_idx).claimant_postcode;
                        lst_printed(deft2_idx).payment_address_1      :=  lst_requests(request_idx).corres_rep_name;
                        lst_printed(deft2_idx).payment_address_2      :=  lst_requests(request_idx).corres_rep_addr_1;
                        lst_printed(deft2_idx).payment_address_3      :=  lst_requests(request_idx).corres_rep_addr_2;
                        lst_printed(deft2_idx).payment_address_4      :=  lst_requests(request_idx).corres_rep_addr_3;
                        lst_printed(deft2_idx).payment_address_5      :=  lst_requests(request_idx).corres_rep_addr_4;
                        lst_printed(deft2_idx).payment_postcode       :=  lst_requests(request_idx).corres_rep_postcode;
                        lst_printed(deft2_idx).reference              :=  lst_requests(request_idx).solicitor_reference;
                        lst_printed(deft2_idx).particulars_name       :=  lst_requests(request_idx).name_on_partics;
                        lst_printed(deft2_idx).deft_1_dets_1          :=  lst_requests(request_idx).def2_name_1;
                        lst_printed(deft2_idx).deft_1_dets_2          :=  lst_requests(request_idx).def2_name_2;
                        lst_printed(deft2_idx).deft_1_dets_3          :=  lst_requests(request_idx).def2_addr_1;
                        lst_printed(deft2_idx).deft_1_dets_4          :=  lst_requests(request_idx).def2_addr_2;
                        lst_printed(deft2_idx).deft_1_dets_5          :=  lst_requests(request_idx).def2_addr_3;
                        lst_printed(deft2_idx).deft_1_dets_6          :=  lst_requests(request_idx).def2_addr_4;
                        lst_printed(deft2_idx).deft_1_dets_7          :=  lst_requests(request_idx).def2_addr_5;
                        lst_printed(deft2_idx).deft_1_dets_8          :=  lst_requests(request_idx).def2_postcode;
                        -- cannot use decode so use IF statement
                        IF  lst_requests(request_idx).solicitor = 'N' THEN
                            lst_printed(deft2_idx).claimant_x         :=  NULL;
                            lst_printed(deft2_idx).solicitor_x        :=  'XXXXXXXXXXXXXXX';
                        ELSIF lst_requests(request_idx).solicitor = 'Y' THEN
                            lst_printed(deft2_idx).claimant_x         :=  'XXXXXXXX';
                            lst_printed(deft2_idx).solicitor_x        :=  NULL;
                        ELSE -- solicitor is NULL or other non Y/N value
                            lst_printed(deft2_idx).claimant_x         :=  NULL;
                            lst_printed(deft2_idx).solicitor_x        :=  NULL;
                        END IF;
                        lst_printed(deft2_idx).deft_2_dets_1          :=  lst_requests(request_idx).def1_name_1;
                        lst_printed(deft2_idx).deft_2_dets_2          :=  lst_requests(request_idx).def1_name_2;
                        lst_printed(deft2_idx).deft_2_dets_3          :=  lst_requests(request_idx).def1_addr_1;
                        lst_printed(deft2_idx).deft_2_dets_4          :=  lst_requests(request_idx).def1_addr_2;
                        lst_printed(deft2_idx).deft_2_dets_5          :=  lst_requests(request_idx).def1_addr_3;
                        lst_printed(deft2_idx).deft_2_dets_6          :=  lst_requests(request_idx).def1_addr_4;
                        lst_printed(deft2_idx).deft_2_dets_7          :=  lst_requests(request_idx).def1_addr_5;
                        lst_printed(deft2_idx).deft_2_dets_8          :=  lst_requests(request_idx).def1_postcode;
                        lst_printed(deft2_idx).particulars_1          :=  lst_requests(request_idx).claim_particulars_1;
                        lst_printed(deft2_idx).particulars_2          :=  lst_requests(request_idx).claim_particulars_2;
                        lst_printed(deft2_idx).particulars_3          :=  lst_requests(request_idx).claim_particulars_3;
                        lst_printed(deft2_idx).particulars_4          :=  lst_requests(request_idx).claim_particulars_4;
                        lst_printed(deft2_idx).particulars_5          :=  lst_requests(request_idx).claim_particulars_5;
                        lst_printed(deft2_idx).particulars_6          :=  lst_requests(request_idx).claim_particulars_6;
                        lst_printed(deft2_idx).particulars_7          :=  lst_requests(request_idx).claim_particulars_7;
                        lst_printed(deft2_idx).particulars_8          :=  lst_requests(request_idx).claim_particulars_8;
                        lst_printed(deft2_idx).particulars_9          :=  lst_requests(request_idx).claim_particulars_9;
                        lst_printed(deft2_idx).particulars_10         :=  lst_requests(request_idx).claim_particulars_10;
                        lst_printed(deft2_idx).particulars_11         :=  lst_requests(request_idx).claim_particulars_11;
                        lst_printed(deft2_idx).particulars_12         :=  lst_requests(request_idx).claim_particulars_12;
                        lst_printed(deft2_idx).particulars_13         :=  lst_requests(request_idx).claim_particulars_13;
                        lst_printed(deft2_idx).particulars_14         :=  lst_requests(request_idx).claim_particulars_14;
                        lst_printed(deft2_idx).particulars_15         :=  lst_requests(request_idx).claim_particulars_15;
                        lst_printed(deft2_idx).particulars_16         :=  lst_requests(request_idx).claim_particulars_16;
                        lst_printed(deft2_idx).particulars_17         :=  lst_requests(request_idx).claim_particulars_17;
                        lst_printed(deft2_idx).particulars_18         :=  lst_requests(request_idx).claim_particulars_18;
                        lst_printed(deft2_idx).particulars_19         :=  lst_requests(request_idx).claim_particulars_19;
                        lst_printed(deft2_idx).particulars_20         :=  lst_requests(request_idx).claim_particulars_20;
                        lst_printed(deft2_idx).particulars_21         :=  lst_requests(request_idx).claim_particulars_21;
                        lst_printed(deft2_idx).particulars_22         :=  lst_requests(request_idx).claim_particulars_22;
                        lst_printed(deft2_idx).particulars_23         :=  lst_requests(request_idx).claim_particulars_23;
                        lst_printed(deft2_idx).particulars_24         :=  lst_requests(request_idx).claim_particulars_24;
                        lst_printed(deft2_idx).amount_currency        :=  NULL;
                        lst_printed(deft2_idx).fee_currency           :=  NULL;
                        lst_printed(deft2_idx).costs_currency         :=  NULL;
                        lst_printed(deft2_idx).total_currency         :=  NULL;
                        lst_printed(deft2_idx).help_text_1            :=  'Important Note';
                        lst_printed(deft2_idx).help_text_2            :=  '.';
                        lst_printed(deft2_idx).help_text_3            :=  'You have a limited time in which to reply to';
                        lst_printed(deft2_idx).help_text_4            :=  'this claim form';
                        lst_printed(deft2_idx).help_text_5            :=  '.';
                        lst_printed(deft2_idx).help_text_6            :=  'Please read all the guidance notes on the';
                        lst_printed(deft2_idx).help_text_7            :=  'back of this form - they set out the time limits';
                        lst_printed(deft2_idx).help_text_8            :=  'and tell you what you can do about the claim';
                        lst_printed(deft2_idx).help_text_9            :=  '.';
                        lst_printed(deft2_idx).help_text_10           :=  'You can respond to this claim online. Log on';
                        lst_printed(deft2_idx).help_text_11           :=  'to' ;
                        lst_printed(deft2_idx).help_text_12           :=  'www.moneyclaim.gov.uk';
                        lst_printed(deft2_idx).help_text_13           :=  '.' ;
                        lst_printed(deft2_idx).help_text_14           :=  'You will need the claim number';
                        lst_printed(deft2_idx).help_text_15           :=  '(see above)';
                        lst_printed(deft2_idx).help_text_16           :=  'and the following password';
                        lst_printed(deft2_idx).help_text_17           :=  lst_requests(request_idx).def2_password;
                        lst_printed(deft2_idx).p2_claimant_name_1     :=  substr(lst_requests(request_idx).claimant_name_1,30);
                        lst_printed(deft2_idx).p2_claimant_name_2     :=  substr(lst_requests(request_idx).claimant_name_2,1,30);
                        lst_printed(deft2_idx).p2_deft_name_1         :=  lst_requests(request_idx).def2_name_1;
                        lst_printed(deft2_idx).p2_deft_name_2         :=  lst_requests(request_idx).def2_name_2;
                        lst_printed(deft2_idx).p2_help_text_1         := 'If you want to defend all or part of this claim or request';
                        lst_printed(deft2_idx).p2_help_text_2         := 'additional time to prepare your defence you can respond';
                        lst_printed(deft2_idx).p2_help_text_3         := 'online, by logging on to';
                        lst_printed(deft2_idx).p2_help_text_4         := 'www.moneyclaim.gov.uk';
                        lst_printed(deft2_idx).p2_help_text_5         := 'You will need the claim number and password from the';
                        lst_printed(deft2_idx).p2_help_text_6         := 'front of the claim form.';
                        lst_printed(deft2_idx).p2_help_text_7         := 'More help and information can be found online or by';
                        lst_printed(deft2_idx).p2_help_text_8         := 'telephoning the court on the number shown on the front';
                        lst_printed(deft2_idx).p2_help_text_9         := 'of the claim form.';
                        -- calculate N1 page counts
                        lst_printed(deft2_idx).page_1_count           := (request_idx * 4) - 3;
                        lst_printed(deft2_idx).page_2_count           := (request_idx * 4) - 2;
                        lst_printed(deft2_idx).page_3_count           := (request_idx * 4) - 1;
                        lst_printed(deft2_idx).page_4_count           := (request_idx * 4);

                        -- set court address to either the MCOL address if the coded_creditor is 1999
                        -- or the bulk claims court. Note: legacy code puts postcode in address 5 so
                        -- we have to do the same
                        IF lst_requests(request_idx).coded_creditor = 1999 THEN
                            -- use the mcol address
                            lst_printed(deft2_idx).court_address_1        :=  mcol_address.name;
                            lst_printed(deft2_idx).court_address_2        :=  mcol_address.address_line1;
                            lst_printed(deft2_idx).court_address_3        :=  mcol_address.address_line2;
                            lst_printed(deft2_idx).court_address_4        :=  mcol_address.address_line3;
                            lst_printed(deft2_idx).court_address_5        :=  mcol_address.postcode;
                            lst_printed(deft2_idx).court_postcode         :=  NULL;
                            lst_printed(deft2_idx).p2_court_address       :=  mcol_address.name||' '||
                                                                                mcol_address.address_line1||' '||
                                                                                mcol_address.address_line2||' '||
                                                                                mcol_address.address_line3||' '||
                                                                                mcol_address.postcode;
                            lst_printed(deft2_idx).court_tel_number       :=  mcol_address.telephone_no;
                            -- no claimant telephone for MCOL claims
                            lst_printed(deft2_idx).claimant_tel_number    := NULL;
                        ELSE
                            -- use the bulk claims address
                            lst_printed(deft2_idx).court_address_1        :=  bulk_address.name;
                            lst_printed(deft2_idx).court_address_2        :=  bulk_address.address_line1;
                            lst_printed(deft2_idx).court_address_3        :=  bulk_address.address_line2;
                            lst_printed(deft2_idx).court_address_4        :=  bulk_address.address_line3;
                            lst_printed(deft2_idx).court_address_5        :=  bulk_address.postcode;
                            lst_printed(deft2_idx).court_postcode         :=  NULL;
                            lst_printed(deft2_idx).p2_court_address       :=  bulk_address.name||' '||
                                                                                bulk_address.address_line1||' '||
                                                                                bulk_address.address_line2||' '||
                                                                                bulk_address.address_line3||' '||
                                                                                mcol_address.postcode;
                            lst_printed(deft2_idx).court_tel_number       :=  bulk_address.telephone_no;
                            -- claimant telephone is set for  bulk claims
                            OPEN cur_get_claimant_tel (lst_requests(request_idx).coded_creditor);
                            FETCH cur_get_claimant_tel INTO lst_printed(deft2_idx).claimant_tel_number;
                            CLOSE cur_get_claimant_tel;

                        END IF;

                        -- increment omr code and rec_no in preparation for
                        -- inserting the next print claims record
                        nv_rec_no := nv_rec_no + 1;
                        IF nv_omr_code = 7 THEN
                            nv_omr_code := 1;
                        ELSE
                            nv_omr_code := nv_omr_code + 1;
                        END IF;

                    END IF;
                    -- Insert record into the MCOL_DATA table with 'I'ssued status
                    -- Note: it is not possible to use FORALL bulk collection syntax
                    -- with a database link, so we have do a single row insert
                    -- An on-insert trigger on the table fires to populate the primary key
                    -- column of mcol_data_t_id

                    current_statement := 'Inserting MCOL data for '||TO_CHAR(lst_requests(request_idx).claim_number);

                    INSERT INTO mcol_data@cpt_mcol_link
                        (
                        claim_number,
                        claim_status,
                        issue_date,
                        reject_code,
                        claimant_name_1,
                        claimant_name_2,
                        deft1_name_1,
                        deft1_name_2,
                        deft1_password,
                        deft2_name_1,
                        deft2_name_2,
                        deft2_password,
                        claim_amount,
                        court_fee,
                        solicitors_costs,
                        total_amount
                        )
                    VALUES
                        (
                        lst_requests(request_idx).claim_number,
                        'I',
                        rec_date.issue_date,
                        NULL, -- reject code
                        lst_requests(request_idx).claimant_name_1,
                        lst_requests(request_idx).claimant_name_2,
                        lst_requests(request_idx).def1_name_1,
                        lst_requests(request_idx).def1_name_2,
                        v_password_1,
                        lst_requests(request_idx).def2_name_1,
                        lst_requests(request_idx).def2_name_2,
                        v_password_2,
                        lst_requests(request_idx).claim_amount,
                        lst_requests(request_idx).court_fee,
                        lst_requests(request_idx).solicitors_costs,
                        lst_requests(request_idx).total_amount
                        );

                    -- record the  number of accepted claims and
                    -- keep a running total of court fees for all
                    -- accepted claims
                    n_accepted_count := n_accepted_count + 1;
                    n_accepted_court_fees_total := n_accepted_court_fees_total + lst_requests(request_idx).court_fee;



                ELSE
                    -- coded party not known to CASEMAN
                    -- This is never expected to happen in practice

                    DBMS_OUTPUT.PUT_LINE('ERROR : coded_creditor '||
                                         lst_requests(request_idx).coded_creditor||
                                         ' not known to CASEMAN. Claim number '||
                                         lst_requests(request_idx).claim_number||
                                         ' will not be processed');

                    -- record the  number of rejected claims and
                    -- keep a running total of court fees for all
                    -- rejected claims

                    n_rejected_count := n_rejected_count + 1;
                    -- DBMS_OUTPUT.PUT_LINE('Rejected count = '||TO_CHAR(n_rejected_count));

                    n_rejected_court_fees_total := n_rejected_court_fees_total + lst_requests(request_idx).court_fee;

                    /*  Since we do have a valid coded creditor, we cannot add a record to the statistics
                     *   table for this claim
                     */

                    -- Insert record into the MCOL_DATA table with 'R'ejected status
                    -- Note: it is not possible to use FORALL bulk collection syntax
                    -- with a database link, so we have do a single row insert
                    -- An on-insert trigger on the table fires to populate the primary key
                    -- column of mcol_data_t_id

                    current_statement := 'rejecting claim in MCOL for '||TO_CHAR(lst_requests(request_idx).claim_number);

                    INSERT INTO mcol_data@cpt_mcol_link
                        (
                        claim_number,
                        claim_status,
                        issue_date,
                        reject_code,
                        court_fee
                        )
                    VALUES
                        (
                        lst_requests(request_idx).claim_number,
                        'R', -- rejected status
                        NULL,
                        24,
                        lst_requests(request_idx).court_fee
                        );

                END IF; -- end of coded creditor check

                CLOSE cur_party_chk;

            END LOOP; --end of claims processing loop

        DBMS_OUTPUT.PUT_LINE('.');

        -- DBMS_OUTPUT.PUT_LINE('All claims processed. About to do bulk inserts');
        -- all claims have been processed or rejected
        -- report on number of claims processed or rejected

        -- store the collected data into the database

        -- NOTE: where collections could be sparsely populated
        -- if one or more claims have been rejected, the FORALL
        -- indices syntax is used

        --DBMS_OUTPUT.PUT_LINE('Bulk Insert into claims '||lst_claims.COUNT);
        --DBMS_OUTPUT.PUT_LINE('accepted claims '||n_accepted_count);


        current_statement := 'Bulk Insert of CLAIMS';

        FORALL i IN INDICES OF lst_claims
            INSERT INTO cpt_claims VALUES lst_claims(i);

        -- DBMS_OUTPUT.PUT_LINE('Bulk Insert into defendants');

        current_statement := 'Bulk Insert of DEFENDANTS';

        FORALL i IN INDICES OF lst_defendants
            INSERT INTO cpt_defendants VALUES lst_defendants(i);

        -- DBMS_OUTPUT.PUT_LINE('Bulk Insert into statistics');

        current_statement := 'Bulk Insert of STATISTICS';

        FORALL i IN INDICES OF lst_statistics
            INSERT INTO cpt_statistics VALUES lst_statistics(i);

        current_statement := 'Bulk Insert of cases into CASEMAN ';

        FORALL i IN INDICES OF lst_cases
            INSERT INTO load_cases VALUES lst_cases(i);

        current_statement := 'Bulk Insert of printed_claims ';

        FORALL i IN INDICES OF lst_printed
            INSERT INTO cpt_print_claims VALUES lst_printed(i);

        -- clear collections for next iteration of loop
        lst_cases       := empty_cases;
        lst_defendants  := empty_defendants;
        lst_claims      := empty_claims;
        lst_statistics  := empty_statistics;
        lst_printed     := empty_printed;

        --DBMS_OUTPUT.PUT_LINE(' case collection cleared count = '||lst_cases.count);
        --DBMS_OUTPUT.PUT_LINE(' defendants collection cleared count = '||lst_defendants.count);
        --DBMS_OUTPUT.PUT_LINE(' claims collection cleared count = '||lst_claims.count);
        --DBMS_OUTPUT.PUT_LINE(' stats collection cleared count = '||lst_statistics.count);
        --DBMS_OUTPUT.PUT_LINE(' printed collection cleared count = '||lst_printed.count);

        COMMIT;
        EXIT WHEN cur_requests%NOTFOUND;
    END LOOP; -- end of cursor processing loop

    -- mark the claim requests as having been processed
    -- by updating the tape_files table.

    current_statement := 'update of tape_files in MCOL';

    -- have to use individual updates on remote table

    IF lst_tape_seq.COUNT > 0 THEN
        -- We have at least one tape file record to update
        FOR i IN lst_tape_seq.FIRST..lst_tape_seq.LAST
            LOOP
                UPDATE      tape_files@cpt_mcol_link
                SET         status          = 'T',
                            comments        = 'Transferred on '||TO_CHAR(rec_date.issue_date, 'DD-MON-YYYY ')
                WHERE       status          = 'L'
                AND         tape_file_seq     = lst_tape_seq(i);
            END LOOP;
    END IF;

    DBMS_OUTPUT.PUT_LINE('SDT CPC - has processed '||n_accepted_count||' claims on '||TO_CHAR(rec_date.issue_date, 'DD/MON/YYYY '));

    IF n_rejected_count > 0 THEN
        DBMS_OUTPUT.PUT_LINE('SDT CPT - rejected '||n_rejected_count||' claims on '||TO_CHAR(rec_date.issue_date, 'DD/MON/YYYY'));
    END IF;

    --DBMS_OUTPUT.PUT_LINE('Insert into liberata_total_fees');

    current_statement := 'insert into LIBERATA_TOTAL_FEES';

    INSERT INTO cpt_liberata_total_fees
        (
        issue_date,
        report_line_string
        )
    VALUES
        (
        rec_date.issue_date,
        TO_CHAR(rec_date.issue_date,'DD-MON-YYYY')||','||
        TO_CHAR(n_accepted_count)||','||
        TO_CHAR(n_accepted_court_fees_total, '999999990.00')||','||
        TO_CHAR(n_rejected_count)||','||
        TO_CHAR(n_rejected_court_fees_total,'999999990.00')
        );

    IF  n_accepted_count + n_rejected_count = 0 THEN
        -- no claims have been been found for processing
        DBMS_OUTPUT.PUT_LINE('SDT CPT - No Claims found for processing ');
    END IF; -- end of lst_requests.count if statement

    IF  expected_claims != n_accepted_count + n_rejected_count THEN
        -- we have a mismatch between the expected claims reported in
        -- the tape_files table and actual claims found in the claims.
        -- report the problem, but continune to process claims
        DBMS_OUTPUT.PUT_LINE('Warning: Expected claims = '||TO_CHAR(expected_claims)||
                                 ' Actual claims found = '||TO_CHAR(n_accepted_count + n_rejected_count));
    END IF;


    CLOSE cur_requests;

    IF  (n_accepted_count + n_rejected_count) > 0 THEN
        -- If we have processed claims tell MCOL by calling the following MCOL procedure
        exec_ols_cpc_package.exec_p_data_to_mcol@cpt_mcol_link;
    END IF;
    -- all done so commit

    COMMIT;
    DBMS_OUTPUT.PUT_LINE('.');
    DBMS_OUTPUT.PUT_LINE('SDT CPT - Finished processing claims at '||TO_CHAR(SYSDATE, 'DD/MM/YYYY HH24:MI:SS'));

EXCEPTION
    WHEN NO_DATA_FOUND THEN
        DBMS_OUTPUT.PUT_LINE('No Claims found to process at '||TO_CHAR(SYSDATE, 'DD/MM/YYYY HH24:MI:SS'));
        IF cur_requests%ISOPEN THEN
            CLOSE cur_requests;
        END IF;
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
        DBMS_OUTPUT.PUT_LINE('while executing procedure cpt_process_claims at '||current_statement);
        DBMS_OUTPUT.PUT_LINE('processing claim '||current_claim);
        DBMS_OUTPUT.PUT_LINE('Rolling Back changes');
        ROLLBACK;
        DBMS_OUTPUT.PUT_LINE('SDT CPT - Claims processing Failed at '||TO_CHAR(SYSDATE, 'DD/MM/YYYY HH24:MI:SS'));
        IF cur_requests%ISOPEN THEN
            CLOSE cur_requests;
        END IF;
        -- re-raise exception so control.sh and autosys picks up the failure
        RAISE;
END; -- end of cpt_process_claims procedure
END; -- cpt_claims_pack
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."CREATE_JUDGMNT_PRINT_FILE"
AS
 PROCEDURE run_print_judgments ( p_username IN VARCHAR2 );
END create_judgmnt_print_file;
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."CREATE_JUDGMNT_PRINT_FILE"
AS

 /*------------------------------------------------*
  * Procedure to Truncate the Print Judgments      *
  * table                                          *
  *------------------------------------------------*/

 PROCEDURE truncate_print_judgments
 AS
 BEGIN

  EXECUTE IMMEDIATE 'truncate table print_judgments';

 END truncate_print_judgments;


 /*------------------------------------------------*
  * Procedure to run the Actual Processing         *
  *------------------------------------------------*/

 PROCEDURE create_print_judgments ( p_username IN VARCHAR2 )
 IS

  nv_old_cred               NUMBER(4);
  cv_old_type               VARCHAR2(1);
  nv_rec_number             NUMBER(6);
  cv_payee_name             VARCHAR2(70);
  cv_payee_addr_1           VARCHAR2(35);
  cv_payee_addr_2           VARCHAR2(35);
  cv_payee_addr_3           VARCHAR2(35);
  cv_payee_addr_4           VARCHAR2(35);
  cv_payee_addr_5           VARCHAR2(35);
  cv_payee_postcode         VARCHAR2(8);
  cv_payee_tel_no           VARCHAR2(24);
  cv_payee_ref              VARCHAR2(25);
  cv_payee_ref_sol          VARCHAR2(25);
  cv_payee_bank_sort_code       VARCHAR2(8);
  cv_payee_acc_holder           VARCHAR2(70);
  cv_payee_bank_name            VARCHAR2(30);
  cv_payee_bank_info_1          VARCHAR2(30);
  cv_payee_bank_info_2          VARCHAR2(30);
  cv_payee_bank_acc_no          VARCHAR2(18);
  cv_payee_giro_acc_no          VARCHAR2(8);
  cv_payee_giro_trans_code_1    VARCHAR2(9);
  cv_payee_giro_trans_code_2    VARCHAR2(2);
  cv_payee_apacs_trans_code     VARCHAR2(2);

  CURSOR c_judg
      IS
  SELECT DECODE(eve.username, p_username ,cred.code,'1999') code    ,
         cas.cred_code                      ,
         SUBSTR(judg.judgment_type,1,1) judgment_type       ,
         cas.case_number                    ,
         parclmt.person_requested_name  claimant_details_1  ,
         gaclmt.address_line1           claimant_details_2  ,
         gaclmt.address_line2           claimant_details_3  ,
         gaclmt.address_line3       claimant_details_4  ,
         gaclmt.address_line4       claimant_details_5  ,
         gaclmt.address_line5       claimant_details_6  ,
         gaclmt.postcode        claimant_details_7  ,
     judg.payee_reference                   ,
     cprclmt.reference                  ,
         pardef.person_requested_name   name            ,
         pardef.person_dob                  ,
     gadef.address_line1 addr_1             ,
     gadef.address_line2 addr_2             ,
         gadef.address_line3 addr_3             ,
         gadef.address_line4 addr_4             ,
         gadef.address_line5 addr_5             ,
         gadef.postcode                     ,
     judg.judgment_amount                   ,
     judg.total_costs                   ,
     judg.paid_before_judgment              ,
     judg.total                     ,
     judg.instalment_amount                 ,
     judg.instalment_period                 ,
     judg.first_payment_date                ,
     judg.judgment_date                 ,
     judg.slip_codeline_1                   ,
     judg.slip_codeline_2                   ,
     judg.payee_name                    ,
         judg.payee_addr_1                  ,
         judg.payee_addr_2                  ,
         judg.payee_addr_3                  ,
         judg.payee_addr_4                  ,
         judg.payee_addr_5                  ,
         judg.payee_postcode                    ,
         judg.payee_tel_no                  ,
     judg.payee_bank_sort_code              ,
     judg.payee_acc_holder                  ,
     judg.payee_bank_name                   ,
     judg.payee_bank_info_1                 ,
     judg.payee_bank_info_2                 ,
     judg.payee_bank_acc_no                 ,
     judg.payee_giro_acc_no                 ,
     judg.payee_giro_trans_code_1               ,
     judg.payee_giro_trans_code_2               ,
     judg.payee_apacs_trans_code                ,
         NVL(parcred.party_type_code, 'SOLICITOR') party_type_code,
         parcred.party_id
  FROM   case_events            eve,
     cases                  cas,
         judgments              judg,
         coded_parties          cred,
         national_coded_parties ncp,
     report_sequences       rseq,
     parties                parclmt,
     given_addresses        gaclmt,
     case_party_roles       cprclmt,
     parties                pardef,
     given_addresses        gadef,
     parties                parcred
  WHERE  gadef.case_number = judg.case_number
    AND  gadef.case_party_no = judg.against_case_party_no
    AND  gadef.party_role_code = 'DEFENDANT'
    AND  gadef.address_type_code = 'SERVICE'
    AND  gadef.valid_to IS NULL
    AND  pardef.party_id = gadef.party_id
    AND  cprclmt.case_number = judg.case_number
    AND  cprclmt.case_party_no = 1
    AND  cprclmt.party_role_code = 'CLAIMANT'
    AND  gaclmt.case_number = judg.case_number
    AND  gaclmt.case_party_no = 1
    AND  gaclmt.party_role_code = 'CLAIMANT'
    AND  gaclmt.address_type_code = 'SERVICE'
    AND  gaclmt.valid_to IS NULL
    AND  parclmt.party_id = gaclmt.party_id
    AND  cred.code = cas.cred_code
    AND  cred.admin_court_code = 335
    AND  parcred.party_id = cred.party_id
    AND  ncp.code = cred.code
    AND  ncp.print_judgments = 'Y'
    AND  cas.manual is NULL
    AND  cas.case_number = judg.case_number
    AND  cas.admin_crt_code = 335
    AND  eve.deleted_flag = 'N'
    AND  eve.std_event_id IN (230,240)
    AND  eve.judg_seq = judg.judg_seq
    AND  judg.status IS NULL
    AND  judg.judgment_type IN ('DEFAULT','ADMISSION')
    AND  judg.judg_seq > rseq.last_seqno
    AND  rseq.form_name = 'JUDGMENTS'
  ORDER BY 1, 3, gadef.postcode;

BEGIN

 nv_old_cred := 0;
 cv_old_type := 'X';

 -- Loop through the Cursor
 FOR c_judg_rec IN c_judg
 LOOP

   IF nv_old_cred = c_judg_rec.code AND cv_old_type = c_judg_rec.judgment_type THEN
      nv_rec_number := nv_rec_number + 1;
   ELSE
    nv_rec_number := 1;
    nv_old_cred := c_judg_rec.code;
    cv_old_type := c_judg_rec.judgment_type;
   END IF;

    /* Default payee fields to those obtained in cursor c_judg */
    cv_payee_name              := c_judg_rec.claimant_details_1;
    cv_payee_addr_1            := c_judg_rec.claimant_details_2;
    cv_payee_addr_2            := c_judg_rec.claimant_details_3;
    cv_payee_addr_3            := c_judg_rec.claimant_details_4;
    cv_payee_addr_4            := c_judg_rec.claimant_details_5;
    cv_payee_addr_5            := c_judg_rec.claimant_details_6;
    cv_payee_postcode          := c_judg_rec.claimant_details_7;
    cv_payee_tel_no            := c_judg_rec.payee_tel_no;
    cv_payee_bank_sort_code    := c_judg_rec.payee_bank_sort_code;
    cv_payee_acc_holder        := c_judg_rec.payee_acc_holder;
    cv_payee_bank_name         := c_judg_rec.payee_bank_name;
    cv_payee_bank_info_1       := c_judg_rec.payee_bank_info_1;
    cv_payee_bank_info_2       := c_judg_rec.payee_bank_info_2;
    cv_payee_bank_acc_no       := c_judg_rec.payee_bank_acc_no;
    cv_payee_giro_acc_no       := c_judg_rec.payee_giro_acc_no;
    cv_payee_giro_trans_code_1 := c_judg_rec.payee_giro_trans_code_1;
    cv_payee_giro_trans_code_2 := c_judg_rec.payee_giro_trans_code_2;
    cv_payee_apacs_trans_code  := c_judg_rec.payee_apacs_trans_code;

/* If MCOL case then set payee fields to solicitor fields */
    IF c_judg_rec.cred_code = 1999 THEN

      -- Run in a seperate block so that the exception
      -- is caught and just return NULL if it is.
      BEGIN

         SELECT parsol.person_requested_name,
                gasol.address_line1         ,
                gasol.address_line2     ,
                gasol.address_line3         ,
            gasol.address_line4         ,
            gasol.address_line5         ,
            gasol.postcode              ,
            NULL                        ,
            cprcprsol.personal_reference
           INTO cv_payee_name           ,
                cv_payee_addr_1         ,
                cv_payee_addr_2         ,
                cv_payee_addr_3         ,
                cv_payee_addr_4         ,
                cv_payee_addr_5         ,
                cv_payee_postcode       ,
                cv_payee_tel_no         ,
                cv_payee_ref_sol
           FROM parties                  parsol   ,
                given_addresses          gasol    ,
                cpr_to_cpr_relationship  cprcprsol
          WHERE cprcprsol.cpr_a_case_number = c_judg_rec.case_numbeR
            AND cprcprsol.cpr_a_case_party_no = 1
            AND cprcprsol.cpr_a_party_role_code = 'CLAIMANT'
            AND cprcprsol.cpr_b_case_number = c_judg_rec.case_number
            AND cprcprsol.cpr_b_party_role_code = 'SOLICITOR'
            AND cprcprsol.deleted_flag = 'N'
            AND gasol.case_number = c_judg_rec.case_number
            AND gasol.case_party_no = cprcprsol.cpr_b_case_party_no
            AND gasol.party_role_code = 'SOLICITOR'
            AND gasol.address_type_code = 'SOLICITOR'
            AND gasol.valid_to IS NULL
            AND parsol.party_id = gasol.party_id;
      EXCEPTION
        WHEN NO_DATA_FOUND THEN NULL;
      END;

    END IF;

   /*---------------------------------------------------------*
    * If non-MCOL then if payee details have been supplied on *
    * the judgment then use them otherwise use the standard   *
    * payee details from the database                         *
    *---------------------------------------------------------*/

    IF C_JUDG_REC.CRED_CODE <> 1999 THEN

      IF c_judg_rec.payee_name IS NOT NULL THEN
        cv_payee_name     := c_judg_rec.payee_name;
        cv_payee_addr_1   := c_judg_rec.payee_addr_1;
        cv_payee_addr_2   := c_judg_rec.payee_addr_2;
        cv_payee_addr_3   := c_judg_rec.payee_addr_3;
        cv_payee_addr_4   := c_judg_rec.payee_addr_4;
        cv_payee_addr_5   := c_judg_rec.payee_addr_5;
        cv_payee_postcode := c_judg_rec.payee_postcode;

      ELSE

        -- Run a seperate PL/SQL block so that the exception
        -- can be caught and handled without impacting the
        -- main program.
        BEGIN

          SELECT parpay.person_requested_name   ,
                 gapay.address_line1        ,
                 gapay.address_line2        ,
                 gapay.address_line3        ,
                 gapay.address_line4        ,
                 gapay.address_line5        ,
                 gapay.postcode         ,
                 parpay.tel_no          ,
                 pay.bank_sort_code     ,
             pay.acc_holder         ,
             pay.bank_name          ,
             pay.bank_info_1        ,
             pay.bank_info_2        ,
             pay.bank_acc_no        ,
             pay.giro_acc_no        ,
             pay.giro_trans_code_1      ,
             pay.giro_trans_code_2      ,
             pay.apacs_trans_code
            INTO cv_payee_name          ,
                 cv_payee_addr_1        ,
                 cv_payee_addr_2        ,
                 cv_payee_addr_3        ,
                 cv_payee_addr_4        ,
                 cv_payee_addr_5        ,
                 cv_payee_postcode      ,
                 cv_payee_tel_no        ,
                 cv_payee_bank_sort_code    ,
                 cv_payee_acc_holder        ,
                 cv_payee_bank_name     ,
                 cv_payee_bank_info_1       ,
                 cv_payee_bank_info_2       ,
                 cv_payee_bank_acc_no       ,
                 cv_payee_giro_acc_no       ,
                 cv_payee_giro_trans_code_1 ,
                 cv_payee_giro_trans_code_2 ,
                 cv_payee_apacs_trans_code
            FROM parties          parpay        ,
             given_addresses  gapay         ,
             payees           pay           ,
             party_to_party_relationship  ptyptypay
           WHERE ptyptypay.party_a_id = c_judg_rec.party_id
             AND ptyptypay.party_a_role_code = c_judg_rec.party_type_code
             AND ptyptypay.party_b_role_code = 'NCP PAYEE'
             AND gapay.party_id = ptyptypay.party_b_id
             AND gapay.address_type_code = 'NCP PAYEE'
             AND gapay.valid_to IS NULL
             AND parpay.party_id = ptyptypay.party_b_id
             AND pay.party_id = ptyptypay.party_b_id;
       EXCEPTION
          WHEN NO_DATA_FOUND THEN NULL;
       END;

      END IF;


    /*-----------------------------------*
     * Now get the reference             *
     *-----------------------------------*/

     SELECT cprcprsol.personal_reference
       INTO cv_payee_ref_sol
       FROM cpr_to_cpr_relationship  cprcprsol
      WHERE cprcprsol.cpr_a_case_number = c_judg_rec.case_number
        AND cprcprsol.cpr_a_case_party_no = 1
        AND cprcprsol.cpr_a_party_role_code = 'CLAIMANT'
        AND cprcprsol.cpr_b_case_number = c_judg_rec.case_number
        AND cprcprsol.cpr_b_party_role_code = 'SOLICITOR'
        AND cprcprsol.deleted_flag = 'N';

    END IF;

    /*-----------------------------------*
     * Lastly use the correct reference  *
     *-----------------------------------*/

    IF c_judg_rec.payee_reference IS NOT NULL THEN
       cv_payee_ref := c_judg_rec.payee_reference;
    ELSE
      IF cv_payee_ref_sol IS NOT NULL THEN
         cv_payee_ref := cv_payee_ref_sol;
      ELSE
         cv_payee_ref := c_judg_rec.reference;
      END IF;
    END IF;

    INSERT INTO PRINT_JUDGMENTS
    (
      cred_code         ,
      judgment_type     ,
      rec_no            ,
      printed           ,
      case_number       ,
      claimant_details_1    ,
      claimant_details_2    ,
      claimant_details_3    ,
      claimant_details_4    ,
      claimant_details_5    ,
      claimant_details_6    ,
      claimant_details_7    ,
      payee_name        ,
      payee_addr_1      ,
      payee_addr_2      ,
      payee_addr_3      ,
      payee_addr_4      ,
      payee_addr_5      ,
      payee_postcode        ,
      payee_tel_no      ,
      payee_reference       ,
      defendant_name        ,
      defendant_addr_1      ,
      defendant_addr_2      ,
      defendant_addr_3      ,
      defendant_addr_4      ,
      defendant_addr_5      ,
      defendant_postcode    ,
      defendant_dob     ,
      judgment_amount       ,
      total_costs       ,
      paid_before_judgment  ,
      total         ,
      instalment_amount     ,
      instalment_period     ,
      first_payment_date    ,
      judgment_date     ,
      slip_codeline_1       ,
      slip_codeline_2       ,
      payee_bank_sort_code  ,
      payee_acc_holder      ,
      payee_bank_name       ,
      payee_bank_info_1     ,
      payee_bank_info_2     ,
      payee_bank_acc_no     ,
      payee_giro_acc_no     ,
      payee_giro_trans_code_1   ,
      payee_giro_trans_code_2   ,
      payee_apacs_trans_code
      )
    VALUES
    ( c_judg_rec.code,
      c_judg_rec.judgment_type,
      nv_rec_number,
      'N',
      c_judg_rec.case_number,
      c_judg_rec.claimant_details_1,
      c_judg_rec.claimant_details_2,
      c_judg_rec.claimant_details_3,
      c_judg_rec.claimant_details_4,
      c_judg_rec.claimant_details_5,
      c_judg_rec.claimant_details_6,
      c_judg_rec.claimant_details_7,
      cv_payee_name,
      cv_payee_addr_1,
      cv_payee_addr_2,
      cv_payee_addr_3,
      cv_payee_addr_4,
      cv_payee_addr_5,
      cv_payee_postcode,
      cv_payee_tel_no,
      cv_payee_ref,
      c_judg_rec.name,
      c_judg_rec.addr_1,
      c_judg_rec.addr_2,
      c_judg_rec.addr_3,
      c_judg_rec.addr_4,
      c_judg_rec.addr_5,
      c_judg_rec.postcode,
      c_judg_rec.person_dob,
      c_judg_rec.judgment_amount,
      c_judg_rec.total_costs,
      c_judg_rec.paid_before_judgment,
      c_judg_rec.total,
      c_judg_rec.instalment_amount,
      c_judg_rec.instalment_period,
      c_judg_rec.first_payment_date,
      c_judg_rec.judgment_date,
      c_judg_rec.slip_codeline_1,
      c_judg_rec.slip_codeline_2,
      cv_payee_bank_sort_code,
      cv_payee_acc_holder,
      cv_payee_bank_name,
      cv_payee_bank_info_1,
      cv_payee_bank_info_2,
      cv_payee_bank_acc_no,
      cv_payee_giro_acc_no,
      cv_payee_giro_trans_code_1,
      cv_payee_giro_trans_code_2,
      cv_payee_apacs_trans_code
     );
    COMMIT;

  END LOOP;

END create_print_judgments;

/*------------------------------------------------*
 * Controlling procedure that will truncate the   *
 * print judgments table, clear down the logging  *
 * table and then run the create print judgments  *
 * code.                                          *
 *------------------------------------------------*/

 PROCEDURE run_print_judgments ( p_username IN VARCHAR2 )
 IS
 BEGIN

 -- Truncate the print judgments table.
 truncate_print_judgments;

 -- Run the create print judgments code.
 create_print_judgments (p_username);

END run_print_judgments;

END create_judgmnt_print_file;
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."DEL_OBSOLETE_CASES_PACK" AS

/*------------------------------------------------------------------------------------------------------
|                                                 Package
------------------------------------------------------------------------------------------------------*/

/*------------------------------------------------------------------------------------------------------
|                                                 Global Variables
------------------------------------------------------------------------------------------------------*/
gn_override system_data.item_value%TYPE;
gn_batch_size system_data.item_value%TYPE;
gn_init_del_date system_data.item_value%TYPE;
gn_del_flag system_data.item_value%TYPE;
gn_thead_cnt system_data.item_value%TYPE;
gn_bulk_limit NUMBER;
gn_csv_rec_count NUMBER;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_del_case_co_main
| DESCRIPTION : The main stored proc that control the flow of deletion process.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_del_case_co_main;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_init_globals
| DESCRIPTION  : Initialize CaseMan deletion temporary data.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_init_globals;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : init_cm_delete_tables
| DESCRIPTION : Initialize CaseMan deletion temporary data.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_init_cm_delete_tables;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_set_deletion_dates
| DESCRIPTION   : Compute and set deletion date column in the CASES and Consolidated_Orders tables
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_set_deletion_dates;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_perform_recalc_del_date
| DESCRIPTION : Recalulate and Update the deletion date of a case, consolidated order.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_perform_calc_del_date (pv_identifier IN VARCHAR2,
                                   pv_type       IN VARCHAR2,
                                   pn_create_ret IN NUMBER,
                                   pn_insig_ret  IN NUMBER);

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_populate_linked_co_ca
| DESCRIPTION   : Insert linked candidate cases and consolidated orders into candidate tables.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_populate_linked_co_ca;

/*------------------------------------------------------------------------------------------------------
 TYPE          : PROCEDURE
| NAME          : p_populate_unlinked_case
| DESCRIPTION   : Insert candidate cases not linked to consolidated orders into
|                 candidate tables.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_populate_unlinked_case;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_generic_rule_validation
| DESCRIPTION   : Apply generic rule validations to cases and consolidated orders.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_generic_rule_validation;

/*------------------------------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_generic_rule
| DESCRIPTION   : Perform the actual rule validations on cases and consolidated_Orders tables
------------------------------------------------------------------------------------------------------*/
FUNCTION f_generic_rule(p_type varchar2, p_identifier varchar2) RETURN varchar2;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_upd_co_cases_delete_flag
| DESCRIPTION   : Apply generic rule validations to cases and consolidated orders.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_upd_linked_co_cases_del_flag ;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_resolve_linked_del_flag
| DESCRIPTION   : Update consolidated orders and cases deletion status based on whether a case is linked
|                 to an undeletable CO or a CO is linked to an undeletable case.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_resolve_linked_del_flag;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_perform_deletions
| DESCRIPTION   : Calling p_delete_case and p_delete_co to delete cases and co's.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_perform_deletions (p_delete_index IN NUMBER);

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_print_audit_report
| DESCRIPTION : Export Audit Report Records to CSV file.
--------------------------------------------------------------------------------*/
PROCEDURE p_print_audit_report;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_print_exceptions_report
| DESCRIPTION : Export Exceptions Report Records to CSV file.
--------------------------------------------------------------------------------*/
PROCEDURE p_print_exceptions_report;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_delete_case
| DESCRIPTION : Deletes a case record and all child records including output
|                 data and audit data held in the SUPS_AMENDMENTS table.
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_delete_case (pv_case_number IN VARCHAR2,
                         p_valid                    IN OUT VARCHAR2,
                         p_reason                       IN OUT VARCHAR2);

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_delete_outputs
| DESCRIPTION : Deletes output data associated with a case event, ae event,
|                 co event or warrant return
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_delete_outputs (p_type  IN VARCHAR2,
                                        p_event_id IN NUMBER);

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_delete_co
| DESCRIPTION : Deletes a consolidated order record and all child records including
|                 output data and audit data held in the SUPS_AMENDMENTS table.
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_delete_co (pv_co_number IN VARCHAR2,
                       p_valid      IN OUT VARCHAR2,
                       p_reason     IN OUT VARCHAR2);

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_disable_audit_triggers
| DESCRIPTION   : Disables the audit triggers in CaseMan
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_disable_audit_triggers;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_enable_audit_triggers
| DESCRIPTION   : Enables the audit triggers in CaseMan
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_enable_audit_triggers;

/*------------------------------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_validate_ae
| DESCRIPTION   : Indicates if there is any AE on the case that would prevent case
|                 deletion.  Includes checks on the CAPS database.
| RETURN        : An exception reason if one found with the AE, else NULL
-------------------------------------------------------------------------------------------------------*/
FUNCTION f_validate_ae (p_case_number IN cases.case_number%TYPE) RETURN VARCHAR2;

/*------------------------------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_money_in_crt
| DESCRIPTION   : Indicates if there is money yet to be paid out on a case/co
| RETURN        : An exception reason if there is money held on the case/co, else NULL
-------------------------------------------------------------------------------------------------------*/
FUNCTION f_is_money_in_crt (p_enf_number    IN cases.case_number%TYPE,
                            p_type          IN VARCHAR2) RETURN VARCHAR2;

/*------------------------------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_live_warrant
| DESCRIPTION   : Indicates if there is a live Warrant on a case/co
| RETURN        : An exception reason if there is a live Warrant on the case/co, else NULL
-------------------------------------------------------------------------------------------------------*/
FUNCTION f_is_live_warrant (p_enf_number    IN cases.case_number%TYPE,
                            p_type          IN VARCHAR2) RETURN VARCHAR2;

/*------------------------------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_live_judg
| DESCRIPTION   : Indicates if there is a live Judgment on a case
| RETURN        : An exception reason if there is a live Judgment on the case, else NULL
-------------------------------------------------------------------------------------------------------*/
FUNCTION f_is_live_judg (p_case_number IN cases.case_number%TYPE) RETURN VARCHAR2;

/*------------------------------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_invalid_status
| DESCRIPTION   : Indicates if the case status is the correct value based upon
|                 the case events on the case
| RETURN        : An exception reason if invalid, else NULL
-------------------------------------------------------------------------------------------------------*/
FUNCTION f_is_invalid_status (p_case_number IN cases.case_number%TYPE) RETURN VARCHAR2;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_process_recalc_dates
| DESCRIPTION   : Using the last run date for the batch job to recalculate the
|                 deletion date of cases/cos, every date since up to SYSDATE
|                 is processed to recalculate the deletion dates.
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_process_recalc_dates;

/*------------------------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_recalculate_deletion_dates
| DESCRIPTION   : For a given date, the procedure will query the SUPS_AMENDMENTS
|                 table for new cases/cos or event changes so that the deletion
|                 date can be recalculated.
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_recalculate_deletion_dates(p_date IN DATE);

END del_obsolete_cases_pack;
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."DEL_OBSOLETE_CASES_PACK" AS

/*--------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_create_temp_indexes
| DESCRIPTION : Creates temporary indexes to be used by the p_set_deletion_dates
|               process
--------------------------------------------------------------------------------*/
PROCEDURE p_create_temp_indexes;

/*--------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_drop_temp_indexes
| DESCRIPTION : Drops the temporary indexes to be used by the p_set_deletion_dates
|               process
--------------------------------------------------------------------------------*/
PROCEDURE p_drop_temp_indexes;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_print_reports
| DESCRIPTION : Generate csv audit/exception report files
-------------------------------------------------------------------------------------------------------*/
PROCEDURE p_print_reports(pv_report_type IN VARCHAR2,
                          pv_file_dir IN VARCHAR2,
                          pv_delete_complete IN VARCHAR2);

/*--------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_del_case_co_main
| DESCRIPTION : The main stored proc that control the flow of deletion process.
--------------------------------------------------------------------------------*/
PROCEDURE p_del_case_co_main IS

BEGIN

   p_init_globals;

   IF gn_init_del_date = 1 THEN
   -- initialize the deletion dates in cases and consolidated_orders tables.
      p_set_deletion_dates;
   END IF;

   -- Remove all temporary data records from the working tables for deletions.
   p_init_cm_delete_tables;

   IF gn_batch_size = 0 THEN
     -- Insert all linked CO's and Cases into co_state, case_state and delete_candidate table.
     p_populate_linked_co_ca;

     -- Apply generic rule checking on all linked co's and cases in delete_candidates table.
     -- Commented out as validation now occurs in p_populate_linked_co_ca
     --p_generic_rule_validation;

     -- Apply update delete flag back to case_state and co_state table.
     p_upd_linked_co_cases_del_flag;

     -- Update the delete flag if a case is linked to a undeletable co and vice versa.
     p_resolve_linked_del_flag;
   END IF;

   -- Insert all unlinked case and co's into deletion_candidates table.
   p_populate_unlinked_case;

   -- Apply generic rule checking on all unlinked cases
   -- Commented out as validation now occurs in p_populate_unlinked_case
   --p_generic_rule_validation;

   -- Perform the actual deletions of cases and co's.
   --IF gn_del_flag = 1 THEN
   --   p_perform_deletions;
   --END IF;

   -- Print audit and exceptions reports.
   --p_print_audit_report;
   --p_print_exceptions_report;

EXCEPTION
  WHEN OTHERS THEN
    dbms_output.put_line('p_del_case_co_main: ' ||SQLERRM);
    ROLLBACK;
    RAISE;
END;

/*--------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_init_globals
| DESCRIPTION  : Initialize CaseMan deletion temporary data.
--------------------------------------------------------------------------------*/
PROCEDURE p_init_globals IS

BEGIN
   -- Get the Bulk Collect size
   SELECT item_value INTO gn_bulk_limit
     FROM system_data
   WHERE item = 'DEL_BULK_COLLECT_SIZE' AND admin_court_code = 0;

   -- Get the De3etion Override Period
   SELECT item_value INTO gn_override
      FROM system_data sd
   WHERE sd.item = 'DEL_OVERRIDE' AND sd.admin_court_code = 0;

   -- Get the limit on the maximum number of cases and consolidated orders to be processed.
   SELECT item_value INTO gn_batch_size
      FROM system_data sd
   WHERE sd.item = 'DEL_LIMIT' AND sd.admin_court_code = 0;

   -- Get the flag to decide whether the deletion dates in cases/consolidated_orders will be initialized.
   SELECT item_value INTO gn_init_del_date
      FROM system_data sd
   WHERE sd.item = 'DEL_INIT_DATE' AND sd.admin_court_code = 0;

   -- Indicate whether the cases/co's will physically be deleted from the database.
   SELECT item_value INTO gn_del_flag
      FROM system_data sd
   WHERE sd.item = 'DEL_DEL_FLAG' AND sd.admin_court_code = 0;

   -- Specify the maxiumu size of each of generated CSV report file.
   SELECT item_value INTO gn_csv_rec_count
      FROM system_data sd
   WHERE sd.item = 'DEL_CSV_LIMIT' AND sd.admin_court_code = 0;

   -- Retrieve the number of deletion threads that will be running
   SELECT item_value INTO gn_thead_cnt
      FROM system_data sd
   WHERE sd.item = 'DEL_NO_THREADS' AND sd.admin_court_code = 0;

END;

/*--------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_init_cm_delete_tables
| DESCRIPTION : Initialize CaseMan deletion temporary data.
--------------------------------------------------------------------------------*/
PROCEDURE p_init_cm_delete_tables IS

BEGIN

   EXECUTE IMMEDIATE 'TRUNCATE TABLE delete_candidates';
   EXECUTE IMMEDIATE 'TRUNCATE TABLE case_state';
   EXECUTE IMMEDIATE 'TRUNCATE TABLE co_state';
   EXECUTE IMMEDIATE 'TRUNCATE TABLE delete_sql_errors';

END;

/*--------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_create_temp_indexes
| DESCRIPTION : Creates temporary indexes to be used by the p_set_deletion_dates
|               process
--------------------------------------------------------------------------------*/
PROCEDURE p_create_temp_indexes IS

BEGIN

    BEGIN
        EXECUTE IMMEDIATE 'CREATE INDEX case_events_tmp_ix1 ON case_events (case_number, std_event_id, judg_seq, deleted_flag, event_date)';
        EXCEPTION
        WHEN OTHERS THEN NULL;
    END;

    BEGIN
        EXECUTE IMMEDIATE 'CREATE INDEX judgments_tmp_ix1 ON judgments (judg_seq, case_number, status)';
        EXCEPTION
        WHEN OTHERS THEN NULL;
    END;

    BEGIN
        EXECUTE IMMEDIATE 'CREATE INDEX event_deletion_rules_tmp_ix1 ON event_deletion_rules (std_event_id, event_type, retention_period)';
        EXCEPTION
        WHEN OTHERS THEN NULL;
    END;

END;

/*--------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_drop_temp_indexes
| DESCRIPTION : Drops the temporary indexes to be used by the p_set_deletion_dates
|               process
--------------------------------------------------------------------------------*/
PROCEDURE p_drop_temp_indexes IS

BEGIN

    BEGIN
        EXECUTE IMMEDIATE 'DROP INDEX case_events_tmp_ix1';
        EXCEPTION
        WHEN OTHERS THEN NULL;
    END;

    BEGIN
        EXECUTE IMMEDIATE 'DROP INDEX judgments_tmp_ix1';
        EXCEPTION
        WHEN OTHERS THEN NULL;
    END;

    BEGIN
        EXECUTE IMMEDIATE 'DROP INDEX event_deletion_rules_tmp_ix1';
        EXCEPTION
        WHEN OTHERS THEN NULL;
    END;

END;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE                                                                                 *
| NAME          : p_set_deletion_dates                                                                        *
| DESCRIPTION   : Compute and set deletion date column in the CASES and
|                 Consolidated_Orders tables
--------------------------------------------------------------------------------*/
PROCEDURE p_set_deletion_dates IS
  CURSOR cases_cur
  IS
  SELECT c.case_number
  FROM cases c;

  CURSOR co_cur
  IS
  SELECT co.co_number
  FROM consolidated_orders co;

  TYPE t_case_number IS TABLE OF CASES.case_number%TYPE;
  TYPE t_co_number IS TABLE OF CONSOLIDATED_ORDERS.co_number%TYPE;
  l_case_numbers t_case_number;
  l_co_numbers t_co_number;

  l_creation_ret    NUMBER;
  l_insig_evt_ret   NUMBER;

BEGIN
   IF gn_bulk_limit IS NULL THEN
     p_init_globals;
   END IF;

   -- Create the temporary indexes for the process
   p_create_temp_indexes;

   -- Get the constant retention periods
   SELECT period
   INTO l_creation_ret
   FROM default_retention_period
   WHERE retention_type = 'CASE_CREATE';

   SELECT period
   INTO l_insig_evt_ret
   FROM default_retention_period
   WHERE retention_type = 'INSIG_EVENT';

  OPEN cases_cur;
  LOOP
    FETCH cases_cur
    BULK COLLECT INTO l_case_numbers
    LIMIT gn_bulk_limit;

    FOR i IN 1..l_case_numbers.COUNT
    LOOP
        p_perform_calc_del_date(l_case_numbers(i), 'CA', l_creation_ret, l_insig_evt_ret);
    END LOOP;
    COMMIT;

    EXIT WHEN l_case_numbers.COUNT = 0;
    l_case_numbers.delete;
  END LOOP;
  COMMIT;
  CLOSE cases_cur;

  OPEN co_cur;
  LOOP
    FETCH co_cur
    BULK COLLECT INTO l_co_numbers
    LIMIT gn_bulk_limit;

    FOR i IN 1..l_co_numbers.COUNT
    LOOP
        p_perform_calc_del_date(l_co_numbers(i), 'CO', l_creation_ret, l_insig_evt_ret);
    END LOOP;
    COMMIT;

    EXIT WHEN l_co_numbers.COUNT = 0;
    l_co_numbers.delete;
  END LOOP;
  COMMIT;
  CLOSE co_cur;

  -- Drop the temporary indexes used by this procedure
  p_drop_temp_indexes;

EXCEPTION
  WHEN OTHERS THEN
    p_drop_temp_indexes;
    dbms_output.put_line('p_set_deletion_dates: ' ||SQLERRM);
    ROLLBACK;
    RAISE;
END;

/*-------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_perform_recalc_del_date
| DESCRIPTION : Recalulate and Update the deletion date of a case, consolidated order.
--------------------------------------------------------------------------------------*/
PROCEDURE p_perform_calc_del_date (pv_identifier IN VARCHAR2,
                                   pv_type       IN VARCHAR2,
                                   pn_create_ret IN NUMBER,
                                   pn_insig_ret  IN NUMBER) IS
  v_deletion_date date;
  v_latest_event_date date;

BEGIN
  CASE pv_type
     WHEN 'CA' THEN
        SELECT
          MAX(NVL(ce.event_date, c.date_of_issue)) AS latest_event_date,
          GREATEST(
             MAX(NVL(ADD_MONTHS(c.date_of_issue, pn_create_ret),
                           TO_DATE('1900/01/01','yyyy/mm/dd'))),
             MAX(NVL( NVL(ADD_MONTHS(ce.event_date, edr.retention_period), ADD_MONTHS(ce.event_date, pn_insig_ret)),
                 TO_DATE('1900/01/01','yyyy/mm/dd'))),
             NVL(MAX(ADD_MONTHS(ce.event_date, jdr.retention_period)), TO_DATE('1900/01/01','yyyy/mm/dd'))
             ) AS deletion_date
          INTO v_latest_event_date, v_deletion_date
        FROM CASES c LEFT OUTER JOIN
             (CASE_EVENTS ce  LEFT OUTER JOIN event_deletion_rules edr
                                   ON ce.std_event_id = edr.std_event_id AND
                                      ce.deleted_flag = 'N' AND
                                      edr.event_type IN ('CE','CS','CI')
                              LEFT OUTER JOIN (judgments j JOIN judgment_deletion_rules jdr
                                                                ON j.status = jdr.status)
                                   ON   ce.case_number = j.case_number AND
                                        ce.judg_seq = j.judg_seq AND
                                        ce.std_event_id = jdr.std_event_id AND
                                        ce.deleted_flag = 'N'
                              )
                         ON c.case_number = ce.case_number
        WHERE c.case_number = pv_identifier;
        UPDATE cases SET last_event_date = v_latest_event_date, deletion_date = v_deletion_date
          WHERE case_number = pv_identifier;

     WHEN 'CO' THEN
        SELECT
          MAX(NVL(coe.event_date, co.appln_received_date)) AS latest_event_date,
          GREATEST(MAX(ADD_MONTHS(co.appln_received_date, pn_create_ret)),
             MAX(NVL(NVL(ADD_MONTHS(coe.event_date, edr.retention_period),
             ADD_MONTHS(coe.event_date, pn_insig_ret)), TO_DATE('1900/01/01','yyyy/dd/mm')))
          )
        INTO v_latest_event_date, v_deletion_date
        FROM consolidated_orders co LEFT OUTER JOIN
            (co_events coe
            LEFT OUTER JOIN event_deletion_rules edr
              ON coe.std_event_id = edr.std_event_id AND
                 coe.error_indicator = 'N' AND
                 edr.event_type = 'CO')
            ON co.co_number = coe.co_number
         WHERE co.co_number = pv_identifier;
        UPDATE consolidated_orders co SET co.last_event_date = v_latest_event_date,
                                          co.deletion_date = v_deletion_date
          WHERE co.co_number = pv_identifier;
  END CASE;
END;

/*-------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_populate_linked_co_ca
| DESCRIPTION   : Insert linked candidate cases and consolidated orders into candidate
|                 tables.
|-------------------------------------------------------------------------------------*/
PROCEDURE p_populate_linked_co_ca IS
  CURSOR co_cur IS
  SELECT co.co_number, co.admin_court_code, co.co_status
    FROM consolidated_orders co;

  CURSOR cor_cur IS
  SELECT co.co_number, co.admin_court_code, co.co_status
    FROM consolidated_orders co
    WHERE co.deletion_date < SYSDATE;

  CURSOR cor_cur_or IS
  SELECT co.co_number, co.admin_court_code, co.co_status
    FROM consolidated_orders co
    WHERE co.deletion_date < SYSDATE
      AND ADD_MONTHS(co.last_event_date, gn_override) < SYSDATE;

  CURSOR case_cur IS
    SELECT distinct ad.debt_case_number, c.admin_crt_code, c.status, c.deletion_date, c.last_event_date
    FROM allowed_debts ad LEFT OUTER JOIN cases c ON
       ad.debt_case_number = c.case_number
    WHERE ad.debt_case_number IS NOT NULL;

  TYPE t_case_number IS TABLE OF cases.case_number%TYPE;
  TYPE t_co_number IS TABLE OF consolidated_orders.co_number%TYPE;
  TYPE t_court_code IS TABLE OF cases.admin_crt_code%TYPE;
  TYPE t_status IS TABLE OF cases.status%TYPE;
  TYPE t_co_status IS TABLE OF consolidated_orders.co_status%TYPE;
  TYPE t_deletion_date IS TABLE OF cases.deletion_date%TYPE;
  TYPE t_last_event_date IS TABLE OF cases.last_event_date%TYPE;
  TYPE t_delete_flag IS TABLE OF delete_candidates.delete_flag%TYPE;
  TYPE t_exception_reason IS TABLE OF delete_candidates.exception_reason%TYPE;
  TYPE t_delete_index IS TABLE OF delete_candidates.delete_index%TYPE;

  l_case_numbers t_case_number;
  l_co_numbers t_co_number;
  l_status t_status;
  l_co_status t_co_status;
  l_court_codes t_court_code;
  l_deletion_date t_deletion_date;
  l_last_event_date t_last_event_date;
  l_delete_flag t_delete_flag;
  l_exception_reason t_exception_reason;
  l_delete_index t_delete_index;

  pv_exception_reason delete_candidates.exception_reason%TYPE;
  pv_del_flag delete_candidates.delete_flag%TYPE;

  l_total_records   NUMBER;
  l_index_limit     NUMBER;
  l_del_index   NUMBER;

BEGIN

    l_delete_flag := t_delete_flag();
    l_exception_reason := t_exception_reason();
    l_delete_index := t_delete_index();

    -- Insert all Consolidated Orders into the CO_STATE table
    OPEN co_cur;
    LOOP
       FETCH co_cur
       BULK COLLECT INTO l_co_numbers, l_court_codes, l_co_status
       LIMIT gn_bulk_limit;

       EXIT WHEN l_co_numbers.COUNT = 0;

       FORALL i IN 1..l_co_numbers.COUNT
          INSERT INTO co_state (co_number, delete_flag, reset) VALUES (l_co_numbers(i), 'N', 'Y');

       COMMIT;
       l_co_numbers.DELETE;
       l_court_codes.DELETE;
       l_co_status.DELETE;
    END LOOP;
    CLOSE co_cur;

    IF gn_override = 0 THEN
       OPEN cor_cur;
    ELSE
       OPEN cor_cur_or;
    END IF;

    -- Insert all candidate consolidated orders into the DELETE_CANDIDATES table
    LOOP
      IF gn_override = 0 THEN
        FETCH cor_cur
        BULK COLLECT INTO l_co_numbers, l_court_codes, l_co_status
        LIMIT gn_bulk_limit;
      ELSE
        FETCH cor_cur_or
        BULK COLLECT INTO l_co_numbers, l_court_codes, l_co_status
        LIMIT gn_bulk_limit;
      END IF;

      -- Initialise the delete index
      l_total_records := l_co_numbers.COUNT;
      l_index_limit := ROUND(l_total_records / gn_thead_cnt);
      l_del_index := 1;

      FOR co_idx IN 1..l_co_numbers.COUNT
      LOOP
        -- Perform validation
        pv_exception_reason := f_generic_rule('CO', l_co_numbers(co_idx));
        l_exception_reason.extend();
        l_delete_flag.extend();
        l_delete_index.extend();
        l_exception_reason(co_idx) := pv_exception_reason;
        IF pv_exception_reason IS NULL THEN
            l_delete_flag(co_idx) := 'Y';
        ELSE
            l_delete_flag(co_idx) := 'N';
        END IF;

        -- Increment the deletion index if required
        IF MOD(co_idx, l_index_limit) = 0 AND l_del_index < gn_thead_cnt THEN
            l_del_index := l_del_index + 1;
        END IF;
        l_delete_index(co_idx) := l_del_index;

      END LOOP;

      FORALL i IN 1..l_co_numbers.COUNT
         INSERT INTO delete_candidates (type, identifier, delete_flag, exception_reason, owning_code, status, delete_complete, delete_index) VALUES
            ('CO', l_co_numbers(i), l_delete_flag(i), l_exception_reason(i), l_court_codes(i), l_co_status(i), 'N', l_delete_index(i));

      COMMIT;

      EXIT WHEN l_co_numbers.COUNT = 0;
      l_co_numbers.DELETE;
      l_court_codes.DELETE;
      l_co_status.DELETE;
      l_delete_flag.DELETE;
      l_exception_reason.DELETE;
      l_delete_index.DELETE;

    END LOOP;
    IF gn_override = 0 THEN
       CLOSE cor_cur;
    ELSE
       CLOSE cor_cur_or;
    END IF;

    OPEN case_cur;
    LOOP
       -- Insert all cases linked to a consolidated order into the CASE_STATE table
       FETCH case_cur
       BULK COLLECT INTO l_case_numbers, l_court_codes, l_status, l_deletion_date, l_last_event_date
       LIMIT gn_bulk_limit;

       EXIT WHEN l_case_numbers.COUNT = 0;

       FORALL i IN 1..l_case_numbers.COUNT
          INSERT INTO case_state (case_number, delete_flag, reset) VALUES
             (l_case_numbers(i), 'N', 'Y');

       COMMIT;

      -- Initialise the delete index
      l_total_records := l_case_numbers.COUNT;
      l_index_limit := ROUND(l_total_records / gn_thead_cnt);
      l_del_index := 1;

       -- For all cases linked to consolidated orders, insert into the DELETE_CANDIDATES table if old enough
       FOR i IN 1..l_case_numbers.COUNT
       LOOP

          -- Increment the deletion index if required
          IF MOD(i, l_index_limit) = 0 AND l_del_index < gn_thead_cnt THEN
            l_del_index := l_del_index + 1;
          END IF;

          IF l_deletion_date(i) IS NOT NULL THEN
            IF gn_override = 0 THEN
               IF l_deletion_date(i) < SYSDATE THEN

                  pv_exception_reason := f_generic_rule('CA', l_case_numbers(i));
                  IF pv_exception_reason IS NULL THEN
                     pv_del_flag := 'Y';
                  ELSE
                     pv_del_flag := 'N';
                  END IF;

                  INSERT INTO delete_candidates
                     (type, identifier, delete_flag, exception_reason, owning_code, status, delete_complete, delete_index)
                   VALUES ('CA', l_case_numbers(i), pv_del_flag, pv_exception_reason, l_court_codes(i), l_status(i), 'N', l_del_index);

               END IF;
            ELSE
               IF l_deletion_date(i) < SYSDATE AND
                  ADD_MONTHS(l_last_event_date(i),gn_override) < SYSDATE AND
                  ADD_MONTHS(l_last_event_date(i),gn_override) > l_deletion_date(i) THEN

                  pv_exception_reason := f_generic_rule('CA', l_case_numbers(i));
                  IF pv_exception_reason IS NULL THEN
                     pv_del_flag := 'Y';
                  ELSE
                     pv_del_flag := 'N';
                  END IF;

                  INSERT INTO delete_candidates
                     (type, identifier, delete_flag, exception_reason, owning_code, status, delete_complete, delete_index)
                   VALUES ('CA', l_case_numbers(i), pv_del_flag, pv_exception_reason, l_court_codes(i), l_status(i), 'N', l_del_index);

               END IF;
            END IF;
          END IF;
       END LOOP;

       COMMIT;

       l_case_numbers.DELETE;
       l_court_codes.DELETE;
       l_status.DELETE;
       l_exception_reason.DELETE;
       l_delete_flag.DELETE;
    END LOOP;
    CLOSE case_cur;

    UPDATE case_state cs SET cs.delete_flag = 'Y', cs.reset = 'N'
       WHERE cs.case_number NOT IN (SELECT dc.identifier FROM delete_candidates dc WHERE dc.type = 'CA');
    COMMIT;
END;

/*-------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_populate_unlinked_case
| DESCRIPTION   : Insert candidate cases not linked to consolidated orders into
|                 candidate tables.
--------------------------------------------------------------------------------------*/
PROCEDURE p_populate_unlinked_case IS
  CURSOR cases_cur
  IS
  SELECT case_number, c.status, c.admin_crt_code
  FROM cases c
  WHERE c.deletion_date < SYSDATE AND c.deletion_date IS NOT NULL
      AND c.case_number NOT IN
     (SELECT ad.debt_case_number FROM allowed_debts ad WHERE ad.debt_case_number IS NOT NULL);

  CURSOR or_cases_cur
  IS
  SELECT case_number, c.status, c.admin_crt_code
  FROM cases c
  WHERE ADD_MONTHS(c.last_event_date, gn_override) < SYSDATE AND c.deletion_date < SYSDATE
      AND c.case_number NOT IN
     (SELECT ad.debt_case_number FROM allowed_debts ad WHERE ad.debt_case_number IS NOT NULL);

  TYPE t_case_number IS TABLE OF CASES.case_number%TYPE;
  TYPE t_status IS TABLE OF CASES.Status%TYPE;
  TYPE t_owning_crt IS TABLE OF cases.admin_crt_code%TYPE;
  TYPE t_delete_flag IS TABLE OF delete_candidates.delete_flag%TYPE;
  TYPE t_exception_reason IS TABLE OF delete_candidates.exception_reason%TYPE;
  TYPE t_delete_index IS TABLE OF delete_candidates.delete_index%TYPE;

  l_case_numbers t_case_number;
  l_status t_status;
  l_owning_crt t_owning_crt;
  l_delete_flag t_delete_flag;
  l_exception_reason t_exception_reason;
  l_delete_index t_delete_index;

  pn_record_count NUMBER;
  pn_candidates_count NUMBER;
  pv_exception_reason delete_candidates.exception_reason%TYPE;

  l_index_limit     NUMBER;
  l_del_index   NUMBER;

BEGIN

  pn_record_count := 0;
  l_delete_flag := t_delete_flag();
  l_exception_reason := t_exception_reason();
  l_delete_index := t_delete_index();

  IF gn_override = 0 THEN
    OPEN cases_cur;
  ELSE
    OPEN or_cases_cur;
  END IF;

  LOOP
    IF gn_override = 0 THEN
      FETCH cases_cur
         BULK COLLECT INTO l_case_numbers, l_status, l_owning_crt
         LIMIT gn_bulk_limit;
    ELSE
       FETCH or_cases_cur
         BULK COLLECT INTO l_case_numbers, l_status, l_owning_crt
         LIMIT gn_bulk_limit;
    END IF;

    IF gn_batch_size > 0 THEN
      pn_record_count := pn_record_count + l_case_numbers.COUNT;
      IF pn_record_count > gn_batch_size THEN
         pn_candidates_count := l_case_numbers.COUNT - (pn_record_count - gn_batch_size) ;
      ELSE
         pn_candidates_count := l_case_numbers.COUNT;
      END IF;
    ELSE
      pn_candidates_count := l_case_numbers.COUNT;
    END IF;

    -- Initialise the delete index
    l_index_limit := ROUND(pn_candidates_count / gn_thead_cnt);
    l_del_index := 1;

    FOR case_idx IN 1..pn_candidates_count
    LOOP
        -- Perform validation
        pv_exception_reason := f_generic_rule('CA', l_case_numbers(case_idx));
        l_exception_reason.extend();
        l_delete_flag.extend();
        l_delete_index.extend();
        l_exception_reason(case_idx) := pv_exception_reason;
        IF pv_exception_reason IS NULL THEN
            l_delete_flag(case_idx) := 'Y';
        ELSE
            l_delete_flag(case_idx) := 'N';
        END IF;

        -- Increment the deletion index if required
        IF MOD(case_idx, l_index_limit) = 0 AND l_del_index < gn_thead_cnt THEN
            l_del_index := l_del_index + 1;
        END IF;
        l_delete_index(case_idx) := l_del_index;
    END LOOP;

    FORALL i IN 1..pn_candidates_count
       INSERT INTO delete_candidates dc (type, identifier, delete_flag, exception_reason, status, owning_code, delete_complete, delete_index)
              VALUES ('CA', l_case_numbers(i), l_delete_flag(i), l_exception_reason(i), l_status(i), l_owning_crt(i), 'N', l_delete_index(i));

    COMMIT;

    IF gn_batch_size > 0 THEN
       EXIT WHEN l_case_numbers.COUNT = 0 OR pn_record_count >= gn_batch_size;
    ELSE
       EXIT WHEN l_case_numbers.COUNT = 0;
    END IF;

    -- Reinitialise collections
    l_case_numbers.DELETE;

    IF l_status IS NOT NULL THEN
        l_status.DELETE;
    END IF;

    IF l_owning_crt IS NOT NULL THEN
        l_owning_crt.DELETE;
    END IF;

    IF l_delete_flag IS NOT NULL THEN
        l_delete_flag.DELETE;
    END IF;

    IF l_exception_reason IS NOT NULL THEN
        l_exception_reason.DELETE;
    END IF;

    IF l_delete_index IS NOT NULL THEN
        l_delete_index.DELETE;
    END IF;

  END LOOP;

  IF gn_override = 0 THEN
     CLOSE cases_cur;
  ELSE
     CLOSE or_cases_cur;
  END IF;

  COMMIT;
END;

/*-------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_generic_rule_validation
| DESCRIPTION   : Apply generic rule validations to cases and consolidated orders.
--------------------------------------------------------------------------------------*/
PROCEDURE p_generic_rule_validation IS
  CURSOR candidates_cur
  IS
  SELECT dc.type, dc.identifier
     FROM delete_candidates dc
     WHERE dc.delete_flag IS NULL;

  TYPE t_identifiers IS TABLE OF delete_candidates.identifier%TYPE;
  TYPE t_types IS TABLE OF delete_candidates.type%TYPE;
  l_identifiers t_identifiers;
  l_types t_types;
  pv_exception_reason VARCHAR(50);

BEGIN
  IF gn_bulk_limit IS NULL THEN
    SELECT item_value INTO gn_bulk_limit
       FROM system_data
    WHERE item = 'DEL_BULK_COLLECT_SIZE';
  END IF;

  OPEN candidates_cur;
  LOOP
      FETCH candidates_cur
        BULK COLLECT INTO l_types, l_identifiers
        LIMIT gn_bulk_limit;

      FOR i IN 1..l_identifiers.COUNT
      LOOP
         pv_exception_reason := f_generic_rule(l_types(i), l_identifiers(i));
         UPDATE delete_candidates dc
            SET dc.delete_flag = DECODE(pv_exception_reason, NULL, 'Y', 'N'),
                dc.exception_reason = pv_exception_reason
         WHERE dc.identifier = l_identifiers(i);
      END LOOP;
      COMMIT;

      EXIT WHEN l_identifiers.COUNT = 0;

      l_identifiers.delete;
      l_types.delete;
   END LOOP;
   CLOSE candidates_cur;
   COMMIT;
END;

/*-------------------------------------------------------------------------------------
| TYPE          : PROCEDURE                                                                                 *
| NAME          : p_upd_co_cases_delete_flag                                                                   *
| DESCRIPTION   : Update case_state and co_state tables' delete_flag from that of the
|                 of the Delete_Candidates table.
--------------------------------------------------------------------------------------*/
PROCEDURE p_upd_linked_co_cases_del_flag IS

BEGIN
   UPDATE case_state cs SET cs.delete_flag = (SELECT dc.delete_flag FROM delete_candidates dc
                                                WHERE dc.identifier = cs.case_number
                                                  AND dc.type = 'CA')
   WHERE EXISTS
      (SELECT * FROM delete_candidates dc2 WHERE dc2.identifier = cs.case_number
                                             AND dc2.type = 'CA');

   UPDATE case_state cs SET cs.delete_flag = 'N', cs.reset = 'Y' WHERE NOT EXISTS
      (SELECT * FROM delete_candidates dc WHERE dc.identifier = cs.case_number
                                       AND dc.type = 'CA');

   UPDATE case_state cs SET cs.reset = 'N'
      WHERE cs.delete_flag = 'Y';

   UPDATE co_state cs SET cs.delete_flag = (SELECT dc.delete_flag FROM delete_candidates dc
                                              WHERE dc.identifier = cs.co_number
                                                AND dc.type = 'CO')
   WHERE EXISTS
      (SELECT * FROM delete_candidates dc2 WHERE dc2.identifier = cs.co_number
                                             AND dc2.type = 'CO');

   UPDATE co_state cs SET cs.delete_flag = 'N', cs.reset = 'Y' WHERE NOT EXISTS
      (SELECT * FROM delete_candidates dc WHERE dc.identifier = cs.co_number
                                       AND dc.type = 'CO');

   UPDATE co_state cs SET cs.reset = 'N'
      WHERE cs.delete_flag = 'Y';

   COMMIT;
END;

/*-------------------------------------------------------------------------------------
| TYPE          : FUNCTION                                                                                 *
| NAME          : f_generic_rule                                                                             *
| DESCRIPTION   : Perform the actual rule validations on cases and consolidated_Orders
|                 tables
--------------------------------------------------------------------------------------*/
FUNCTION f_generic_rule(p_type varchar2, p_identifier varchar2) RETURN varchar2 IS
   exception_reason VARCHAR2(50);

BEGIN

   exception_reason := NULL;
   CASE p_type
      WHEN 'CA' THEN
        exception_reason := f_validate_ae(p_identifier);
        IF exception_reason IS NOT NULL THEN
           RETURN exception_reason;
        END IF;
        exception_reason := f_is_money_in_crt(p_identifier, p_type);
        IF exception_reason IS NOT NULL THEN
           RETURN exception_reason;
        END IF;
        exception_reason := f_is_live_warrant(p_identifier, p_type);
        IF exception_reason IS NOT NULL THEN
           RETURN exception_reason;
        END IF;
        exception_reason := f_is_live_judg(p_identifier);
        IF exception_reason IS NOT NULL THEN
           RETURN exception_reason;
        END IF;
        exception_reason := f_is_invalid_status(p_identifier);
        IF exception_reason IS NOT NULL THEN
           RETURN exception_reason;
        END IF;
      WHEN 'CO' THEN
        exception_reason := f_is_money_in_crt(p_identifier, p_type);
        IF exception_reason IS NOT NULL THEN
           RETURN exception_reason;
        END IF;
        exception_reason := f_is_live_warrant(p_identifier, p_type);
        IF exception_reason IS NOT NULL THEN
           RETURN exception_reason;
        END IF;
   END CASE;
   RETURN exception_reason;

END f_generic_rule;

/*-------------------------------------------------------------------------------------
| TYPE          : PROCEDURE                                                                                 *
| NAME          : p_resolve_linked_del_flag                                                             *          *
| DESCRIPTION   : Update consolidated orders and cases deletion status based on whether
|                 a case is linked to an undeletable CO or a CO is linked to an
|                 undeletable case.                            *
|-------------------------------------------------------------------------------------*/
PROCEDURE p_resolve_linked_del_flag IS
  CURSOR cases_cur
  IS
  SELECT cs.case_number, cs.delete_flag
     FROM case_state cs;
  CURSOR co_cur
  IS
  SELECT cos.co_number, cos.delete_flag
     FROM co_state cos;

  TYPE t_identifiers IS TABLE OF CASES.case_number%TYPE;
  TYPE t_deletes IS TABLE OF CONSOLIDATED_ORDERS.co_number%TYPE;
  l_identifiers t_identifiers;
  l_deletes t_deletes;
BEGIN
  IF gn_bulk_limit IS NULL THEN
     p_init_globals;
  END IF;

  LOOP
    UPDATE co_state co SET co.delete_flag = 'N', co.reset = 'Y'
       WHERE co.delete_flag = 'Y' AND co.co_number IN (
             SELECT  ad.debt_co_number
                FROM case_state cs, allowed_debts ad
                WHERE cs.case_number = ad.debt_case_number
                   AND ad.debt_co_number IS NOT NULL
                   AND cs.reset = 'Y');

    UPDATE case_state cs SET cs.reset = 'N' WHERE cs.reset = 'Y';
    COMMIT;

    UPDATE case_state cs SET cs.delete_flag = 'N', cs.reset = 'Y'
       WHERE cs.delete_flag = 'Y' AND cs.case_number IN (
             SELECT  ad.debt_case_number
                FROM co_state cos, allowed_debts ad
                WHERE cos.co_number = ad.debt_co_number
                   AND ad.debt_co_number IS NOT NULL
                   AND cos.reset = 'Y');

    UPDATE co_state cs SET cs.reset = 'N' WHERE cs.reset = 'Y';

    IF SQL%ROWCOUNT <= 0 THEN
       EXIT;
    ELSE
       COMMIT;
    END IF;

  END LOOP;

  OPEN cases_cur;
  LOOP
     FETCH cases_cur
       BULK COLLECT INTO l_identifiers, l_deletes
       LIMIT gn_bulk_limit;

     FORALL i IN 1..l_identifiers.COUNT
        UPDATE delete_candidates dc SET dc.delete_flag = l_deletes(i),
                                        dc.exception_reason = DECODE(l_deletes(i),
                                                                     'N',
                                                                     NVL(dc.exception_reason,'LINKED_LIVE_CO'),
                                                                     NULL)
           WHERE dc.identifier = l_identifiers(i)
             AND dc.type = 'CA';

     EXIT WHEN l_identifiers.COUNT = 0;
     l_identifiers.delete;
     l_deletes.delete;
  END LOOP;
  CLOSE cases_cur;

  OPEN co_cur;
  LOOP
     FETCH co_cur
       BULK COLLECT INTO l_identifiers, l_deletes
       LIMIT gn_bulk_limit;

     FORALL i IN 1..l_identifiers.COUNT
        UPDATE delete_candidates dc SET dc.delete_flag = l_deletes(i),
                                        dc.exception_reason = DECODE(l_deletes(i),
                                                                     'N',
                                                                     NVL(dc.exception_reason,'LINKED_LIVE_CASE'),
                                                                     NULL)
           WHERE dc.identifier = l_identifiers(i)
             AND dc.type = 'CO';

     EXIT WHEN l_identifiers.COUNT = 0;
     l_identifiers.delete;
     l_deletes.delete;
  END LOOP;
  CLOSE co_cur;
END;

/*-------------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_perform_deletions
| DESCRIPTION   : Calling p_delete_case and p_delete_co to delete cases and co's.
--------------------------------------------------------------------------------------*/
PROCEDURE p_perform_deletions (p_delete_index IN NUMBER) IS
  CURSOR candidates_cur
  IS
  SELECT dc.identifier, dc.type
  FROM delete_candidates dc
  WHERE delete_flag = 'Y'
  AND delete_index = p_delete_index;

  TYPE t_identifiers IS TABLE OF delete_candidates.identifier%TYPE;
  TYPE t_types IS TABLE OF delete_candidates.type%TYPE;
  l_identifiers t_identifiers;
  l_types t_types;
  v_valid VARCHAR2(1);
  v_reason delete_sql_errors.error_message%TYPE;
BEGIN
   IF gn_bulk_limit IS NULL THEN
     p_init_globals;
   END IF;
  -- Disable audit triggers
  --p_disable_audit_triggers();

  OPEN candidates_cur;
  LOOP
     FETCH candidates_cur
        BULK COLLECT INTO l_identifiers, l_types
        LIMIT gn_bulk_limit;

     FOR i IN 1..l_identifiers.COUNT
     LOOP
        v_valid := 'Y';
        v_reason := NULL;
        CASE l_types(i)
           WHEN 'CA' THEN
                p_delete_case(l_identifiers(i),p_valid => v_valid,p_reason => v_reason);
           WHEN 'CO' THEN
                p_delete_co(l_identifiers(i),p_valid => v_valid,p_reason => v_reason);
        END CASE;
         IF v_valid = 'N' THEN
            -- Problem was encountered deleting the record, update the delete_candidates
            -- table to state it could not be deleted and write a row to the delete_sql_errors table
          UPDATE   delete_candidates
             SET delete_flag = 'N', exception_reason = 'SQL_ERROR'
          WHERE identifier = l_identifiers(i)
            AND type = l_types(i);

          INSERT INTO delete_sql_errors
            VALUES (l_types(i), l_identifiers(i), v_reason);

            COMMIT;
        END IF;
     END LOOP;

     EXIT WHEN l_identifiers.COUNT = 0;
     l_identifiers.DELETE;
     l_types.DELETE;
  END LOOP;
  CLOSE candidates_cur;

  -- Re-enable the audit triggers
  --p_enable_audit_triggers();

EXCEPTION
  WHEN OTHERS THEN
    dbms_output.put_line('p_perform_deletions: ' ||SQLERRM);
    ROLLBACK;
    RAISE;

END;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_print_audit_report
| DESCRIPTION : Export Audit Report Records to CSV file.
--------------------------------------------------------------------------------*/
PROCEDURE p_print_audit_report IS

BEGIN

    IF gn_del_flag IS NULL THEN
        p_init_globals;
    END IF;

    IF gn_del_flag = 1 THEN
        p_print_reports('AUDIT', 'SOURCE_DIR', 'Y');
    ELSE
        p_print_reports('AUDIT', 'SOURCE_DIR', 'N');
    END IF;

EXCEPTION
   WHEN OTHERS THEN
      dbms_output.put_line('p_print_audit_report: ' ||SQLERRM);
      RAISE;
END;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_print_exceptions_report
| DESCRIPTION : Export Exception Report Records to CSV file.
--------------------------------------------------------------------------------*/
PROCEDURE p_print_exceptions_report IS

BEGIN

    IF gn_del_flag IS NULL THEN
        p_init_globals;
    END IF;

    IF gn_del_flag = 1 THEN
        p_print_reports('EXP', 'SOURCE_DIR', 'Y');
    ELSE
        p_print_reports('EXP', 'SOURCE_DIR', 'N');
    END IF;

EXCEPTION
   WHEN OTHERS THEN
      dbms_output.put_line('p_print_exceptions_report: ' ||SQLERRM);
      RAISE;
END;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_print_reports
| DESCRIPTION : Export Audit or Exception Report Records to CSV file.
--------------------------------------------------------------------------------*/
PROCEDURE p_print_reports(pv_report_type IN VARCHAR2,
                          pv_file_dir IN VARCHAR2,
                          pv_delete_complete IN VARCHAR2) IS
   CURSOR del_audit_cur (pv_type VARCHAR2) IS
   SELECT dc.type, dc.identifier, dc.status, dc.owning_code
   FROM delete_candidates dc
   WHERE dc.delete_flag = 'Y' AND dc.type = pv_type AND dc.delete_complete = pv_delete_complete
   ORDER BY dc.owning_code;

   CURSOR del_exp_cur (pv_type VARCHAR2) IS
   SELECT dc.type, dc.identifier, dc.status, dc.owning_code, dc.exception_reason
   FROM delete_candidates dc JOIN delete_exception_reasons der ON
      dc.exception_reason = der.exception_reason AND der.report = 'Y'
   WHERE dc.delete_flag = 'N' AND dc.type = pv_type
   ORDER BY dc.owning_code;

   TYPE t_type IS TABLE OF delete_candidates.type%TYPE;
   TYPE t_identifier IS TABLE OF delete_candidates.identifier%TYPE;
   TYPE t_status IS TABLE OF delete_candidates.status%TYPE;
   TYPE t_owning_code IS TABLE OF delete_candidates.owning_code%TYPE;
   TYPE t_exception_reason IS TABLE OF delete_candidates.exception_reason%TYPE;

   l_types t_type;
   l_identifiers t_identifier;
   l_status t_status;
   l_owning_codes t_owning_code;
   l_exception_reason t_exception_reason;
   l_cm_types t_type := t_type();

   f_handle UTL_FILE.FILE_TYPE;
   pn_owning_court NUMBER := -1;
   pv_file_name VARCHAR2(100);
   pv_file_name_prefix VARCHAR2(30);
   pv_file_line VARCHAR(100);
   pv_file_hdr VARCHAR(100);
   pn_rec_count NUMBER := 0;
   pn_file_index NUMBER := 0;
BEGIN

   IF gn_bulk_limit IS NULL THEN
     p_init_globals;
   END IF;

   l_cm_types.EXTEND(2);
   l_cm_types(1) := 'CA';
   l_cm_types(2) := 'CO';

   FOR j IN 1..l_cm_types.COUNT
   LOOP
      CASE pv_report_type
         WHEN 'AUDIT' THEN
            OPEN del_audit_cur(l_cm_types(j));

            CASE l_cm_types(j)
               WHEN 'CA' THEN
                  pv_file_hdr := 'Case Number,Case Status,Court Code';
                  pv_file_name_prefix := 'cm-del-audit-case-';
               WHEN 'CO' THEN
                  pv_file_hdr := 'CO Number,CO Status,Court Code';
                  pv_file_name_prefix := 'cm-del-audit-co-';
            END CASE;
         WHEN 'EXP' THEN
            OPEN del_exp_cur (l_cm_types(j));

            CASE l_cm_types(j)
               WHEN 'CA' THEN
                  pv_file_hdr := 'Case Number,Case Status,Court Code,Exception Reason';
                  pv_file_name_prefix := 'cm-del-exp-case-';
               WHEN 'CO' THEN
                  pv_file_hdr := 'CO Number,CO Status,Court Code,Exception Reason';
                  pv_file_name_prefix := 'cm-del-exp-co-';
            END CASE;
      END CASE;

      pn_file_index := 0;

      LOOP
         CASE pv_report_type
            WHEN 'AUDIT' THEN
              FETCH del_audit_cur
                 BULK COLLECT INTO l_types, l_identifiers, l_status, l_owning_codes
                 LIMIT gn_bulk_limit;
           WHEN 'EXP' THEN
              FETCH del_exp_cur
                 BULK COLLECT INTO l_types, l_identifiers, l_status, l_owning_codes, l_exception_reason
                 LIMIT gn_bulk_limit;
         END CASE;

         EXIT WHEN l_identifiers.COUNT = 0;

         FOR i IN 1..l_identifiers.COUNT
         LOOP
            IF pn_file_index = 0 OR pn_rec_count >= gn_csv_rec_count THEN
                -- Close the previous file
                IF pn_file_index <> 0 THEN
                    UTL_FILE.FCLOSE(f_handle);
                END IF;

                -- Increment the file index
                pn_file_index := pn_file_index + 1;

                pv_file_name := pv_file_name_prefix || '-' ||
                               TO_CHAR(SYSDATE, 'yyyymmddhh24miss') || '-' || TO_CHAR(pn_file_index) || '.csv';
                f_handle := UTL_FILE.FOPEN(pv_file_dir, pv_file_name, 'W');

                UTL_FILE.PUT_LINE(f_handle, pv_file_hdr);
                pn_rec_count := 1;
            END IF;

            pv_file_line := l_identifiers(i) || ',' ||
                            l_status(i) || ',' ||
                            l_owning_codes(i) ;

            IF pv_report_type = 'EXP' THEN
               pv_file_line := pv_file_line || ',' || l_exception_reason(i);
            END IF;

            pn_rec_count := pn_rec_count + 1;

            UTL_FILE.PUT_LINE(f_handle, pv_file_line);
         END LOOP;

         l_types.DELETE;
         l_identifiers.DELETE;
         l_status.DELETE;
         l_owning_codes.DELETE;
         IF l_exception_reason IS NOT NULL THEN
            l_exception_reason.DELETE;
         END IF;
      END LOOP;

      IF f_handle.id IS NOT NULL THEN
         UTL_FILE.FCLOSE(f_handle);
      END IF;

      CASE pv_report_type
         WHEN 'AUDIT' THEN
            CLOSE del_audit_cur;
         WHEN 'EXP' THEN
            CLOSE del_exp_cur;
      END CASE;
   END LOOP;

END;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_delete_case
| DESCRIPTION : Deletes a case record and all child records including output
|                       data and audit data held in the SUPS_AMENDMENTS table.
--------------------------------------------------------------------------------*/
PROCEDURE p_delete_case (pv_case_number IN VARCHAR2,
                         p_valid        IN OUT VARCHAR2,
                         p_reason       IN OUT VARCHAR2) IS

    CURSOR  get_ae_data IS
    SELECT  ae_number,
            debtors_employers_party_id
    FROM    ae_applications
    WHERE   case_number = pv_case_number;

    CURSOR  get_judg_data IS
    SELECT  judg_seq
    FROM    judgments
    WHERE   case_number = pv_case_number;

    CURSOR  get_party_data IS
    SELECT  cpr.party_id,
            cpr.party_role_code,
            cpr.case_party_no
    FROM    case_party_roles cpr
    WHERE   cpr.case_number = pv_case_number
    AND NOT EXISTS (
        SELECT NULL FROM coded_parties cp
        WHERE cp.party_id = cpr.party_id);

    CURSOR  get_party_data_cp IS
    SELECT  cpr.party_role_code,
            cpr.case_party_no
    FROM    case_party_roles cpr
    WHERE   cpr.case_number = pv_case_number
    AND EXISTS (
        SELECT NULL FROM coded_parties cp
        WHERE cp.party_id = cpr.party_id);

    CURSOR  get_warrant_data IS
    SELECT  warrant_id
    FROM    warrants
    WHERE   case_number = pv_case_number;

    CURSOR  get_warrant_returns (cp_warrant_id VARCHAR2) IS
    SELECT  warrant_returns_id
    FROM    warrant_returns
    WHERE   warrant_id = cp_warrant_id;

    CURSOR  get_obligation_data IS
    SELECT  obligation_seq
    FROM    obligations
    WHERE   case_number = pv_case_number;

    CURSOR  get_case_event_data IS
    SELECT  event_seq
    FROM    case_events
    WHERE   case_number = pv_case_number;

    CURSOR  get_ae_events (cp_ae_number VARCHAR2) IS
    SELECT  ae_event_seq
    FROM    ae_events
    WHERE   ae_number = cp_ae_number;

    CURSOR  get_addressid_by_party (cp_party_id NUMBER) IS
    SELECT  address_id
    FROM    given_addresses
    WHERE   party_id = cp_party_id;

    CURSOR  get_addressid_by_case IS
    SELECT  address_id
    FROM    given_addresses
    WHERE   address_type_code IN ('POSSESSION','WORKPLACE','SUBSERV')
    AND     case_number = pv_case_number;

    CURSOR  get_addressid_by_cpr (cp_party_no NUMBER, cp_party_code VARCHAR2) IS
    SELECT  address_id
    FROM    given_addresses
    WHERE   case_number = pv_case_number
    AND     case_party_no = cp_party_no
    AND     party_role_code = cp_party_code;

    CURSOR  get_hearing_data IS
    SELECT  hrg_seq
    FROM    hearings
    WHERE   case_number = pv_case_number;

    CURSOR  get_payment_data IS
    SELECT  transaction_number, admin_court_code
    FROM    payments
    WHERE   enforcement_parent = pv_case_number;

    v_ae_number     ae_applications.ae_number%TYPE;
    v_emp_id        ae_applications.debtors_employers_party_id%TYPE;
    v_judg_seq      judgments.judg_seq%TYPE;
    v_party_id      parties.party_id%TYPE;
    v_party_role    case_party_roles.party_role_code%TYPE;
    v_case_party_no case_party_roles.case_party_no%TYPE;
    v_warrant_id    warrants.warrant_id%TYPE;
    v_warrant_ret_id    warrant_returns.warrant_returns_id%TYPE;
    v_obl_seq       obligations.obligation_seq%TYPE;
    v_case_event_seq    case_events.event_seq%TYPE;
    v_ae_event_seq  ae_events.ae_event_seq%TYPE;
    v_address_id    given_addresses.address_id%TYPE;
    v_hearing_seq   hearings.hrg_seq%TYPE;
    v_trans_no      payments.transaction_number%TYPE;
    v_court_code    courts.code%TYPE;

BEGIN

    -- Delete WFT, ECHR and obligation data
    OPEN get_obligation_data;
    LOOP
        FETCH   get_obligation_data
        INTO    v_obl_seq;
        EXIT WHEN get_obligation_data%NOTFOUND OR get_obligation_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'OBLIGATIONS' AND pk01 = TO_CHAR(v_obl_seq) AND pk02 = pv_case_number;
    END LOOP;
    CLOSE get_obligation_data;
    DELETE FROM sups_amendments WHERE table_name = 'WINDOW_FOR_TRIAL' AND pk01 = pv_case_number;
    DELETE FROM wft_exclusions WHERE wfe_wft_case_number = pv_case_number;
    DELETE FROM window_for_trial WHERE wft_case_number = pv_case_number;
    DELETE FROM obligations WHERE case_number = pv_case_number;
    DELETE FROM echr_article_protocol WHERE deft_case_number = pv_case_number;
    DELETE FROM echr_details WHERE deft_case_number = pv_case_number;

    -- Delete AE data including AE Events and AE Employer data
    OPEN get_ae_data;
    LOOP
        FETCH   get_ae_data
        INTO    v_ae_number,
                v_emp_id;
        EXIT WHEN get_ae_data%NOTFOUND OR get_ae_data%NOTFOUND IS NULL;

        OPEN get_ae_events (v_ae_number);
        LOOP
            FETCH   get_ae_events
            INTO    v_ae_event_seq;
            EXIT WHEN get_ae_events%NOTFOUND OR get_ae_events%NOTFOUND IS NULL;
            p_delete_outputs('AE', v_ae_event_seq);
            DELETE FROM sups_amendments WHERE table_name = 'AE_EVENTS' AND pk01 = TO_CHAR(v_ae_event_seq);
        END LOOP;
        CLOSE get_ae_events;

        DELETE FROM sups_amendments WHERE table_name = 'AE_APPLICATIONS' AND pk01 = v_ae_number;
        IF v_emp_id IS NOT NULL THEN
            DELETE FROM sups_amendments WHERE table_name = 'PARTIES' AND pk01 = TO_CHAR(v_emp_id);
        END IF;

        OPEN get_addressid_by_party (v_emp_id);
        LOOP
            FETCH   get_addressid_by_party
            INTO    v_address_id;
            EXIT WHEN get_addressid_by_party%NOTFOUND OR get_addressid_by_party%NOTFOUND IS NULL;
            DELETE FROM sups_amendments WHERE table_name = 'GIVEN_ADDRESSES' AND pk01 = TO_CHAR(v_address_id);
        END LOOP;
        CLOSE get_addressid_by_party;

        DELETE FROM ae_per_items WHERE ae_number = v_ae_number;
        DELETE FROM ae_events WHERE ae_number = v_ae_number;
        DELETE FROM ae_applications WHERE ae_number = v_ae_number;
        DELETE FROM given_addresses WHERE party_id = v_emp_id;
        DELETE FROM parties WHERE party_id = v_emp_id;

    END LOOP;
    CLOSE get_ae_data;

    -- Delete warrant return data
    OPEN get_warrant_data;
    LOOP
        FETCH   get_warrant_data
        INTO    v_warrant_id;
        EXIT WHEN get_warrant_data%NOTFOUND OR get_warrant_data%NOTFOUND IS NULL;

        OPEN get_warrant_returns (v_warrant_id);
        LOOP
            FETCH   get_warrant_returns
            INTO    v_warrant_ret_id;
            EXIT WHEN get_warrant_returns%NOTFOUND OR get_warrant_returns%NOTFOUND IS NULL;
            p_delete_outputs('WT', v_warrant_ret_id);
            DELETE FROM sups_amendments WHERE table_name = 'WARRANT_RETURNS' AND pk01 = v_warrant_ret_id;
        END LOOP;
        CLOSE get_warrant_returns;

        DELETE FROM warrant_returns WHERE warrant_id = v_warrant_id;
    END LOOP;
    CLOSE get_warrant_data;

    -- Delete case event and hearing data
    OPEN get_case_event_data;
    LOOP
        FETCH   get_case_event_data
        INTO    v_case_event_seq;
        EXIT WHEN get_case_event_data%NOTFOUND OR get_case_event_data%NOTFOUND IS NULL;
        p_delete_outputs('CA', v_case_event_seq);
        DELETE FROM sups_amendments WHERE table_name = 'CASE_EVENTS' AND pk01 = TO_CHAR(v_case_event_seq);
    END LOOP;
    CLOSE get_case_event_data;

    OPEN get_hearing_data;
    LOOP
        FETCH   get_hearing_data
        INTO    v_hearing_seq;
        EXIT WHEN get_hearing_data%NOTFOUND OR get_hearing_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'HEARINGS' AND pk01 = TO_CHAR(v_hearing_seq);
    END LOOP;
    CLOSE get_hearing_data;

    DELETE FROM case_event_instigators WHERE case_number = pv_case_number;
    DELETE FROM case_events WHERE case_number = pv_case_number;
    DELETE FROM hearings WHERE case_number = pv_case_number;

    -- Delete warrant data
    OPEN get_warrant_data;
    LOOP
        FETCH   get_warrant_data
        INTO    v_warrant_id;
        EXIT WHEN get_warrant_data%NOTFOUND OR get_warrant_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'WARRANTS' AND pk01 = v_warrant_id;
        DELETE FROM warrants WHERE warrant_id = v_warrant_id;
    END LOOP;
    CLOSE get_warrant_data;

    -- Delete Judgment data
    OPEN get_judg_data;
    LOOP
        FETCH   get_judg_data
        INTO    v_judg_seq;
        EXIT WHEN get_judg_data%NOTFOUND OR get_judg_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'JUDGMENTS' AND pk01 = TO_CHAR(v_judg_seq);
        DELETE FROM variations WHERE judg_seq = v_judg_seq;
        DELETE FROM infavour_parties WHERE judg_seq = v_judg_seq;
        DELETE FROM judgments WHERE judg_seq = v_judg_seq;
    END LOOP;
    CLOSE get_judg_data;

    -- Delete CPR relationship and certain addresses
    DELETE FROM sups_amendments WHERE table_name = 'CPR_TO_CPR_RELATIONSHIP' AND pk01 = pv_case_number AND pk04 = pv_case_number;
    OPEN get_addressid_by_case;
    LOOP
        FETCH   get_addressid_by_case
        INTO    v_address_id;
        EXIT WHEN get_addressid_by_case%NOTFOUND OR get_addressid_by_case%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'GIVEN_ADDRESSES' AND pk01 = TO_CHAR(v_address_id);
    END LOOP;
    CLOSE get_addressid_by_case;
    DELETE FROM cpr_to_cpr_relationship WHERE cpr_a_case_number = pv_case_number;
    DELETE FROM given_addresses WHERE address_type_code IN ('POSSESSION','WORKPLACE','SUBSERV') and case_number = pv_case_number;

    -- Delete party data (Non Coded Parties only)
    OPEN get_party_data;
    LOOP
        FETCH   get_party_data
        INTO    v_party_id,
                v_party_role,
                v_case_party_no;
        EXIT WHEN get_party_data%NOTFOUND OR get_party_data%NOTFOUND IS NULL;
        IF v_party_id IS NOT NULL THEN
            DELETE FROM sups_amendments WHERE table_name = 'PARTIES' AND pk01 = TO_CHAR(v_party_id);
        END IF;
        DELETE FROM sups_amendments WHERE table_name = 'CASE_PARTY_ROLES' AND pk01 = pv_case_number AND pk02 = TO_CHAR(v_case_party_no) AND pk03 = v_party_role;

        OPEN get_addressid_by_party (v_party_id);
        LOOP
            FETCH   get_addressid_by_party
            INTO    v_address_id;
            EXIT WHEN get_addressid_by_party%NOTFOUND OR get_addressid_by_party%NOTFOUND IS NULL;
            DELETE FROM sups_amendments WHERE table_name = 'GIVEN_ADDRESSES' AND pk01 = TO_CHAR(v_address_id);
        END LOOP;
        CLOSE get_addressid_by_party;

        OPEN get_addressid_by_cpr (v_case_party_no, v_party_role);
        LOOP
            FETCH   get_addressid_by_cpr
            INTO    v_address_id;
            EXIT WHEN get_addressid_by_cpr%NOTFOUND OR get_addressid_by_cpr%NOTFOUND IS NULL;
            DELETE FROM sups_amendments WHERE table_name = 'GIVEN_ADDRESSES' AND pk01 = TO_CHAR(v_address_id);
        END LOOP;
        CLOSE get_addressid_by_cpr;

        DELETE FROM given_addresses WHERE party_id = v_party_id;
        DELETE FROM given_addresses WHERE case_number = pv_case_number AND party_role_code = v_party_role AND case_party_no = v_case_party_no;
        DELETE FROM case_party_roles WHERE case_number = pv_case_number AND party_role_code = v_party_role AND case_party_no = v_case_party_no;
        DELETE FROM parties WHERE party_id = v_party_id;
    END LOOP;
    CLOSE get_party_data;

    -- Delete coded party case specific data
    OPEN get_party_data_cp;
    LOOP
        FETCH   get_party_data_cp
        INTO    v_party_role,
                v_case_party_no;
        EXIT WHEN get_party_data_cp%NOTFOUND OR get_party_data_cp%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'CASE_PARTY_ROLES' AND pk01 = pv_case_number AND pk02 = TO_CHAR(v_case_party_no) AND pk03 = v_party_role;
        DELETE FROM case_party_roles WHERE case_number = pv_case_number AND party_role_code = v_party_role AND case_party_no = v_case_party_no;
    END LOOP;
    CLOSE get_party_data_cp;

    -- Delete payment data
    OPEN get_payment_data;
    LOOP
        FETCH   get_payment_data
        INTO    v_trans_no,
                v_court_code;
        EXIT WHEN get_payment_data%NOTFOUND OR get_payment_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'PAYMENTS' AND pk01 = TO_CHAR(v_trans_no) AND pk02 = TO_CHAR(v_court_code);
        DELETE FROM payments WHERE enforcement_parent = pv_case_number;
    END LOOP;
    CLOSE get_payment_data;

    -- Delete any other addresses linked and the main case record
    DELETE FROM sups_amendments WHERE table_name = 'CASES' AND pk01 = pv_case_number;
    DELETE FROM given_addresses WHERE case_number = pv_case_number;
    DELETE FROM cases WHERE case_number = pv_case_number;
    UPDATE delete_candidates SET delete_complete = 'Y' WHERE identifier = pv_case_number AND type = 'CA';
    COMMIT;

EXCEPTION
    WHEN OTHERS THEN
        p_valid := 'N';
        p_reason := 'p_delete_case '||SQLERRM;
        dbms_output.put_line('p_delete_case '||SQLERRM);
        ROLLBACK;
END;


/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_delete_outputs
| DESCRIPTION   : Deletes output data associated with a case event, ae event,
|                 co event or warrant return
--------------------------------------------------------------------------------*/
PROCEDURE p_delete_outputs(p_type   IN VARCHAR2,
                           p_event_id IN NUMBER) IS

    p_doc_id    document_store.id%TYPE;
    p_rep_id    report_queue.id%TYPE;
    p_cnt_id    content_store.id%TYPE;

    CURSOR  get_case_event_outputs IS
    SELECT  rq.id, ds.id, cs.id
    FROM    report_queue rq, document_store ds, content_store cs, report_output ro
    WHERE   ro.event_seq = p_event_id
    AND     rq.id = ro.report_id
    AND     ds.id = rq.document_id
    AND     cs.id = TO_NUMBER(ds.content_store_id);

    CURSOR  get_co_event_outputs IS
    SELECT  rq.id, ds.id, cs.id
    FROM    report_queue rq, document_store ds, content_store cs, report_output ro
    WHERE   ro.co_event_seq = p_event_id
    AND     rq.id = ro.report_id
    AND     ds.id = rq.document_id
    AND     cs.id = TO_NUMBER(ds.content_store_id);

    CURSOR  get_ae_event_outputs IS
    SELECT  rq.id, ds.id, cs.id
    FROM    report_queue rq, document_store ds, content_store cs, report_output ro
    WHERE   ro.ae_event_seq = p_event_id
    AND     rq.id = ro.report_id
    AND     ds.id = rq.document_id
    AND     cs.id = TO_NUMBER(ds.content_store_id);

BEGIN
    -- Get the document_store id for the word processing outputs
    p_doc_id := NULL;
    BEGIN
        IF p_type = 'WT' THEN
            SELECT xmlsource INTO p_doc_id FROM wp_output WHERE warrant_returns_id = TO_CHAR(p_event_id);
        ELSIF p_type = 'CA' THEN
            SELECT xmlsource INTO p_doc_id FROM wp_output WHERE event_seq = p_event_id;
        ELSIF p_type = 'CO' THEN
            SELECT xmlsource INTO p_doc_id FROM wp_output WHERE co_event_seq = p_event_id;
        ELSIF p_type = 'AE' THEN
            SELECT xmlsource INTO p_doc_id FROM wp_output WHERE ae_event_seq = p_event_id;
        END IF;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN p_doc_id := NULL;
    END;

    -- Delete the word processing output data
    IF p_doc_id IS NOT NULL THEN
        DELETE FROM content_store cs WHERE cs.id = (SELECT TO_NUMBER(ds.content_store_id) FROM document_store ds WHERE ds.id = p_doc_id);
        DELETE FROM document_store WHERE id = p_doc_id;
        DELETE FROM report_map rm WHERE rm.report_queue_id IN (SELECT rq.id FROM report_queue rq WHERE rq.document_id = p_doc_id);
        DELETE FROM report_queue WHERE document_id = p_doc_id;
    END IF;

    BEGIN
        IF p_type = 'WT' THEN
            -- Warrant Return output delete
            DELETE FROM wp_output WHERE warrant_returns_id = TO_CHAR(p_event_id);
        ELSIF p_type = 'CA' THEN
            -- Case Event output deletes including oracle report outputs
            DELETE FROM wp_output WHERE event_seq = p_event_id;
            OPEN get_case_event_outputs;
            LOOP
                FETCH   get_case_event_outputs
                INTO    p_rep_id, p_doc_id, p_cnt_id;
                EXIT WHEN get_case_event_outputs%NOTFOUND OR get_case_event_outputs%NOTFOUND IS NULL;

                DELETE FROM content_store WHERE id = p_cnt_id;
                DELETE FROM document_store WHERE id = p_doc_id;
                DELETE FROM report_map WHERE report_queue_id = p_rep_id;
                DELETE FROM report_queue WHERE id = p_rep_id;
            END LOOP;
            CLOSE get_case_event_outputs;
            DELETE FROM report_output WHERE event_seq = p_event_id;
        ELSIF p_type = 'CO' THEN
            -- CO Event output deletes including oracle report outputs
            DELETE FROM wp_output WHERE co_event_seq = p_event_id;
            OPEN get_co_event_outputs;
            LOOP
                FETCH   get_co_event_outputs
                INTO    p_rep_id, p_doc_id, p_cnt_id;
                EXIT WHEN get_co_event_outputs%NOTFOUND OR get_co_event_outputs%NOTFOUND IS NULL;

                DELETE FROM content_store WHERE id = p_cnt_id;
                DELETE FROM document_store WHERE id = p_doc_id;
                DELETE FROM report_map WHERE report_queue_id = p_rep_id;
                DELETE FROM report_queue WHERE id = p_rep_id;
            END LOOP;
            CLOSE get_co_event_outputs;
            DELETE FROM report_output WHERE co_event_seq = p_event_id;

        ELSIF p_type = 'AE' THEN
            -- AE Event output deletes including oracle report outputs
            DELETE FROM wp_output WHERE ae_event_seq = p_event_id;
            OPEN get_ae_event_outputs;
            LOOP
                FETCH   get_ae_event_outputs
                INTO    p_rep_id, p_doc_id, p_cnt_id;
                EXIT WHEN get_ae_event_outputs%NOTFOUND OR get_ae_event_outputs%NOTFOUND IS NULL;

                DELETE FROM content_store WHERE id = p_cnt_id;
                DELETE FROM document_store WHERE id = p_doc_id;
                DELETE FROM report_map WHERE report_queue_id = p_rep_id;
                DELETE FROM report_queue WHERE id = p_rep_id;
            END LOOP;
            CLOSE get_ae_event_outputs;
            DELETE FROM report_output WHERE ae_event_seq = p_event_id;

        END IF;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN NULL;
    END;

END;


/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_delete_co
| DESCRIPTION   : Deletes a consolidated order record and all child records including
|                 output data and audit data held in the SUPS_AMENDMENTS table.
--------------------------------------------------------------------------------*/
PROCEDURE p_delete_co (pv_co_number IN VARCHAR2,
                       p_valid      IN OUT VARCHAR2,
                       p_reason     IN OUT VARCHAR2) IS

    CURSOR  get_allowed_debt_data IS
    SELECT  debt_seq
    FROM    allowed_debts
    WHERE   debt_co_number = pv_co_number;

    CURSOR  get_warrant_data IS
    SELECT  warrant_id
    FROM    warrants
    WHERE   co_number = pv_co_number;

    CURSOR  get_warrant_returns (cp_warrant_id VARCHAR2) IS
    SELECT  warrant_returns_id
    FROM    warrant_returns
    WHERE   warrant_id = cp_warrant_id;

    CURSOR  get_co_event_data IS
    SELECT  co_event_seq
    FROM    co_events
    WHERE   co_number = pv_co_number;

    CURSOR  get_address_by_ald (cp_ald_seq NUMBER) IS
    SELECT  address_id, party_id
    FROM    given_addresses
    WHERE   ald_seq = cp_ald_seq
    AND     address_type_code IN ('CO PAYEE','CO CRED');

    CURSOR  get_address_by_co IS
    SELECT  address_id, party_id
    FROM    given_addresses
    WHERE   co_number = pv_co_number;

    CURSOR  get_hearing_data IS
    SELECT  hrg_seq
    FROM    hearings
    WHERE   co_number = pv_co_number;

    CURSOR  get_payment_data IS
    SELECT  transaction_number, admin_court_code
    FROM    payments
    WHERE   enforcement_parent = pv_co_number;

    v_party_id      parties.party_id%TYPE;
    v_warrant_id    warrants.warrant_id%TYPE;
    v_warrant_ret_id    warrant_returns.warrant_returns_id%TYPE;
    v_co_event_seq  co_events.co_event_seq%TYPE;
    v_address_id    given_addresses.address_id%TYPE;
    v_hearing_seq   hearings.hrg_seq%TYPE;
    v_trans_no      payments.transaction_number%TYPE;
    v_court_code    courts.code%TYPE;
    v_ald_seq       allowed_debts.debt_seq%TYPE;
    v_cp_exists     VARCHAR2(1);

BEGIN

    -- Delete warrant return data
    OPEN get_warrant_data;
    LOOP
        FETCH   get_warrant_data
        INTO    v_warrant_id;
        EXIT WHEN get_warrant_data%NOTFOUND OR get_warrant_data%NOTFOUND IS NULL;

        OPEN get_warrant_returns (v_warrant_id);
        LOOP
            FETCH   get_warrant_returns
            INTO    v_warrant_ret_id;
            EXIT WHEN get_warrant_returns%NOTFOUND OR get_warrant_returns%NOTFOUND IS NULL;
            p_delete_outputs('WT', v_warrant_ret_id);
            DELETE FROM sups_amendments WHERE table_name = 'WARRANT_RETURNS' AND pk01 = v_warrant_ret_id;
        END LOOP;
        CLOSE get_warrant_returns;

        DELETE FROM warrant_returns WHERE warrant_id = v_warrant_id;
    END LOOP;
    CLOSE get_warrant_data;

    -- Delete co event and hearing data
    OPEN get_co_event_data;
    LOOP
        FETCH   get_co_event_data
        INTO    v_co_event_seq;
        EXIT WHEN get_co_event_data%NOTFOUND OR get_co_event_data%NOTFOUND IS NULL;
        p_delete_outputs('CO', v_co_event_seq);
        DELETE FROM sups_amendments WHERE table_name = 'CO_EVENTS' AND pk01 = TO_CHAR(v_co_event_seq);
        DELETE FROM co_text_items WHERE co_text_event_seq = v_co_event_seq AND co_text_co_number = pv_co_number;
    END LOOP;
    CLOSE get_co_event_data;

    OPEN get_hearing_data;
    LOOP
        FETCH   get_hearing_data
        INTO    v_hearing_seq;
        EXIT WHEN get_hearing_data%NOTFOUND OR get_hearing_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'HEARINGS' AND pk01 = TO_CHAR(v_hearing_seq);
    END LOOP;
    CLOSE get_hearing_data;

    DELETE FROM co_events WHERE co_number = pv_co_number;
    DELETE FROM hearings WHERE co_number = pv_co_number;

    -- Delete payment data
    OPEN get_payment_data;
    LOOP
        FETCH   get_payment_data
        INTO    v_trans_no,
                v_court_code;
        EXIT WHEN get_payment_data%NOTFOUND OR get_payment_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'PAYMENTS' AND pk01 = TO_CHAR(v_trans_no) AND pk02 = TO_CHAR(v_court_code);
        DELETE FROM payments WHERE enforcement_parent = pv_co_number;
    END LOOP;
    CLOSE get_payment_data;

    -- Delete Allowed Debt data
    OPEN get_allowed_debt_data;
    LOOP
        FETCH   get_allowed_debt_data
        INTO    v_ald_seq;
        EXIT WHEN get_allowed_debt_data%NOTFOUND OR get_allowed_debt_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'ALLOWED_DEBTS' AND pk01 = TO_CHAR(v_ald_seq);
        DELETE FROM co_case_events WHERE co_number = pv_co_number AND ald_debt_seq = v_ald_seq;
        DELETE FROM debt_dividends WHERE dd_co_number = pv_co_number AND dd_ald_seq = v_ald_seq;

        OPEN get_address_by_ald (v_ald_seq);
        LOOP
            FETCH   get_address_by_ald
            INTO    v_address_id, v_party_id;
            EXIT WHEN get_address_by_ald%NOTFOUND OR get_address_by_ald%NOTFOUND IS NULL;
            DELETE FROM sups_amendments WHERE table_name = 'GIVEN_ADDRESSES' AND pk01 = TO_CHAR(v_address_id);

            -- Check party linked to allowed debt is not a coded party
            SELECT  DECODE(COUNT(*), 0, 'N', 'Y') INTO v_cp_exists
            FROM    coded_parties
            WHERE   party_id = v_party_id;
            IF v_cp_exists = 'N' AND v_party_id IS NOT NULL THEN
                DELETE FROM sups_amendments WHERE table_name = 'PARTIES' AND pk01 = TO_CHAR(v_party_id);
                DELETE FROM parties WHERE party_id = v_party_id;
            END IF;
        END LOOP;
        CLOSE get_address_by_ald;
        DELETE FROM given_addresses WHERE ald_seq = v_ald_seq AND address_type_code IN ('CO PAYEE','CO CRED');
    END LOOP;
    CLOSE get_allowed_debt_data;
    DELETE FROM allowed_debts WHERE debt_co_number = pv_co_number;

    -- Delete warrant data
    OPEN get_warrant_data;
    LOOP
        FETCH   get_warrant_data
        INTO    v_warrant_id;
        EXIT WHEN get_warrant_data%NOTFOUND OR get_warrant_data%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'WARRANTS' AND pk01 = v_warrant_id;
        DELETE FROM warrants WHERE warrant_id = v_warrant_id;
    END LOOP;
    CLOSE get_warrant_data;

    -- Delete CO addresses and parties specific to the CO rather than a debt
    OPEN get_address_by_co;
    LOOP
        FETCH   get_address_by_co
        INTO    v_address_id, v_party_id;
        EXIT WHEN get_address_by_co%NOTFOUND OR get_address_by_co%NOTFOUND IS NULL;
        DELETE FROM sups_amendments WHERE table_name = 'GIVEN_ADDRESSES' AND pk01 = TO_CHAR(v_address_id);
        DELETE FROM given_addresses WHERE address_id = v_address_id;

        IF v_party_id IS NOT NULL THEN
            DELETE FROM sups_amendments WHERE table_name = 'PARTIES' AND pk01 = TO_CHAR(v_party_id);
            DELETE FROM parties WHERE party_id = v_party_id;
        END IF;
    END LOOP;
    CLOSE get_address_by_co;

    -- Delete any other records linked and the main co record
    DELETE FROM sups_amendments WHERE table_name = 'CONSOLIDATED_ORDERS' AND pk01 = pv_co_number;
    DELETE FROM given_addresses WHERE co_number = pv_co_number;
    DELETE FROM co_per_items WHERE co_number = pv_co_number;
    DELETE FROM dividends WHERE div_co_number = pv_co_number;
    DELETE FROM consolidated_orders WHERE co_number = pv_co_number;
    UPDATE delete_candidates SET delete_complete = 'Y' WHERE identifier = pv_co_number AND type = 'CO';
    COMMIT;

EXCEPTION
    WHEN OTHERS THEN
        p_valid := 'N';
        p_reason := 'p_delete_co '||SQLERRM;
        dbms_output.put_line('p_delete_co ('||pv_co_number||') '||SQLERRM);
        ROLLBACK;
END;

