/*--------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_validate_ae
| DESCRIPTION : Indicates if there is any AE on the case that would prevent case
|                       deletion.  Includes checks on the CAPS database.
| RETURN          : An exception reason if one found with the AE, else NULL
--------------------------------------------------------------------------------*/
FUNCTION f_validate_ae (p_case_number IN cases.case_number%TYPE) RETURN VARCHAR2 IS

    v_return_val        delete_candidates.exception_reason%TYPE := NULL;
    v_ae_number         ae_applications.ae_number%TYPE;
    v_ae_event_seq1     ae_events.ae_event_seq%TYPE;
    v_ae_event_seq2     ae_events.ae_event_seq%TYPE;
    v_std_event_id      ae_events.std_event_id%TYPE;
    v_caps_live_ae_cnt  NUMBER;
    v_caps_ae_cnt       NUMBER;
    v_max_evt_date      DATE;
    v_active_in_caps    BOOLEAN;

    CURSOR  get_case_aes IS
    SELECT  ae_number
    FROM    ae_applications
    WHERE   case_number = p_case_number
    AND     ae_type != 'MG';

BEGIN

    OPEN get_case_aes;
    LOOP
        -- Retrieve list of AEs on the case
        FETCH   get_case_aes
        INTO    v_ae_number;
        EXIT WHEN get_case_aes%NOTFOUND OR get_case_aes%NOTFOUND IS NULL;

        -- Check for AE Events that have not reached their retention period yet
        SELECT NVL(MAX( ADD_MONTHS(ae.date_entered, edr.retention_period) ), TRUNC(SYSDATE-1) )
        INTO v_max_evt_date
        FROM ae_events ae, event_deletion_rules edr
        WHERE ae.ae_number = v_ae_number
        AND ae.error_indicator = 'N'
        AND ae.std_event_id = edr.std_event_id
        AND edr.event_type = 'CA';

        IF TRUNC(v_max_evt_date) > TRUNC(SYSDATE) THEN
            -- An AE Event retention period has not yet expired
            v_return_val := 'AE_EVENT_RET';
            EXIT;
        END IF;

        IF v_return_val IS NULL THEN
            -- Perform CAPS checks
            SELECT  COUNT(*)
            INTO    v_caps_ae_cnt
            FROM    aes@caps_link
            WHERE   ae_number = v_ae_number
            AND     SUBSTR(case_number,1,8) = p_case_number;

            IF v_caps_ae_cnt > 0 THEN
                -- AE exists in CAPS, check if is live in CAPS
                SELECT  COUNT(*)
                INTO    v_caps_live_ae_cnt
                FROM    aes@caps_link
                WHERE   ae_number = v_ae_number
                AND     SUBSTR(case_number,1,8) = p_case_number
                AND     status IN ('LIVE','LAPSED');

                IF v_caps_live_ae_cnt > 0 THEN
                    -- Live in CAPS, not live in CaseMan
                    v_return_val := 'CAPS_INVALID_STATUS';
                    EXIT;
                ELSE
                    -- AE is not live in CaseMan and not live in CAPS, check if old enough in CAPS to delete
                    v_active_in_caps := del_obsolete_caps_pack.f_has_active_ae@caps_link(v_ae_number, p_case_number);
                    IF v_active_in_caps = TRUE THEN
                        v_return_val := 'ACTIVE_CAPS_AE';
                        EXIT;
                    END IF;
                END IF;

            END IF;

        END IF;

    END LOOP;
    CLOSE get_case_aes;

    RETURN v_return_val;
END;

/*--------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_money_in_crt
| DESCRIPTION   : Indicates if there is money yet to be paid out on a case/co
| RETURN        : An exception reason if there is money held on the case/co, else NULL
--------------------------------------------------------------------------------*/
FUNCTION f_is_money_in_crt (p_enf_number    IN cases.case_number%TYPE,
                                          p_type            IN VARCHAR2) RETURN VARCHAR2 IS

    v_return_val        delete_candidates.exception_reason%TYPE := NULL;
    v_cnt_live_payments NUMBER;

BEGIN

    -- Get a count of the valid non-passthrough payments that have not been paid out
    SELECT  COUNT(*) INTO v_cnt_live_payments
    FROM    payments
    WHERE   enforcement_parent = p_enf_number
    AND     rd_date IS NULL
    AND     NVL(error_indicator, 'N') = 'N'
    AND     passthrough = 'N'
    AND     payout_date IS NULL;

    IF v_cnt_live_payments > 0 THEN
        v_return_val := 'MONEY_IN_CRT';
    END IF;

    RETURN v_return_val;
END;

/*--------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_live_warrant
| DESCRIPTION   : Indicates if there is a live Warrant on a case/co
| RETURN        : An exception reason if there is a live Warrant on the case/co, else NULL
--------------------------------------------------------------------------------*/
FUNCTION f_is_live_warrant (p_enf_number    IN cases.case_number%TYPE,
                            p_type          IN VARCHAR2) RETURN VARCHAR2 IS

    v_return_val    delete_candidates.exception_reason%TYPE := NULL;
    v_warrant_id    warrants.warrant_id%TYPE;
    v_def1          warrants.defendant1%TYPE;
    v_def2          warrants.defendant2%TYPE;

    CURSOR  get_case_warrants IS
    SELECT  warrant_id, defendant1, defendant2
    FROM    warrants
    WHERE   case_number = p_enf_number;

    CURSOR  get_co_warrants IS
    SELECT  warrant_id, defendant1, defendant2
    FROM    warrants
    WHERE   co_number = p_enf_number;

BEGIN

    IF p_type = 'CA' THEN

        OPEN get_case_warrants;
        LOOP
            -- Retrieve list of Warrants on the case
            FETCH   get_case_warrants
            INTO    v_warrant_id, v_def1, v_def2;
            EXIT WHEN get_case_warrants%NOTFOUND OR get_case_warrants%NOTFOUND IS NULL;

            -- Determine if a final return exists against defendant 1 on the warrant
            SELECT  DECODE(COUNT(*), 0, 'LIVE_WARRANT', NULL)
            INTO    v_return_val
            FROM    warrant_returns wr, return_codes rc
            WHERE   wr.warrant_id = v_warrant_id
            AND     NVL(wr.defendant_id, 1) = 1
            AND     wr.error_indicator = 'N'
            AND     wr.return_code = rc.return_code
            AND     wr.return_code_court_code = rc.admin_court_code
            AND     rc.return_type = 'F';

            IF v_return_val IS NOT NULL THEN
                -- The previous query returned no final returns so warrant is live
                EXIT;
            END IF;

            IF v_def2 IS NOT NULL THEN
                -- Check for final returns against defendant 2
                SELECT  DECODE(COUNT(*), 0, 'LIVE_WARRANT', NULL)
                INTO    v_return_val
                FROM    warrant_returns wr, return_codes rc
                WHERE   wr.warrant_id = v_warrant_id
                AND     NVL(wr.defendant_id, 1) = 2
                AND     wr.error_indicator = 'N'
                AND     wr.return_code = rc.return_code
                AND     wr.return_code_court_code = rc.admin_court_code
                AND     rc.return_type = 'F';

                IF v_return_val IS NOT NULL THEN
                    -- The previous query returned no final returns so warrant is live
                    EXIT;
                END IF;
            END IF;
        END LOOP;
        CLOSE get_case_warrants;

    ELSIF p_type = 'CO' THEN

        OPEN get_co_warrants;
        LOOP
            -- Retrieve list of Warrants on the CO
            FETCH   get_co_warrants
            INTO    v_warrant_id, v_def1, v_def2;
            EXIT WHEN get_co_warrants%NOTFOUND OR get_co_warrants%NOTFOUND IS NULL;

            -- Determine if a final return exists against defendant 1 on the warrant
            SELECT  DECODE(COUNT(*), 0, 'LIVE_WARRANT', NULL)
            INTO    v_return_val
            FROM    warrant_returns wr, return_codes rc
            WHERE   wr.warrant_id = v_warrant_id
            AND     NVL(wr.defendant_id, 1) = 1
            AND     wr.error_indicator = 'N'
            AND     wr.return_code = rc.return_code
            AND     wr.return_code_court_code = rc.admin_court_code
            AND     rc.return_type = 'F';

            IF v_return_val IS NOT NULL THEN
                -- The previous query returned no final returns so warrant is live
                EXIT;
            END IF;

            IF v_def2 IS NOT NULL THEN
                -- Check for final returns against defendant 2
                SELECT  DECODE(COUNT(*), 0, 'LIVE_WARRANT', NULL)
                INTO    v_return_val
                FROM    warrant_returns wr, return_codes rc
                WHERE   wr.warrant_id = v_warrant_id
                AND     NVL(wr.defendant_id, 1) = 2
                AND     wr.error_indicator = 'N'
                AND     wr.return_code = rc.return_code
                AND     wr.return_code_court_code = rc.admin_court_code
                AND     rc.return_type = 'F';

                IF v_return_val IS NOT NULL THEN
                    -- The previous query returned no final returns so warrant is live
                    EXIT;
                END IF;
            END IF;
        END LOOP;
        CLOSE get_co_warrants;

    END IF;

    RETURN v_return_val;
END;

/*--------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_live_judg
| DESCRIPTION   : Indicates if there is a live Judgment on a case
| RETURN        : An exception reason if there is a live Judgment on the case, else NULL
--------------------------------------------------------------------------------*/
FUNCTION f_is_live_judg (p_case_number IN cases.case_number%TYPE) RETURN VARCHAR2 IS

    v_return_val        delete_candidates.exception_reason%TYPE := NULL;
    v_cnt_live_jgmts    NUMBER;
    v_judg_ret_period   NUMBER;

BEGIN
    -- Retrieve the retention period of a Judgment record
    SELECT  period
    INTO    v_judg_ret_period
    FROM    default_retention_period
    WHERE   retention_type = 'JUDGMENT';

    -- Get a count of the judgments on the case where the status is NULL or VARIED
    -- and the judgment is not old enough to delete
    SELECT  COUNT(*) INTO v_cnt_live_jgmts
    FROM    judgments
    WHERE   case_number = p_case_number
    AND     (status IS NULL OR status = 'VARIED')
    AND     ADD_MONTHS(judgment_date, v_judg_ret_period) > SYSDATE;

    IF v_cnt_live_jgmts > 0 THEN
        v_return_val := 'ACTIVE_JUDG';
    END IF;

    RETURN v_return_val;
END;

/*--------------------------------------------------------------------------------
| TYPE          : FUNCTION
| NAME          : f_is_invalid_status
| DESCRIPTION   : Indicates if the case status is the correct value based upon
|                 the case events on the case
| RETURN        : An exception reason if invalid, else NULL
--------------------------------------------------------------------------------*/
FUNCTION f_is_invalid_status (p_case_number IN cases.case_number%TYPE) RETURN VARCHAR2 IS

    v_return_val    delete_candidates.exception_reason%TYPE := NULL;
    v_event_seq     case_events.event_seq%TYPE;
    v_case_status   cases.status%TYPE;
    v_evt_status1   event_deletion_rules.status_1%TYPE;
    v_count         NUMBER;

BEGIN

    -- Get a list of the case events on the case that can change the case status
    SELECT  NVL(MAX(event_seq),-1) INTO v_event_seq
    FROM    case_events
    WHERE   case_number = p_case_number
    AND     deleted_flag = 'N'
    AND     std_event_id IN (
        SELECT  edr.std_event_id
        FROM    event_deletion_rules edr
        WHERE   edr.event_type = 'CS');

    IF v_event_seq != -1 THEN

        -- Retrieve the case status
        SELECT status INTO v_case_status
        FROM cases
        WHERE case_number = p_case_number;

        -- Retrieve the expected case status from the configuration table
        SELECT edr.status_1
        INTO v_evt_status1
        FROM case_events ce, event_deletion_rules edr
        WHERE ce.event_seq = v_event_seq
        AND edr.std_event_id = ce.std_event_id;

        -- If the case status is NULL, we're not intrested unless the expected status is NULL e.g. 756
        -- which resets the status to NULL.
        IF v_case_status IS NOT NULL OR (v_case_status IS NULL AND v_evt_status1 = 'X') THEN

            -- Determine if the current case status is valid for the latest status
            -- changing event.  v_evt_status1 is a comma separated list of valid
            -- case statuses and the REGEXP_SUBSTR call below splits them out using
            -- the comma and checks if NVL(v_case_status,'X') matches any of them.
            SELECT COUNT(*) INTO v_count FROM DUAL
            WHERE NVL(v_case_status,'X') IN
            (SELECT REGEXP_SUBSTR(v_evt_status1,'[^,]+',1,LEVEL) FROM DUAL
            CONNECT BY REGEXP_SUBSTR(v_evt_status1,'[^,]',1,LEVEL) IS NOT NULL);

            -- No matches found, return unexpected status
            IF v_count = 0 THEN
                v_return_val := 'UNEXPECT_STATUS';
            END IF;

        END IF;

    END IF;

    RETURN v_return_val;
END;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_process_recalc_dates
| DESCRIPTION   : Using the last run date for the batch job to recalculate the
|                 deletion date of cases/cos, every date since up to SYSDATE
|                 is processed to recalculate the deletion dates.
--------------------------------------------------------------------------------*/
PROCEDURE p_process_recalc_dates IS

  v_last_run_date DATE;
  v_new_date      DATE;

BEGIN

    SELECT  TO_DATE(TO_CHAR(sd.item_value),'YYYYMMDD')
    INTO    v_last_run_date
    FROM    system_data sd
    WHERE   sd.item = 'DEL_DATE_RUNDATE'
    AND     sd.admin_court_code = 0;

    v_new_date := v_last_run_date;

    LOOP
        -- Iterate through every date between the last run date and today (does not run for today)
        v_new_date := v_new_date + 1;
        EXIT WHEN TRUNC(v_new_date) = TRUNC(SYSDATE);   -- Exit when date = SYSDATE
        -- Run the recalculation job for the new run date
        p_recalculate_deletion_dates( TRUNC(v_new_date) );
    END LOOP;

EXCEPTION
    WHEN OTHERS THEN
        dbms_output.put_line('p_process_recalc_dates '||SQLERRM);
        ROLLBACK;
        RAISE;
END;

/*--------------------------------------------------------------------------------
| TYPE          : PROCEDURE
| NAME          : p_recalculate_deletion_dates
| DESCRIPTION   : For a given date, the procedure will query the SUPS_AMENDMENTS
|                 table for new cases/cos or event changes so that the deletion
|                 date can be recalculated.
--------------------------------------------------------------------------------*/
PROCEDURE p_recalculate_deletion_dates(p_date IN DATE) IS

    CURSOR get_new_cases IS
    SELECT pk01
    FROM sups_amendments
    WHERE date_of_change = TRUNC(p_date)
    AND table_name = 'CASES'
    AND amendment_type = 'Inserted';

    CURSOR get_changed_case_events IS
    SELECT DISTINCT ce.case_number
    FROM sups_amendments sa, case_events ce
    WHERE sa.date_of_change = TRUNC(p_date)
    AND sa.table_name = 'CASE_EVENTS'
    AND ( (sa.amendment_type = 'Inserted')
    OR ( sa.amendment_type = 'Updated'
           AND sa.column_name = 'DELETED_FLAG' ) )
    AND ce.event_seq = TO_NUMBER(sa.pk01)
    AND ce.std_event_id != 1;

    CURSOR get_new_cos IS
    SELECT pk01
    FROM sups_amendments
    WHERE date_of_change = TRUNC(p_date)
    AND table_name = 'CONSOLIDATED_ORDERS'
    AND amendment_type = 'Inserted';

    CURSOR get_changed_co_events IS
    SELECT DISTINCT ce.co_number
    FROM sups_amendments sa, co_events ce
    WHERE sa.date_of_change = TRUNC(p_date)
    AND sa.table_name = 'CO_EVENTS'
    AND ( (sa.amendment_type = 'Inserted')
    OR ( sa.amendment_type = 'Updated'
           AND sa.column_name = 'ERROR_INDICATOR' ) )
    AND ce.co_event_seq = TO_NUMBER(sa.pk01);

    v_case_number       cases.case_number%TYPE;
    v_co_number         consolidated_orders.co_number%TYPE;
    v_count_cos         NUMBER := 0;
    v_count_cases       NUMBER := 0;
    l_creation_ret      NUMBER;
    l_insig_evt_ret     NUMBER;

BEGIN

    -- Get the constant retention periods
    SELECT period
    INTO l_creation_ret
    FROM default_retention_period
    WHERE retention_type = 'CASE_CREATE';

    SELECT period
    INTO l_insig_evt_ret
    FROM default_retention_period
    WHERE retention_type = 'INSIG_EVENT';

    OPEN get_new_cos;
    LOOP
        -- Retrieve list of new consolidated orders created on that date
        FETCH   get_new_cos
        INTO    v_co_number;
        EXIT WHEN get_new_cos%NOTFOUND OR get_new_cos%NOTFOUND IS NULL;

        v_count_cos := v_count_cos + 1;

        -- Invoke deletion date calculation for v_co_number
        p_perform_calc_del_date(v_co_number, 'CO', l_creation_ret, l_insig_evt_ret);
    END LOOP;
    COMMIT;
    CLOSE get_new_cos;

    OPEN get_changed_co_events;
    LOOP
        -- Retrieve list of new co events created or existing co events errored/unerrored on that date
        FETCH   get_changed_co_events
        INTO    v_co_number;
        EXIT WHEN get_changed_co_events%NOTFOUND OR get_changed_co_events%NOTFOUND IS NULL;

        v_count_cos := v_count_cos + 1;

        -- Invoke deletion date calculation for v_co_number
        p_perform_calc_del_date(v_co_number, 'CO', l_creation_ret, l_insig_evt_ret);
    END LOOP;
    COMMIT;
    CLOSE get_changed_co_events;

    OPEN get_new_cases;
    LOOP
        -- Retrieve list of new consolidated orders created on that date
        FETCH   get_new_cases
        INTO    v_case_number;
        EXIT WHEN get_new_cases%NOTFOUND OR get_new_cases%NOTFOUND IS NULL;

        v_count_cases := v_count_cases + 1;

        -- Invoke deletion date calculation for v_case_number
        p_perform_calc_del_date(v_case_number, 'CA', l_creation_ret, l_insig_evt_ret);
    END LOOP;
    COMMIT;
    CLOSE get_new_cases;

    OPEN get_changed_case_events;
    LOOP
        -- Retrieve list of new case events created or existing case events errored/unerrored on that date
        FETCH   get_changed_case_events
        INTO    v_case_number;
        EXIT WHEN get_changed_case_events%NOTFOUND OR get_changed_case_events%NOTFOUND IS NULL;

        v_count_cases := v_count_cases + 1;

        -- Invoke deletion date calculation for v_case_number
        p_perform_calc_del_date(v_case_number, 'CA', l_creation_ret, l_insig_evt_ret);
    END LOOP;
    COMMIT;
    CLOSE get_changed_case_events;

    UPDATE  system_data
    SET     item_value = TO_NUMBER( TO_CHAR(p_date, 'YYYYMMDD') )
    WHERE   item = 'DEL_DATE_RUNDATE'
    AND     admin_court_code = 0;
    COMMIT;

    -- Statistics for the logs
    dbms_output.put_line('Recalculation of Deletion Dates for: ' || TO_CHAR(TRUNC(p_date), 'DD-Mon-YYYY') );
    dbms_output.put_line('==================================================');
    dbms_output.put_line('Cases Updated: ' || v_count_cases);
    dbms_output.put_line('COs Updated: ' || v_count_cos);

END;
END del_obsolete_cases_pack;
/



