  CREATE OR REPLACE PACKAGE "CASEMAN"."DOCUMENT_LOAD_PKG" IS

PROCEDURE   load_document_for_event (
                                    p_case_number   IN  VARCHAR2,
                                    p_pdf_filename  IN  VARCHAR2,
                                    p_event_seq     IN  NUMBER,
                                    p_order_id      IN  VARCHAR2,
                                    p_debug         IN  VARCHAR2,
                                    p_file_loaded   OUT VARCHAR2
                                    );

PROCEDURE   reload_documents        (p_debug        IN  VARCHAR2);

END; -- end of document_load_pkg
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."DOCUMENT_LOAD_PKG" IS

/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : load_document_for_event                                                                   *
* DESCRIPTION   : Procedure to load an MCOL PDDF document into the Caseman Database document store          *
\***********************************************************************************************************/

PROCEDURE load_document_for_event(  p_case_number   IN  VARCHAR2,
                                    p_pdf_filename  IN  VARCHAR2,
                                    p_event_seq     IN  NUMBER,
                                    p_order_id      IN  VARCHAR2,
                                    p_debug         IN  VARCHAR2,
                                    p_file_loaded   OUT VARCHAR2 ) IS

n_content_store_id  NUMBER;
n_document_store_id NUMBER;
n_report_id         NUMBER;
v_file_loc          BFILE;
v_file_con          BLOB;
v_file_size         INTEGER;
err_msg             VARCHAR2(255);
v_source_directory  VARCHAR2(255);
n_user_id           VARCHAR2(10 CHAR);
n_court_id          VARCHAR2(3 CHAR);


-- constants
v_mime_type           VARCHAR2(15) := 'application/pdf';

    BEGIN
        p_file_loaded := 'Y';

        DBMS_OUTPUT.PUT_LINE('Start of load_document_for_event seq '||p_event_seq||' on case '||p_case_number);

        -- get the directory path for the SOURCE_DIR
        SELECT  a.directory_path
        INTO    v_source_directory
        FROM    all_directories a
        WHERE   a.directory_name = 'SOURCE_DIR';

        -- get the user id and court id
        n_user_id   := sys_context('sups_app_ctx','app_user_id');
        n_court_id  := sys_context('sups_app_ctx','app_court_id');


        -- get the report id immediately as its needed to record errors

        SELECT  report_queue_sequence.NEXTVAL
        INTO    n_report_id
        FROM    dual;

        -- initialize the bfile locator
        v_file_loc := BFILENAME( 'SOURCE_DIR', p_pdf_filename );

        IF DBMS_LOB.FILEEXISTS( v_file_loc ) = 0 THEN
            -- file load failed
            p_file_loaded := 'N';
            DBMS_OUTPUT.PUT_LINE
            (p_pdf_filename||' does not exist in directory '||v_source_directory||' on case '||p_case_number);
            -- record the failure to upload the document
            INSERT INTO report_queue
                        (
                        id,
                        parent_id,
                        status ,
                        mime_type,
                        type ,
                        parameters,
                        user_id ,
                        court_id,
                        created_date,
                        storage_duration,
                        is_parent,
                        error_message,
                        send_status,
                        print_status
                        )
            VALUES
                        (
                        n_report_id,
                        n_report_id,
                        4,
                        v_mime_type,
                        -1,
                        '<params />',
                        n_user_id,
                        n_court_id,
                        SYSDATE,
                        -1,
                        0,
                        'Failed to find file '||p_pdf_filename||' to upload',
                        0,
                        0
                        );
        ELSE
            -- document exists, so check it contains some data
            v_file_size := DBMS_LOB.GETLENGTH(v_file_loc);

            IF  v_file_size != 0    THEN

                -- file has content so we need to upload to the database

                -- get the sequence numbers which are required.
                BEGIN
                    SELECT  content_sequence.NEXTVAL
                    INTO    n_content_store_id
                    FROM    dual;

                    SELECT document_sequence.NEXTVAL
                    INTO n_document_store_id
                    FROM dual;

                    IF p_debug = 'Y' THEN
                        DBMS_OUTPUT.PUT_LINE('Content id = '||n_content_store_id|| 'doc id = '||n_document_store_id);
                    END IF;
                    -- create a record with an empty blob into which the file will be loaded
                    INSERT INTO CONTENT_STORE (ID, DATA)
                    VALUES ( n_content_store_id, EMPTY_BLOB() )
                    RETURNING DATA INTO v_file_con;

                    IF p_debug = 'Y' THEN
                        DBMS_OUTPUT.PUT_LINE('content store  '||SQL%ROWCOUNT);
                    END IF; -- debug

                    -- open the file and upload the file into the record which was just created
                    DBMS_LOB.FILEOPEN(v_file_loc);
                    DBMS_LOB.LOADFROMFILE(v_file_con, v_file_loc, v_file_size);

                    -- populate Document_store
                    INSERT INTO document_store (id, user_id , court_id, mime_type, is_viewed, is_persistent, content_store_id, created_date)
                    VALUES     ( n_document_store_id  ,n_user_id , n_court_id , v_mime_type ,'F', 'T', n_content_store_id, SYSDATE );

                    IF p_debug = 'Y' THEN
                        DBMS_OUTPUT.PUT_LINE('Documents  '||SQL%ROWCOUNT);
                    END IF; -- debug

                    -- populate report_queue
                    INSERT INTO report_queue (id, parent_id, status , mime_type, type , parameters, user_id , court_id, created_date, storage_duration, is_parent, document_id, send_status, print_status)
                    VALUES      (n_report_id, n_report_id, 2, v_mime_type , 0 , '<params />', n_user_id , n_court_id , SYSDATE,  -1, 0, n_document_store_id, 0, 0);

                    IF p_debug = 'Y' THEN
                        DBMS_OUTPUT.PUT_LINE('Report queue good  '||SQL%ROWCOUNT);
                    END IF; -- debug

                    -- populate report_output
                    INSERT INTO REPORT_OUTPUT (output_id, date_created, printed, event_seq, report_id, order_id, user_id )
                    VALUES ( report_output_seq.NEXTVAL, SYSDATE, 'Y', p_event_seq, n_report_id, p_order_id, n_user_id );

                    IF p_debug = 'Y' THEN
                        DBMS_OUTPUT.PUT_LINE('Report output  '||SQL%ROWCOUNT);
                    END IF; -- debug

                    -- close the lob if its still open
                    IF  DBMS_LOB.FILEISOPEN(v_file_loc) = 1 THEN
                        DBMS_LOB.FILECLOSE(v_file_loc);
                    END IF;

                    EXCEPTION
                    WHEN OTHERS THEN
                        -- fail load failed
                        p_file_loaded := 'N';
                        err_msg:= sqlerrm;
                        dbms_output.put_line (err_msg);
                        INSERT INTO report_queue (id, parent_id, status , mime_type, type , parameters, user_id , court_id, created_date, storage_duration, is_parent, error_message, send_status, print_status)
                        VALUES
                            (n_report_id, n_report_id, 4, v_mime_type ,  -1 , '<params />', n_user_id , n_court_id , SYSDATE,  -1, 0, 'Failed to upload file: ' || err_msg , 0, 0 );
                                            -- close the lob if its still open
                    IF  DBMS_LOB.FILEISOPEN(v_file_loc) = 1  THEN
                        DBMS_LOB.FILECLOSE(v_file_loc);
                    END IF;

                END;
            ELSE
                -- record the fact the file is empty
                -- fail load failed
                p_file_loaded := 'N';
                DBMS_OUTPUT.PUT_LINE
                (p_pdf_filename||' contains 0 bytes of data in directory '||v_source_directory||' on case '||p_case_number);
                INSERT INTO report_queue
                            (
                            id,
                            parent_id,
                            status ,
                            mime_type,
                            type ,
                            parameters,
                            user_id ,
                            court_id,
                            created_date,
                            storage_duration,
                            is_parent,
                            error_message,
                            send_status,
                            print_status
                            )
                VALUES
                            (
                            n_report_id,
                            n_report_id,
                            4,
                            v_mime_type,
                            -1,
                            '<params />',
                            n_user_id,
                            n_court_id ,
                            SYSDATE,
                            -1,
                            0,
                            'File '||p_pdf_filename||'contained 0 bytes',
                            0,
                            0
                            );
            END IF;  -- end of check for empty

        END IF; -- end of check for file exists
    END; -- end of load_document_for_event procedure
/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : reload_documents                                                                          *
* DESCRIPTION   : This procedure will scan the MCOL_PDF_STATUS table looking for documents which have not   *
*               : loaded. If it finds any it will attempt to load them using the control data in the        *
*               : MCOL_PDF_STATUS table                                                                     *
*               :                                                                                           *
*               : This situation may occur when the orginal document load failed due to the specified file  *
*               : being empty or missing. It is hoped that this issue will have been subsequently           *
*               : remedied by MCOL supplying the correct document file                                      *
\***********************************************************************************************************/
PROCEDURE reload_documents ( p_debug IN  VARCHAR2) IS

-- cursor to find unloaded pdf files.
CURSOR  cur_unloaded_files IS
SELECT  mps.pdf_file_name,
        mps.loaded,
        mps.event_seq,
        mps.case_number,
        mps.order_id
FROM    mcol_pdf_status mps
WHERE   mps.loaded = 'N'
AND     mps.event_seq IS NOT NULL -- this eliminates documents which
                                  -- have not been loaded due to the mcol event
                                  -- being rejected
FOR UPDATE OF mps.loaded;

l_loaded    VARCHAR2(1) := 'N';
l_event_seq NUMBER(9);

BEGIN

    -- Process all unloaded files.
    FOR unloaded_rec IN cur_unloaded_files
    LOOP
        -- first check to see if a file have already been loaded for the event
        BEGIN
            SELECT  ro.event_seq
            INTO    l_event_seq
            FROM    report_output ro
            WHERE   ro.event_seq = unloaded_rec.event_seq;

            -- PDF document has already been loaded and associated with this event
            -- set loaded flag to true , so we don't attempt a reload and the load status will be
            -- updated

            l_loaded := 'Y';

            EXCEPTION WHEN NO_DATA_FOUND THEN
                -- no file loaded for the event, so set flag to attempt to load it
                l_loaded := 'N';
        END;

        IF l_loaded = 'N' THEN
            -- no MCOL PDF document has been associated with the specified event, so load the document
            load_document_for_event (
                                    unloaded_rec.case_number,
                                    unloaded_rec.pdf_file_name,
                                    unloaded_rec.event_seq,
                                    unloaded_rec.order_id,
                                    p_debug,
                                    l_loaded
                                    );
        END IF;

        IF l_loaded = 'N' THEN
            DBMS_OUTPUT.PUT_LINE('PDF reload of '||unloaded_rec.pdf_file_name||'for case '||unloaded_rec.case_number||' failed !');
        END IF;

        -- update the loading status

        UPDATE mcol_pdf_status mps
        SET mps.loaded = l_loaded
        WHERE CURRENT OF cur_unloaded_files;

    END LOOP; -- end of loop processing unloaded files.
    COMMIT;
END;


END; -- end of document_load_pkg body
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."LR_USERS_PACK" AS
    PROCEDURE create_users;

    PROCEDURE delete_users;

    PROCEDURE create_file (
        p_usecase                 IN       lr_data.usecase%TYPE);

    PROCEDURE insert_dca_user (
        p_user                    IN       dca_user.user_id%TYPE);

    PROCEDURE insert_user_court (
        p_user                    IN       user_court.user_id%TYPE
       ,p_court                   IN       user_court.court_code%TYPE);

    PROCEDURE insert_user_role (
        p_user                    IN       user_role.user_id%TYPE
       ,p_court                   IN       user_role.court_code%TYPE);

    PROCEDURE insert_section (
        p_court                   IN       sections.admin_court_code%TYPE);

    FUNCTION get_warr_id (
        p_case                    IN       lr_data.case_no%TYPE)
        RETURN VARCHAR2;

    FUNCTION get_date
        RETURN DATE;

    PROCEDURE get_cases (
        p_usecase                 IN       lr_data.usecase%TYPE
       ,p_code                    IN       lr_data.code%TYPE
       ,p_user                    IN       lr_data.user_id%TYPE
       ,p_dets                    IN       cases.brief_details_of_claim%TYPE);

    PROCEDURE set_party_id (
        p_usecase                 IN       lr_data.usecase%TYPE
       ,p_code                    IN       lr_data.code%TYPE
       ,p_user                    IN       lr_data.user_id%TYPE);

    PROCEDURE insert_lr_data (
        p_usecase                 IN       lr_data.usecase%TYPE
       ,p_code                    IN       lr_data.code%TYPE
       ,p_user                    IN       lr_data.user_id%TYPE
       ,p_case                    IN       lr_data.case_no%TYPE
       ,p_data                    IN       lr_data.DATA%TYPE);

    PROCEDURE loginusers;

    PROCEDURE createcaseusers;

    PROCEDURE maincaseusers;

    PROCEDURE manevent7users;

    PROCEDURE manevent10users;

    PROCEDURE manevent230users;

    PROCEDURE querybypartyusers;

    PROCEDURE mainobligusers;

    PROCEDURE runordprintusers;

    PROCEDURE reprintrepusers;

    PROCEDURE mainwftusers;

    PROCEDURE createhomwarusers;

    PROCEDURE mainquerywarusers;

    PROCEDURE warreturnusers;

    PROCEDURE aestartofdayusers;

    PROCEDURE manaoeusers;

    PROCEDURE captaoeusers;

    PROCEDURE costartofdayusers;

    PROCEDURE createaousers;

    PROCEDURE updaousers;

    PROCEDURE mancoeventusers;

    PROCEDURE bmssectusers;

    PROCEDURE bmscourtusers;

    PROCEDURE viewaudhistusers;
END lr_users_pack; /
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."LR_USERS_PACK" AS
--File name
    lr_file                       UTL_FILE.file_type;
--Global variables
    l_name                        lr_users.NAME%TYPE;
    l_usecase                     lr_data.usecase%TYPE := NULL;
    l_file_name                   VARCHAR2 (30);
    l_users_dir                   VARCHAR2 (30)
                                               := 'home/oracle/lr_user_files';
--Parameters:
--Table CASES
    l_5events                     cases.brief_details_of_claim%TYPE
                                                 := 'LR Data - 5 Case Events';
    l_9events                     cases.brief_details_of_claim%TYPE
                                                 := 'LR Data - 9 Case Events';
    l_12events                    cases.brief_details_of_claim%TYPE
                                                := 'LR Data - 12 Case Events';
    l_15events                    cases.brief_details_of_claim%TYPE
                                                := 'LR Data - 15 Case Events';
    l_aeevents                    cases.brief_details_of_claim%TYPE
                                                := 'LR Data - 17 Events + AE';
--Run time
    l_iter                        INTEGER := 1000;
    l_query_recs                  INTEGER := 50;
    rndval_lo                     INTEGER := 7;
    rndval_lh                     INTEGER := 28;
    rndval_yrs                    INTEGER := 3;
    epoch                         DATE := '31-DEC-2008';
    l_du_title                    dcu_user.title%TYPE := NULL;
    l_du_surname                  dcu_user.surname%TYPE := 'Generate';
    l_du_job_title                dcu_user.job_title%TYPE := 'LR Test User';
    l_du_extension                dcu_user.extension%TYPE := NULL;
    l_du_asl                      dcu_user.access_sucurity_level%TYPE := NULL;
    l_du_udp                      dcu_user.user_defaul_printer%TYPE
                                                       := '<default printer>';
    l_du_usp                      dcu_user.user_style_proile%TYPE := nul;
    l_du_sfp                      dcu_user.section_for_printouts%TYPE
                                                   := '<Performance Testing>';
    l_uc_date_from                user_court.from_data%TYPE := '01-JAN-95';
    l_uc_date_to                  user_court.from_to%TYPE := NULL;
    l_uc_sect_name                user_court.section_name := '<section name>';
    l_ur_role_id                  user_role.role_id%TYPE := 'wcSuper';
--Constant, Set Party
    c_party                       VARCHAR2 (20) := 'CLAIMANT';
    c_party_no                    VARCHAR2 (1) := '1';

-----------------------------------------------------------
    PROCEDURE create_users IS
    BEGIN
        delete_users;
        loginusers;
        createcaseusers;
        maincaseusers;
        manevent7users;
        manevent10users;
        manevent230users;
        querybypartyusers;
        mainobligusers;
        runordprintusers;
        reprintrepusers;
        mainwftusers;
        createhomwarusers;
        mainquerywarusers;
        warreturnusers;
        aestartofdayusers;
        manaoeusers;
        captaoeusers;
        costartofdayusers;
        createaousers;
        updaousers;
        mancoeventusers;
        bmssectusers;
        bmscourtusers;
        viewaudhistusers;
    END create_users;

-----------------------------------------------------------
    PROCEDURE create_file (
        p_usecase                 IN       lr_data.usecase%TYPE) IS
    BEGIN
        l_file_name :=    p_usecase
                       || 'users.txt';

        BEGIN
            UTL_FILE.fremove (lr_users_dir, l_file_name);
        EXCEPTION
            WHEN UTL_FILE.invalid_operation THEN
                NULL;
        END;

        lr_file := UTL_FILE.fopen (lr_users_dir
                                  ,l_file_name
                                  ,'a');
        DBMS_OUTPUT.put_line (   'Creating user file '
                              || lr_users_dir
                              || l_file_name);
    END create_file;

-----------------------------------------------------------
    PROCEDURE delete_users IS
    BEGIN
        DBMS_OUTPUT.put_line ('Deleting LR Data Generation Users!');

        DELETE FROM lr_data;

        DELETE FROM user_court
              WHERE user_id IN (SELECT user_id
                                FROM   dca_user
                                WHERE  surname = l_du_surname);

        DELETE FROM user_role
              WHERE user_id IN (SELECT user_id
                                FROM   dca_user
                                WHERE  surname = l_du_surname);

        DELETE FROM dca_user
              WHERE surname = l_du_surname;
    END delete_users;

-----------------------------------------------------------
    PROCEDURE insert_dca_user (
        p_user                    IN       dca_user.user_id%TYPE) IS
    BEGIN
        DBMS_OUTPUT.put_line (   'Inserting DCA User '
                              || p_user);

        INSERT INTO dca_user
                    (user_id
                    ,title
                    ,forenames
                    ,surname
                    ,user_short_name
                    ,job_title
                    ,extension
                    ,access_security_level
                    ,user_default_printer
                    ,user_style_profile
                    ,active_user_flag
                    ,section_for_printouts)
             VALUES (p_user
                    ,l_du_title
                    ,    'Data '
                      || SUBSTR (p_user
                                ,5
                                ,4)
                    ,l_du_surname
                    ,SUBSTR (p_user
                            ,3
                            ,6)
                    ,l_du_job_title
                    ,l_du_extension
                    ,l_du_asl
                    ,l_du_udp
                    ,l_du_usp
                    ,'Y'
                    ,l_du_sfp);
    END insert_dca_user;

-----------------------------------------------------------
    PROCEDURE insert_user_court (
        p_user                    IN       user_court.user_id%TYPE
       ,p_court                   IN       user_court.court_code%TYPE) IS
    BEGIN
        insert_section (p_court, l_uc_sect_name);

        INSERT INTO user_court
                    (user_id
                    ,date_from
                    ,date_to
                    ,home_flag
                    ,court_code
                    ,section_name)
             VALUES (p_user
                    ,l_uc_date_from
                    ,l_uc_date_to
                    ,'Y'
                    ,p_court
                    ,l_uc_sect_name);
    END insert_user_court;

-----------------------------------------------------------
    PROCEDURE insert_user_role (
        p_user                    IN       user_role.user_id%TYPE
       ,p_court                   IN       user_role.court_code%TYPE) IS
    BEGIN
        INSERT INTO user_role
                    (user_id
                    ,role_id
                    ,court_code)
             VALUES (p_user
                    ,l_ur_role_id
                    ,p_court);
    END insert_user_role;

-----------------------------------------------------------
    PROCEDURE insert_section (
        p_court                   IN       sections.admin_court_code%TYPE
       ,p_section_name            IN       sections.section_name%TYPE) IS
        l_x                           VARCHAR2 (1) := NULL;

        CURSOR one IS
            SELECT section_name
            FROM   sections
            WHERE  section_name = p_section_name
            AND    admin_court_code = p_court;
    BEGIN
        OPEN one;

        FETCH one
        INTO  l_x;

        IF one%NOTFOUND THEN
            DBMS_OUTPUT.put_line (   'Inserting section '
                                  || 'p_section_name'
                                  || p_court);

            INSERT INTO sections
                        (section_name
                        ,admin_court_code)
                 VALUES (p_section_name
                        ,p_court);
        END IF;

        CLOSE one;
    END insert_section;

-----------------------------------------------------------
    PROCEDURE get_cases (
        p_usecase                 IN       lr_data.usecase%TYPE
       ,p_code                    IN       lr_data.code%TYPE
       ,p_user                    IN       lr_data.user_id%TYPE
       ,p_dets                    IN       cases.brief_details_of_claim%TYPE) IS
        l_case                        lr_data.case_no%TYPE;
        l_data                        lr_data.DATA%TYPE;

        CURSOR c_co1 IS
            SELECT case_number
                  ,co_number
            FROM   (SELECT   cce.case_number
                            ,co.co_number
                    FROM     consolidated_orders co
                            ,co_events ce
                            ,allowed_debts ad
                            ,co_case_events cce
                    WHERE    co.co_type = 'AO'
                    AND      co.admin_court_code = ce.creating_court
                    AND      co.co_number = ce.co_number
                    AND      co.co_number = cce.co_number
                    AND      co.co_number = ad.debt_co_number
                    AND      co.admin_court_code = p_code
                    AND      ce.std_event_id = cce.std_event_id
                    AND      ce.std_event_id = '965'
                    AND      co.co_number NOT IN (
                                      SELECT DATA
                                      FROM   lr_data
                                      WHERE  code = p_code
                                      AND    DATA IS NOT NULL)
                    ORDER BY DBMS_RANDOM.VALUE)
            WHERE  ROWNUM = 1;

        CURSOR c_co2 IS
            SELECT case_number
                  ,co_number
            FROM   (SELECT   cce.case_number
                            ,co.co_number
                    FROM     consolidated_orders co
                            ,co_events ce
                            ,allowed_debts ad
                            ,co_case_events cce
                    WHERE    co.co_type = 'AO'
                    AND      co.admin_court_code = ce.creating_court
                    AND      co.co_number = ce.co_number
                    AND      co.co_number = cce.co_number
                    AND      co.co_number = ad.debt_co_number
                    AND      co.admin_court_code = p_code
                    AND      ce.std_event_id = cce.std_event_id
                    AND      ce.std_event_id = '961'
                    AND      co.co_number NOT IN (
                                 SELECT DISTINCT co_number
                                 FROM            co_events
                                                ,allowed_debts
                                 WHERE           co_number = debt_co_number
                                 AND             creating_court = p_code
                                 AND             std_event_id = '965')
                    AND      co.co_number NOT IN (
                                      SELECT DATA
                                      FROM   lr_data
                                      WHERE  code = p_code
                                      AND    DATA IS NOT NULL)
                    ORDER BY DBMS_RANDOM.VALUE)
            WHERE  ROWNUM = 1;

        CURSOR c_case IS
            SELECT case_number
            FROM   (SELECT   case_number
                    FROM     cases
                    WHERE    admin_crt_code = p_code
                    AND      UPPER (brief_details_of_claim) = UPPER (p_dets)
                    AND      case_number NOT IN (
                                   SELECT case_no
                                   FROM   lr_data
                                   WHERE  code = p_code
                                   AND    case_no IS NOT NULL)
                    ORDER BY DBMS_RANDOM.VALUE)
            WHERE  ROWNUM = 1;
    BEGIN
        FOR k IN 1 .. l_iter LOOP
            CASE
                WHEN p_usecase = 'updao' THEN
                    OPEN c_co1;

                    FETCH c_co1
                    INTO  l_case
                         ,l_data;

                    IF c_co1%NOTFOUND THEN
                        l_case := NULL;
                        l_data := NULL;
                        DBMS_OUTPUT.put_line
                            (   l_usecase
                             || ' - Not enough consolidated orders for court '
                             || p_code);
                    END IF;

                    CLOSE c_co1;
                WHEN p_usecase = 'mancoevent' THEN
                    OPEN c_co2;

                    FETCH c_co2
                    INTO  l_case
                         ,l_data;

                    IF c_co2%NOTFOUND THEN
                        l_case := NULL;
                        l_data := NULL;
                        DBMS_OUTPUT.put_line
                            (   l_usecase
                             || ' - Not enough consolidated orders for court '
                             || p_code);
                    END IF;

                    CLOSE c_co2;
                ELSE
                    OPEN c_case;

                    FETCH c_case
                    INTO  l_case;

                    IF c_case%NOTFOUND THEN
                        l_case := NULL;
                        l_data := NULL;
                        DBMS_OUTPUT.put_line
                                         (   l_usecase
                                          || ' - Not enough cases for court '
                                          || p_code);
                    ELSE
                        IF (   p_usecase = 'warreturn'
                            OR p_usecase = 'mainquerywar') THEN
                            l_data := get_warr_id (l_case);
                        ELSE
                            l_data := NULL;
                        END IF;
                    END IF;

                    CLOSE c_case;
            END CASE;

            insert_lr_data (p_usecase
                           ,p_code
                           ,p_user
                           ,l_case
                           ,l_data);
        END LOOP;
    END get_cases;

-----------------------------------------------------------
    FUNCTION get_warr_id (
        p_case                    IN       lr_data.case_no%TYPE)
        RETURN VARCHAR2 IS
        l_data                        lr_data.DATA%TYPE;
    BEGIN
        SELECT warrant_number
        INTO   l_data
        FROM   warrants
        WHERE  case_number = p_case;

        RETURN l_data;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            DBMS_OUTPUT.put_line (   'No Warrant found for '
                                  || p_case);
    END get_warr_id;

-----------------------------------------------------------
    FUNCTION get_date
        RETURN DATE IS
        l_date                        DATE;
        l_rand                        INTEGER;
    BEGIN
        l_rand := DBMS_RANDOM.VALUE (rndval_lh, (  365
                                                 * rndval_yrs));
        l_date :=   TO_DATE (epoch, 'DD-MON-YYYY')
                  - l_rand;
        RETURN l_date;
    END get_date;

-----------------------------------------------------------
    PROCEDURE set_party_id (
        p_usecase                 IN       lr_data.usecase%TYPE
       ,p_code                    IN       lr_data.code%TYPE
       ,p_user                    IN       lr_data.user_id%TYPE) IS
        l_cur_no                      INTEGER := 0;
        l_name                        lr_data.DATA%TYPE;
        l_case                        cases.case_number%TYPE;

        CURSOR c1 IS
            SELECT case_number
            FROM   (SELECT   case_number
                    FROM     cases
                    WHERE    admin_crt_code = p_code
                    AND      case_number NOT IN (
                                   SELECT case_no
                                   FROM   lr_data
                                   WHERE  code = p_code
                                   AND    case_no IS NOT NULL)
                    ORDER BY DBMS_RANDOM.VALUE)
            WHERE  ROWNUM = 1;
    BEGIN
        --Get a random name to use
        SELECT NAME
        INTO   l_name
        FROM   (SELECT   NAME
                FROM     lr_parties
                ORDER BY DBMS_RANDOM.VALUE)
        WHERE  ROWNUM = 1;

        DBMS_OUTPUT.put_line (   'Name - '
                              || l_name);

        FOR i IN 1 .. l_query_recs LOOP
            l_cur_no :=   l_cur_no
                        + 1;

            --Get a random case for the court
            OPEN c1;

            FETCH c1
            INTO  l_case;

            IF c1%NOTFOUND THEN
                DBMS_OUTPUT.put_line
                              (   l_usecase
                               || ' - '
                               || l_cur_no
                               || ' Cases found. Not enough cases for court '
                               || p_code);

                CLOSE c1;

                EXIT;
            ELSE
                DBMS_OUTPUT.put_line (   'Update parties for case - '
                                      || l_case);

                UPDATE parties
                   SET person_requested_name = l_name
                 WHERE party_id =
                           (SELECT party_id
                            FROM   case_party_roles
                            WHERE  case_number = l_case
                            AND    party_role_code = c_party
                            AND    case_party_no = c_party_no);

                insert_lr_data (p_usecase
                               ,p_code
                               ,p_user
                               ,l_case
                               ,l_name);

                CLOSE c1;
            END IF;
        END LOOP;
    END set_party_id;

-----------------------------------------------------------
    PROCEDURE insert_lr_data (
        p_usecase                 IN       lr_data.usecase%TYPE
       ,p_code                    IN       lr_data.code%TYPE
       ,p_user                    IN       lr_data.user_id%TYPE
       ,p_case                    IN       lr_data.case_no%TYPE
       ,p_data                    IN       lr_data.DATA%TYPE) IS
    BEGIN
        INSERT INTO lr_data
                    (usecase
                    ,code
                    ,user_id
                    ,case_no
                    ,DATA)
             VALUES (p_usecase
                    ,p_code
                    ,p_user
                    ,p_case
                    ,p_data);
    END insert_lr_data;

-----------------------------------------------------------
    PROCEDURE loginusers IS
        l_user                        dca_user.user_id%TYPE;
    BEGIN
        l_usecase := 'login';
        l_file_name := 'loginusers.txt';
        create_file (l_usecase);

        FOR i IN (SELECT lr.loginusers
                        ,c.NAME
                        ,c.ID
                        ,c.code
                  FROM   lr_users lr
                        ,courts c
                  WHERE  lr.loginusers > 0
                  AND    lr.ID = c.ID) LOOP
            FOR j IN 1 .. i.loginusers LOOP
                SELECT LOWER (   i.ID
                              || 'LG'
                              || LPAD (lr_user_sequence.NEXTVAL
                                      ,4
                                      ,0))
                INTO   l_user
                FROM   DUAL;

                insert_dca_user (l_user);
                insert_user_role (l_user, i.code);
                insert_user_court (l_user, i.code);
                insert_lr_data (l_usecase
                               ,i.code
                               ,l_user
                               ,NULL
                               ,i.NAME);
                UTL_FILE.put_line (lr_file
                                  ,    i.code
                                    || ','
                                    || i.ID
                                    || ','
                                    || i.NAME
                                    || ','
                                    || l_user);
            END LOOP;
        END LOOP;

        UTL_FILE.fclose (f);
    END loginusers;

-----------------------------------------------------------
    PROCEDURE createcaseusers IS
        l_case_start                  INTEGER (5) := 0;
        l_user                        dca_user.user_id%TYPE;
    BEGIN
        l_usecase := 'createcase';
        l_file_name := 'createcaseusers.txt';

        BEGIN
            UTL_FILE.fremove (lr_users_dir, l_file_name);
        EXCEPTION
            WHEN UTL_FILE.invalid_operation THEN
                NULL;
        END;

        lr_file := UTL_FILE.fopen (lr_users_dir
                                  ,l_file_name
                                  ,'a');
        DBMS_OUTPUT.put_line (   'Creating user file '
                              || lr_users_dir
                              || l_file_name);

        FOR i IN (SELECT lr.createcaseusers
                        ,c.NAME
                        ,c.ID
                        ,c.code
                  FROM   lr_users lr
                        ,courts c
                  WHERE  lr.createcaseusers > 0
                  AND    lr.ID = c.ID) LOOP
            FOR j IN 1 .. i.createcaseusers LOOP
                SELECT LOWER (   i.ID
                              || 'DG'
                              || LPAD (lr_user_sequence.NEXTVAL
                                      ,4
                                      ,0))
                INTO   l_user
                FROM   DUAL;

                insert_dca_user (l_user);
                insert_user_role (l_user, i.code);
                insert_user_court (l_user, i.code);

                IF j = 1 THEN
                    SELECT   MAX (SUBSTR (case_number
                                         ,4
                                         ,5))
                           + 1
                    INTO   l_case_start
                    FROM   cases
                    WHERE  admin_crt_code = i.code;
                ELSE
                    l_case_start :=   l_case_start
                                    + l_iter;
                END IF;

                insert_lr_data (l_usecase
                               ,i.code
                               ,l_user
                               ,NVL (l_case_start, 00001)
                               ,NULL);
                UTL_FILE.put_line (lr_file
                                  ,    i.code
                                    || ','
                                    || i.ID
                                    || ','
                                    || i.NAME
                                    || ','
                                    || l_user
                                    || ','
                                    || l_case_start);
            END LOOP;
        END LOOP;

        UTL_FILE.fclose (f);
    END createcaseusers;

