    PROCEDURE bmssectusers IS
        l_code                        lr_data.code%TYPE;
        l_user                        dca_user.user_id%TYPE;
        l_fr_date                     DATE;
        l_to_date                     DATE;
    BEGIN
        l_usecase := 'bmssect';
        l_file_name := 'bmssectusers.txt';

        FOR i IN (SELECT lr.bmssectusers
                        ,c.NAME
                        ,c.ID
                        ,c.code
                  FROM   lr_users lr
                        ,courts c
                  WHERE  lr.bmssectusers > 0
                  AND    lr.ID = c.ID) LOOP
            FOR j IN 1 .. i.bmssectusers LOOP
                SELECT LOWER (   i.ID
                              || 'DG'
                              || LPAD (lr_user_sequence.NEXTVAL
                                      ,4
                                      ,0))
                INTO   l_user
                FROM   DUAL;

                insert_dca_user (l_user);
                insert_user_role (l_user, i.code);
                insert_user_court (l_user, i.code);
            END LOOP;
        END LOOP;

        --Now create the real data
        --(The above has just created 1 user that will NOT be used!)
        FOR i IN (SELECT DISTINCT court_code
                  FROM            user_court) LOOP
            BEGIN
                SELECT uc.user_id
                      ,uc.court_code
                INTO   l_user
                      ,l_code
                FROM   user_court uc
                      ,user_role ur
                WHERE  uc.user_id = ur.user_id
                AND    uc.court_code = i.court_code
                AND    uc.user_id NOT IN (SELECT DISTINCT user_id
                                          FROM            lr_data)
                AND    ur.role_id = l_ur_role_id
                AND    ROWNUM = 1;

                --Generate dates to use
                l_fr_date := get_date;
                l_to_date :=
                            l_fr_date
                          + DBMS_RANDOM.VALUE (rndval_lo, rndval_lh);
                insert_lr_data (l_usecase
                               ,l_code
                               ,l_user
                               ,NULL
                               ,    TO_CHAR (l_fr_date, 'DD-MON-YYYY')
                                 || ','
                                 || TO_CHAR (l_to_date, 'DD-MON-YYYY'));
            EXCEPTION
                WHEN NO_DATA_FOUND THEN
                    DBMS_OUTPUT.put_line (   l_usecase
                                          || ' - Not enough users for court '
                                          || l_code);
            END;
        END LOOP;
    END bmssectusers;

--------------------------------------------------------
