    OR     EVE.DELETED_FLAG             IS NULL)
    AND    EVE.DATE_TO_RTL              IS NULL
    AND    EVE.REGISTER_JUDGMENT        = 'Y'
    AND    EVE.STD_EVENT_ID             = 233
    AND    JUDG.JUDG_SEQ                = EVE.JUDG_SEQ;

    f_handle UTL_FILE.FILE_TYPE;
    pv_file_line VARCHAR(500);

BEGIN

    f_handle := UTL_FILE.FOPEN(pv_dir, pv_filename, 'A');

    FOR rec IN c_reg_case_evt233 LOOP

        -- Generate the line for the RTL file
        pv_file_line := get_file_line (rec.admin_crt_code
                                      ,rec.case_number
                                      ,rec.judg_total
                                      ,rec.judg_date
                                      ,rec.status
                                      ,rec.canc_date
                                      ,rec.person_requested_name
                                      ,rec.address_line1
                                      ,rec.address_line2
                                      ,rec.address_line3
                                      ,rec.address_line4
                                      ,rec.address_line5
                                      ,rec.postcode
                                      ,rec.person_dob);

        -- Output the line in the file
        UTL_FILE.PUT_LINE(f_handle, pv_file_line);

        -- Update the Judgment address id at registration
        UPDATE judgments SET AGAINST_PARTY_ADDR_ID_JUDG_REG = rec.address_id WHERE judg_seq = rec.judg_seq;
        COMMIT;

        pn_count := pn_count + 1;

    END LOOP;

    UTL_FILE.FCLOSE(f_handle);

EXCEPTION
    WHEN OTHERS THEN
        IF f_handle.id IS NOT NULL THEN
            UTL_FILE.FCLOSE(f_handle);
        END IF;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_process_amnd_case_evts
| DESCRIPTION  : Retrieve Amendment Case Events for RTL and write to the details file
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_process_amnd_case_evts (pn_count IN OUT NUMBER
                                    ,pv_filename IN VARCHAR2
                                    ,pv_dir IN VARCHAR2) IS

    CURSOR c_amnd_case_evts IS
    SELECT
        CAS.admin_crt_code
        ,cas.case_number
        ,eve.std_event_id
        ,LTRIM(TO_CHAR(NVL(JUDG.JUDGMENT_AMOUNT,0) + NVL(JUDG.TOTAL_COSTS,0) - NVL(JUDG.PAID_BEFORE_JUDGMENT,0),'00000000.00')) "JUDG_TOTAL"
        ,JUDG.TOTAL_CURRENCY
        ,TO_CHAR (JUDG.JUDGMENT_DATE,'DDMMYYYY') "JUDG_DATE"
        ,'M' AS "STATUS"
        ,NULL AS "CANC_DATE"
        ,PAR.PERSON_REQUESTED_NAME
        ,ADDR.ADDRESS_LINE1
        ,ADDR.ADDRESS_LINE2
        ,ADDR.ADDRESS_LINE3
        ,ADDR.ADDRESS_LINE4
        ,ADDR.ADDRESS_LINE5
        ,ADDR.POSTCODE
        ,TO_CHAR(PAR.PERSON_DOB,'DDMMYYYY') "PERSON_DOB"
    FROM    CASES             CAS
            ,CASE_PARTY_ROLES  CPR
            ,PARTIES           PAR
            ,GIVEN_ADDRESSES   ADDR
            ,TMP_RTL_JUDGMENTS         JUDG
            ,CASE_EVENTS       EVE
    WHERE  CAS.CASE_NUMBER              = CPR.CASE_NUMBER
    AND    CPR.PARTY_ROLE_CODE          = 'CLAIMANT'
    AND    PAR.PARTY_ID                 = CPR.PARTY_ID
    AND    ADDR.CASE_NUMBER             = CPR.CASE_NUMBER
    AND    ADDR.ADDRESS_TYPE_CODE    = 'SERVICE'
    AND    ADDR.PARTY_ROLE_CODE         = CPR.PARTY_ROLE_CODE
    AND    ADDR.CASE_PARTY_NO           = CPR.CASE_PARTY_NO
    AND    JUDG.CASE_NUMBER             = CPR.CASE_NUMBER
    AND    JUDG.AGAINST_PARTY_ROLE_CODE = CPR.PARTY_ROLE_CODE
    AND    JUDG.AGAINST_CASE_PARTY_NO   = CPR.CASE_PARTY_NO
    AND    JUDG.JUDGMENT_DATE           > ADD_MONTHS(SYSDATE,-72)
    AND    ADDR.ADDRESS_ID     = JUDG.AGAINST_PARTY_ADDR_ID_JUDG_REG
    AND   (EVE.DELETED_FLAG             = 'N' OR     EVE.DELETED_FLAG             IS NULL)
    AND    EVE.DATE_TO_RTL              IS NULL
    AND    (EVE.STD_EVENT_ID = 236 OR (EVE.STD_EVENT_ID= 253    AND EVE.REGISTER_JUDGMENT = 'Y'))
    AND    JUDG.JUDG_SEQ               = EVE.JUDG_SEQ
    UNION (
    SELECT
        CAS.admin_crt_code
        ,cas.case_number
        ,eve.std_event_id
        ,LTRIM(TO_CHAR(NVL(JUDG.JUDGMENT_AMOUNT,0) + NVL(JUDG.TOTAL_COSTS,0) - NVL(JUDG.PAID_BEFORE_JUDGMENT,0),'00000000.00')) "JUDG_TOTAL"
        ,JUDG.TOTAL_CURRENCY
        ,TO_CHAR (JUDG.JUDGMENT_DATE,'DDMMYYYY')"JUDG_DATE"
        ,'M' AS "STATUS"
        ,NULL AS "CANC_DATE"
        ,PAR.PERSON_REQUESTED_NAME,ADDR.ADDRESS_LINE1
        ,ADDR.ADDRESS_LINE2
        ,ADDR.ADDRESS_LINE3
        ,ADDR.ADDRESS_LINE4
        ,ADDR.ADDRESS_LINE5
        ,ADDR.POSTCODE
        ,TO_CHAR(PAR.PERSON_DOB,'DDMMYYYY') "PERSON_DOB"
    FROM    CASES             CAS
            ,CASE_PARTY_ROLES  CPR
            ,PARTIES           PAR
            ,GIVEN_ADDRESSES   ADDR
            ,TMP_RTL_JUDGMENTS         JUDG
            ,CASE_EVENTS       EVE
            ,CODED_PARTIES CPAR
    WHERE  CAS.CASE_NUMBER              = CPR.CASE_NUMBER
    AND    CPR.PARTY_ROLE_CODE          = 'CLAIMANT'
    AND    PAR.PARTY_ID                 = CPR.PARTY_ID
    AND    ADDR.CASE_NUMBER     IS NULL
    AND    ADDR.ADDRESS_TYPE_CODE    = 'CODED PARTY'
    AND    ADDR.PARTY_ID            = CPAR.PARTY_ID
    AND    CPR.PARTY_ID    = CPAR.PARTY_ID
    AND    JUDG.CASE_NUMBER             = CPR.CASE_NUMBER
    AND    JUDG.AGAINST_PARTY_ROLE_CODE = CPR.PARTY_ROLE_CODE
    AND    JUDG.AGAINST_CASE_PARTY_NO   = CPR.CASE_PARTY_NO
    AND    JUDG.JUDGMENT_DATE           > ADD_MONTHS(SYSDATE,-72)
    AND    ADDR.ADDRESS_ID     = JUDG.AGAINST_PARTY_ADDR_ID_JUDG_REG
    AND   (EVE.DELETED_FLAG             = 'N' OR     EVE.DELETED_FLAG             IS NULL)
    AND    EVE.DATE_TO_RTL              IS NULL
    AND    (EVE.STD_EVENT_ID             = 236 OR (EVE.STD_EVENT_ID= 253    AND EVE.REGISTER_JUDGMENT = 'Y'))
    AND    JUDG.JUDG_SEQ               = EVE.JUDG_SEQ)
    UNION (
    SELECT
        CAS.admin_crt_code
        ,cas.case_number
        ,eve.std_event_id
        ,LTRIM(TO_CHAR(NVL(JUDG.JUDGMENT_AMOUNT,0) + NVL(JUDG.TOTAL_COSTS,0) - NVL(JUDG.PAID_BEFORE_JUDGMENT,0),'00000000.00')) "JUDG_TOTAL"
        ,JUDG.TOTAL_CURRENCY
        ,TO_CHAR (JUDG.JUDGMENT_DATE,'DDMMYYYY') "JUDG_DATE"
        ,'M' AS "STATUS"
        ,NULL AS "CANC_DATE"
        ,PAR.PERSON_REQUESTED_NAME
        ,ADDR.ADDRESS_LINE1
        ,ADDR.ADDRESS_LINE2
        ,ADDR.ADDRESS_LINE3
        ,ADDR.ADDRESS_LINE4
        ,ADDR.ADDRESS_LINE5
        ,ADDR.POSTCODE
        ,TO_CHAR(PAR.PERSON_DOB,'DDMMYYYY') "PERSON_DOB"
    FROM    CASES             CAS
            ,CASE_PARTY_ROLES  CPR
            ,PARTIES           PAR
            ,GIVEN_ADDRESSES   ADDR
            ,TMP_RTL_JUDGMENTS         JUDG
            ,CASE_EVENTS       EVE
    WHERE  CAS.CASE_NUMBER              = CPR.CASE_NUMBER
    AND    CPR.PARTY_ROLE_CODE          = 'DEFENDANT'
    AND    PAR.PARTY_ID                 = CPR.PARTY_ID
    AND    ADDR.CASE_NUMBER             = CPR.CASE_NUMBER
    AND    ADDR.ADDRESS_TYPE_CODE    = 'SERVICE'
    AND    ADDR.PARTY_ROLE_CODE         = CPR.PARTY_ROLE_CODE
    AND    ADDR.CASE_PARTY_NO           = CPR.CASE_PARTY_NO
    AND    JUDG.CASE_NUMBER             = CPR.CASE_NUMBER
    AND    JUDG.AGAINST_PARTY_ROLE_CODE = CPR.PARTY_ROLE_CODE
    AND    JUDG.AGAINST_CASE_PARTY_NO   = CPR.CASE_PARTY_NO
    AND    JUDG.JUDGMENT_DATE           > ADD_MONTHS(SYSDATE,-72)
    AND    ADDR.ADDRESS_ID     = JUDG.AGAINST_PARTY_ADDR_ID_JUDG_REG
    AND   (EVE.DELETED_FLAG             = 'N' OR     EVE.DELETED_FLAG IS NULL)
    AND    EVE.DATE_TO_RTL              IS NULL
    AND    (EVE.STD_EVENT_ID             = 236 OR (EVE.STD_EVENT_ID= 253 AND EVE.REGISTER_JUDGMENT = 'Y'))
    AND    JUDG.JUDG_SEQ = EVE.JUDG_SEQ);

    f_handle UTL_FILE.FILE_TYPE;
    pv_file_line VARCHAR(500);

BEGIN

    f_handle := UTL_FILE.FOPEN(pv_dir, pv_filename, 'A');

    FOR rec IN c_amnd_case_evts LOOP

        -- Generate the line for the RTL file
        pv_file_line := get_file_line (rec.admin_crt_code
                                      ,rec.case_number
                                      ,rec.judg_total
                                      ,rec.judg_date
                                      ,rec.status
                                      ,rec.canc_date
                                      ,rec.person_requested_name
                                      ,rec.address_line1
                                      ,rec.address_line2
                                      ,rec.address_line3
                                      ,rec.address_line4
                                      ,rec.address_line5
                                      ,rec.postcode
                                      ,rec.person_dob);

        -- Output the line in the file
        UTL_FILE.PUT_LINE(f_handle, pv_file_line);

        pn_count := pn_count + 1;

    END LOOP;

    UTL_FILE.FCLOSE(f_handle);

EXCEPTION
    WHEN OTHERS THEN
        IF f_handle.id IS NOT NULL THEN
            UTL_FILE.FCLOSE(f_handle);
        END IF;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_process_dereg_co_evts
| DESCRIPTION  : Retrieve Deregistration CO Events 927 and 928 for RTL and write to the details file
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_process_dereg_co_evts (pn_count IN OUT NUMBER
                                    ,pv_filename IN VARCHAR2
                                    ,pv_dir IN VARCHAR2) IS

    CURSOR c_dereg_co_evts IS
    SELECT
        CO.admin_court_code
        ,CO.CO_NUMBER
        ,COE.STD_EVENT_ID
        ,NULL AS "TOTAL"
        ,TO_CHAR(COE.EVENT_DATE,'DDMMYYYY') "ORDER_DATE"
        ,DECODE(COE.STD_EVENT_ID,'927','V','928','K',NULL) "STATUS"
        ,TO_CHAR(COE.EVENT_DATE,'DDMMYYYY') "CANC_DATE"
        ,CO.DEBTOR_NAME
        ,ADDR.ADDRESS_LINE1
        ,ADDR.ADDRESS_LINE2
        ,ADDR.ADDRESS_LINE3
        ,ADDR.ADDRESS_LINE4
        ,ADDR.ADDRESS_LINE5
        ,ADDR.POSTCODE
        ,TO_CHAR(PAR.PERSON_DOB,'DDMMYYYY') "PERSON_DOB"
    FROM    CONSOLIDATED_ORDERS  CO
            ,GIVEN_ADDRESSES   ADDR
            ,PARTIES PAR
            ,CO_EVENTS COE
    WHERE  ADDR.CO_NUMBER = CO.CO_NUMBER
    AND   ADDR.ADDRESS_ID = CO.AGAINST_PARTY_ADDR_ID_CO_REG
    AND   ADDR.ADDRESS_TYPE_CODE = 'CO DEBTOR'
    AND   COE.CO_NUMBER = CO.CO_NUMBER
    AND   COE.STD_EVENT_ID IN (927,928)
    AND   CO.ORDER_DATE > ADD_MONTHS(SYSDATE,-72)
    AND   PAR.PARTY_ID = ADDR.PARTY_ID
    AND   COE.DATE_TO_RTL IS NULL
    AND   COE.ERROR_INDICATOR = 'N';

    f_handle        UTL_FILE.FILE_TYPE;
    pv_file_line    VARCHAR(500);
    pn_co_balance   NUMBER;

BEGIN

    f_handle := UTL_FILE.FOPEN(pv_dir, pv_filename, 'A');

    FOR rec IN c_dereg_co_evts LOOP

        -- Retrieve the CO balance
        pn_co_balance := f_calc_co_balance(rec.co_number);

        -- Generate the line for the RTL file
        pv_file_line := get_file_line (rec.admin_court_code
                                      ,rec.co_number
                                      ,LTRIM(TO_CHAR(pn_co_balance,'00000000.00'))
                                      ,rec.order_date
                                      ,rec.status
                                      ,rec.canc_date
                                      ,rec.debtor_name
                                      ,rec.address_line1
                                      ,rec.address_line2
                                      ,rec.address_line3
                                      ,rec.address_line4
                                      ,rec.address_line5
                                      ,rec.postcode
                                      ,rec.person_dob);

        -- Output the line in the file
        UTL_FILE.PUT_LINE(f_handle, pv_file_line);

        pn_count := pn_count + 1;

    END LOOP;

    UTL_FILE.FCLOSE(f_handle);

EXCEPTION
    WHEN OTHERS THEN
        IF f_handle.id IS NOT NULL THEN
            UTL_FILE.FCLOSE(f_handle);
        END IF;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_process_dereg_co_evt935
| DESCRIPTION  : Retrieve Deregistration CO Event 935 for RTL and write to the details file
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_process_dereg_co_evt935 (pn_count IN OUT NUMBER
                                    ,pv_filename IN VARCHAR2
                                    ,pv_dir IN VARCHAR2) IS

    CURSOR c_dereg_co_evt935 IS
    SELECT
        CO.admin_court_code
        ,CO.CO_NUMBER
        ,T2.CO_TEXT_VALUE AS "TOTAL"
        ,TO_CHAR(TO_DATE(T3.CO_TEXT_VALUE,'DD-Mon-YYYY'),'DDMMYYYY') "ORDER_DATE"
        ,DECODE(T1.CO_TEXT_VALUE, 'CNL' ,'C','SAT','S','SET','C', NULL) "STATUS"
        ,TO_CHAR(TO_DATE(T4.CO_TEXT_VALUE,'DD-Mon-YYYY'),'DDMMYYYY') "CANC_DATE"
        ,CO.DEBTOR_NAME
        ,ADDR.ADDRESS_LINE1
        ,ADDR.ADDRESS_LINE2
        ,ADDR.ADDRESS_LINE3
        ,ADDR.ADDRESS_LINE4
        ,ADDR.ADDRESS_LINE5
        ,ADDR.POSTCODE
        ,TO_CHAR(PAR.PERSON_DOB,'DDMMYYYY') "PERSON_DOB"
    FROM    CONSOLIDATED_ORDERS       CO
            ,GIVEN_ADDRESSES   ADDR
            ,CO_EVENTS COE
            ,PARTIES PAR
            ,CO_TEXT_ITEMS T2
            ,CO_TEXT_ITEMS T1
            ,CO_TEXT_ITEMS T3
            ,CO_TEXT_ITEMS T4
    WHERE  ADDR.CO_NUMBER = CO.CO_NUMBER
    AND   ADDR.ADDRESS_TYPE_CODE = 'CO DEBTOR'
    AND   COE.DATE_TO_RTL IS NULL
    AND   ADDR.ADDRESS_ID = CO.AGAINST_PARTY_ADDR_ID_CO_REG
    AND   COE.CO_NUMBER = CO.CO_NUMBER
    AND   COE.ERROR_INDICATOR = 'N'
    AND   COE.STD_EVENT_ID = 935
    AND   CO.ORDER_DATE >ADD_MONTHS(SYSDATE,-72)
    AND   PAR.PARTY_ID = ADDR.PARTY_ID
    AND   T2.CO_TEXT_DETAIL_CODE = '12535'
    AND   T2.CO_TEXT_EVENT_SEQ IN ( SELECT MAX(CE.CO_EVENT_SEQ) FROM CO_EVENTS CE WHERE CE.STD_EVENT_ID = '935' AND CE.CO_NUMBER = CO.CO_NUMBER)
    AND   T1.CO_TEXT_DETAIL_CODE = '12515'
    AND   T1.CO_TEXT_EVENT_SEQ IN ( SELECT MAX(CE.CO_EVENT_SEQ) FROM CO_EVENTS CE WHERE CE.STD_EVENT_ID = '935' AND CE.CO_NUMBER = CO.CO_NUMBER)
    AND   T3.CO_TEXT_DETAIL_CODE = '12530'
    AND   T3.CO_TEXT_EVENT_SEQ IN ( SELECT MAX(CE.CO_EVENT_SEQ) FROM CO_EVENTS CE WHERE CE.STD_EVENT_ID = '935' AND CE.CO_NUMBER = CO.CO_NUMBER)
    AND   T4.CO_TEXT_DETAIL_CODE = '12520'
    AND   T4.CO_TEXT_EVENT_SEQ IN ( SELECT MAX(CE.CO_EVENT_SEQ) FROM CO_EVENTS CE WHERE CE.STD_EVENT_ID = '935' AND CE.CO_NUMBER = CO.CO_NUMBER);

    f_handle UTL_FILE.FILE_TYPE;
    pv_file_line VARCHAR(500);

BEGIN

    f_handle := UTL_FILE.FOPEN(pv_dir, pv_filename, 'A');

    FOR rec IN c_dereg_co_evt935 LOOP

        -- Generate the line for the RTL file
        pv_file_line := get_file_line (rec.admin_court_code
                                      ,rec.co_number
                                      ,LTRIM(TO_CHAR(rec.total,'00000000.00'))
                                      ,rec.order_date
                                      ,rec.status
                                      ,rec.canc_date
                                      ,rec.debtor_name
                                      ,rec.address_line1
                                      ,rec.address_line2
                                      ,rec.address_line3
                                      ,rec.address_line4
                                      ,rec.address_line5
                                      ,rec.postcode
                                      ,rec.person_dob);

        -- Output the line in the file
        UTL_FILE.PUT_LINE(f_handle, pv_file_line);

        pn_count := pn_count + 1;

    END LOOP;

    UTL_FILE.FCLOSE(f_handle);

EXCEPTION
    WHEN OTHERS THEN
        IF f_handle.id IS NOT NULL THEN
            UTL_FILE.FCLOSE(f_handle);
        END IF;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_process_reg_co_evts
| DESCRIPTION  : Retrieve Registration CO Event 920 for RTL and write to the details file
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_process_reg_co_evts (pn_count IN OUT NUMBER
                                    ,pv_filename IN VARCHAR2
                                    ,pv_dir IN VARCHAR2) IS

    CURSOR c_reg_co_evts IS
    SELECT
        CO.admin_court_code
        ,CO.CO_NUMBER
        ,COE.STD_EVENT_ID
        ,NULL AS "Total"
        ,TO_CHAR(COE.EVENT_DATE,'DDMMYYYY') "ORDER_DATE"
        ,'A' AS "STATUS"
        ,NULL AS "CANC_DATE"
        ,CO.DEBTOR_NAME
        ,ADDR.ADDRESS_ID
        ,ADDR.ADDRESS_LINE1
        ,ADDR.ADDRESS_LINE2
        ,ADDR.ADDRESS_LINE3
        ,ADDR.ADDRESS_LINE4
        ,ADDR.ADDRESS_LINE5
        ,ADDR.POSTCODE
        ,TO_CHAR(PAR.PERSON_DOB,'DDMMYYYY') "PERSON_DOB"
    FROM    CONSOLIDATED_ORDERS  CO
            ,GIVEN_ADDRESSES   ADDR
            ,PARTIES PAR
            ,CO_EVENTS COE
    WHERE  ADDR.CO_NUMBER = CO.CO_NUMBER
    AND   ADDR.ADDRESS_TYPE_CODE = 'CO DEBTOR'
    AND   ADDR.VALID_TO IS NULL
    AND   COE.CO_NUMBER = CO.CO_NUMBER
    AND   COE.STD_EVENT_ID = 920
    AND   CO.ORDER_DATE > ADD_MONTHS(SYSDATE,-72)
    AND   PAR.PARTY_ID = ADDR.PARTY_ID
    AND   COE.DATE_TO_RTL IS NULL
    AND   COE.ERROR_INDICATOR = 'N';

    f_handle        UTL_FILE.FILE_TYPE;
    pv_file_line    VARCHAR(500);
    pn_co_balance   NUMBER;

BEGIN

    f_handle := UTL_FILE.FOPEN(pv_dir, pv_filename, 'A');

    FOR rec IN c_reg_co_evts LOOP

        -- Retrieve the CO balance
        pn_co_balance := f_calc_co_balance(rec.co_number);

        -- Generate the line for the RTL file
        pv_file_line := get_file_line (rec.admin_court_code
                                      ,rec.co_number
                                      ,LTRIM(TO_CHAR(pn_co_balance,'00000000.00'))
                                      ,rec.order_date
                                      ,rec.status
                                      ,rec.canc_date
                                      ,rec.debtor_name
                                      ,rec.address_line1
                                      ,rec.address_line2
                                      ,rec.address_line3
                                      ,rec.address_line4
                                      ,rec.address_line5
                                      ,rec.postcode
                                      ,rec.person_dob);

        -- Output the line in the file
        UTL_FILE.PUT_LINE(f_handle, pv_file_line);

        -- Update the Consolidated Order address id at registration
        UPDATE consolidated_orders SET AGAINST_PARTY_ADDR_ID_CO_REG = rec.address_id WHERE co_number = rec.co_number;
        COMMIT;

        pn_count := pn_count + 1;

    END LOOP;

    UTL_FILE.FCLOSE(f_handle);

EXCEPTION
    WHEN OTHERS THEN
        IF f_handle.id IS NOT NULL THEN
            UTL_FILE.FCLOSE(f_handle);
        END IF;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_post_extract_updates
| DESCRIPTION  : Performs the post extract updates on the case events, co events, judgments and
|                consolidated orders.
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_post_extract_updates IS

BEGIN

    -- Update newly registered judgments
    UPDATE  JUDGMENTS JUDG
    SET     JUDG.SENT_TO_RTL = TRUNC(SYSDATE),
            JUDG.STATUS_TO_RTL = 'Y'
    WHERE   JUDG.JUDG_SEQ IN (
            SELECT  EVE.JUDG_SEQ
            FROM    CASE_EVENTS EVE
            WHERE   EVE.DELETED_FLAG = 'N'
            AND     EVE.DATE_TO_RTL IS NULL
            AND     EVE.REGISTER_JUDGMENT = 'Y'
            AND     EVE.STD_EVENT_ID IN (230, 240, 233, 250, 251, 253, 254, 375)
            AND     JUDG.JUDGMENT_DATE > ADD_MONTHS(SYSDATE,-72));

    -- Update deregistration and amendment case events
    UPDATE  CASE_EVENTS EVE
    SET     EVE.DATE_TO_RTL = TRUNC(SYSDATE)
    WHERE   EVE.DELETED_FLAG = 'N'
    AND     EVE.DATE_TO_RTL IS NULL
    AND     ((EVE.STD_EVENT_ID IN (79 ,170 ,375 ,600 ,253) AND EVE.REGISTER_JUDGMENT = 'Y')
            OR (EVE.STD_EVENT_ID = 236))
    AND EXISTS
        (SELECT j.judg_seq
         FROM   TMP_RTL_JUDGMENTS j
         WHERE  j.judg_seq = eve.judg_seq
    );

    -- Update registration case events
    UPDATE  CASE_EVENTS EVE
    SET     EVE.DATE_TO_RTL = TRUNC(SYSDATE)
    WHERE   EVE.DELETED_FLAG = 'N'
    AND     EVE.DATE_TO_RTL IS NULL
    AND     EVE.REGISTER_JUDGMENT = 'Y'
    AND     EVE.STD_EVENT_ID IN (254 ,251, 230, 240, 233, 250 )
    AND EXISTS
        (SELECT null
         FROM TMP_RTL_JUDGMENTS trj
         WHERE trj.judg_seq = eve.judg_seq
    );

    -- Update newly registered consolidated orders
    UPDATE  CONSOLIDATED_ORDERS CO
    SET     CO.SENT_TO_RTL = TRUNC(SYSDATE),
            CO.STATUS_TO_RTL = 'Y'
    WHERE   CO.CO_NUMBER IN (
            SELECT  COE.CO_NUMBER
            FROM    CO_EVENTS COE
            WHERE   COE.ERROR_INDICATOR = 'N'
            AND     COE.DATE_TO_RTL IS NULL
            AND     COE.STD_EVENT_ID = 920
    );

    -- Update registration and deregistration CO events
    UPDATE  CO_EVENTS COE
    SET     COE.DATE_TO_RTL = TRUNC(SYSDATE)
    WHERE   COE.ERROR_INDICATOR = 'N'
    AND     COE.DATE_TO_RTL IS NULL
    AND     COE.STD_EVENT_ID IN (920 ,927 ,928 ,935);

    COMMIT;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : f_calc_co_balance
| DESCRIPTION  : Calculates the outstanding balance on the consolidated order
------------------------------------------------------------------------------------------------------*/
FUNCTION f_calc_co_balance (p_co_number     IN consolidated_orders.co_number%TYPE) RETURN NUMBER IS

    v_return_val        NUMBER := 0;
    v_fee_amount        NUMBER := 0;
    v_total_paid_out    NUMBER := 0;
    v_total_passthrough NUMBER := 0;
    v_total_fees_paid   NUMBER := 0;
    v_total_debts       NUMBER := 0;
    v_money_in_court    NUMBER := 0;

BEGIN

    -- FEE AMOUNT
    SELECT NVL(fee_amount, 0)
    INTO v_fee_amount
    FROM consolidated_orders
    WHERE co_number = p_co_number;

    -- TOTAL PAID OUT
    SELECT NVL(SUM(dd.dd_amount), 0)
    INTO v_total_paid_out
    FROM debt_dividends dd, allowed_debts ald
    WHERE dd.dd_co_number = p_co_number
    AND dd.dd_ald_seq = ald.debt_seq
    AND ald.debt_status IN ('LIVE','SCHEDULE2','PAID')
    AND dd.created = 'Y';

    -- TOTAL PASSTHROUGH
    SELECT NVL(SUM(pay.amount), 0)
    INTO v_total_passthrough
    FROM payments pay, allowed_debts ald
    WHERE ald.debt_seq = pay.ald_debt_seq
    AND pay.passthrough = 'Y'
    AND ald.debt_co_number = p_co_number
    AND ald.debt_status IN ('LIVE', 'PAID', 'SCHEDULE2')
    AND pay.error_indicator = 'N';

    -- TOTAL FEES PAID
    SELECT NVL(SUM(div.div_fee), 0)
    INTO v_total_fees_paid
    FROM dividends div
    WHERE div.div_co_number = p_co_number
    AND div.created = 'Y';

    -- TOTAL DEBTS
    SELECT NVL(SUM(debt_amount_allowed), 0)
    INTO v_total_debts
    FROM allowed_debts ald
    WHERE ald.debt_status IN ('LIVE', 'PAID', 'SCHEDULE2')
    AND debt_co_number = p_co_number;

    -- MONIES IN COURT
    SELECT NVL(SUM(pay.amount), 0)
    INTO v_money_in_court
    FROM payments pay
    WHERE pay.payout_date IS NULL
    AND pay.rd_date IS NULL
    AND pay.passthrough = 'N'
    AND pay.retention_type = 'AO/CAEO'
    AND pay.payment_for = 'CO'
    AND pay.subject_no = p_co_number;

    -- Calculate the outstanding balance
    v_return_val := (v_total_debts + v_fee_amount) - (v_total_paid_out + v_total_fees_paid + v_total_passthrough + v_money_in_court);
    IF v_return_val < 0.00 THEN
        v_return_val := 0.00;
    END IF;

    RETURN v_return_val;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : check_invalid_char
| DESCRIPTION  : Function to check for invalid characters
------------------------------------------------------------------------------------------------------*/
FUNCTION check_invalid_char(string_in IN VARCHAR2) RETURN BOOLEAN IS
    b_invalid_character_found BOOLEAN := FALSE;
BEGIN
    IF string_in IS NOT NULL
    THEN
        FOR i in 1..LENGTH(string_in)
        LOOP
            IF b_invalid_character_found = FALSE
            THEN
                IF ASCII(SUBSTR(string_in,i,1)) NOT BETWEEN 32 AND 127 THEN
                    b_invalid_character_found := TRUE;
                    EXIT;
                END IF;
            END IF;
        END LOOP;
    END IF;
    RETURN b_invalid_character_found;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_replacement_char
| DESCRIPTION  : For a given invalid ASCII character code, determines the replacement character
------------------------------------------------------------------------------------------------------*/
FUNCTION get_replacement_char(p_ascii_code NUMBER) RETURN VARCHAR2 IS
    v_new_char VARCHAR2(3);
BEGIN

    SELECT NVL(t.replacement_char,'')
    INTO v_new_char
    FROM tmp_rtl_character_map t
    WHERE t.ascii_code = p_ascii_code;

    RETURN v_new_char;

EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RETURN '';
    WHEN OTHERS THEN
        RETURN '';
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : parse_string
| DESCRIPTION  : Parses a string and checks if it contains an invalid XML character, returning a
|                replacement string with any invalid characters removed.
------------------------------------------------------------------------------------------------------*/
FUNCTION parse_string(string_in IN VARCHAR2, maxlength IN NUMBER) RETURN VARCHAR2 IS
    v_new_string parties.person_requested_name%TYPE := NULL;
    n_ascii      NUMBER;
BEGIN

    IF string_in IS NOT NULL
    THEN
        FOR i in 1..LENGTH(string_in)
        LOOP
            -- Get ASCII code for the character
            n_ascii := ASCII(SUBSTR(string_in,i,1));
            IF n_ascii NOT BETWEEN 32 AND 127 THEN
                -- Invalid character identified, replace it with a valid one
                v_new_string := v_new_string || get_replacement_char(n_ascii);
            ELSE
                -- Character is valid
                v_new_string := v_new_string || SUBSTR(string_in,i,1);
            END IF;
        END LOOP;

        -- Check if new string generated exceeds the maximum length
        IF LENGTH(v_new_string) > maxlength THEN
            v_new_string := '';
            FOR i in 1..LENGTH(string_in)
            LOOP
                -- Get ASCII code for the character
                n_ascii := ASCII(SUBSTR(string_in,i,1));
                IF n_ascii NOT BETWEEN 32 AND 127 THEN
                    -- As replacement process exceeds the maximum length, replace with blanks now
                    v_new_string := v_new_string || '';
                ELSE
                    -- Character is valid
                    v_new_string := v_new_string || SUBSTR(string_in,i,1);
                END IF;
            END LOOP;
        END IF;
    END IF;

    RETURN v_new_string;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_file_line
| DESCRIPTION  : Common function to generate a file line
------------------------------------------------------------------------------------------------------*/
FUNCTION get_file_line (p_court IN NUMBER, p_enf_no IN VARCHAR2, p_total IN VARCHAR2, p_judg_date IN VARCHAR2, p_status IN VARCHAR2, p_canc_date IN VARCHAR2,
                        p_name IN VARCHAR2, p_add1 IN VARCHAR2, p_add2 IN VARCHAR2, p_add3 IN VARCHAR2, p_add4 IN VARCHAR2, p_add5 IN VARCHAR2,
                        p_postcode IN VARCHAR2, p_dob IN VARCHAR2) RETURN VARCHAR2 IS

    v_file_line     VARCHAR(500);
    v_name          parties.person_requested_name%TYPE;
    v_addr_1        given_addresses.address_line1%TYPE;
    v_addr_2        given_addresses.address_line2%TYPE;
    v_addr_3        given_addresses.address_line3%TYPE;
    v_addr_4        given_addresses.address_line4%TYPE;
    v_addr_5        given_addresses.address_line5%TYPE;
    v_postcode      given_addresses.postcode%TYPE;
    b_found         BOOLEAN := FALSE;

BEGIN

    -- For name and address lines, check for invalid characters (e.g. Welsh characters) and replace them
    b_found := check_invalid_char(p_name);
    IF b_found = TRUE THEN
        v_name := parse_string(p_name, 70);
    ELSE
        v_name := p_name;
    END IF;

    b_found := check_invalid_char(p_add1);
    IF b_found = TRUE THEN
        v_addr_1 := parse_string(p_add1, 35);
    ELSE
        v_addr_1 := p_add1;
    END IF;

    b_found := check_invalid_char(p_add2);
    IF b_found = TRUE THEN
        v_addr_2 := parse_string(p_add2, 35);
    ELSE
        v_addr_2 := p_add2;
    END IF;

    b_found := check_invalid_char(p_add3);
    IF b_found = TRUE THEN
        v_addr_3 := parse_string(p_add3, 35);
    ELSE
        v_addr_3 := p_add3;
    END IF;

    b_found := check_invalid_char(p_add4);
    IF b_found = TRUE THEN
        v_addr_4 := parse_string(p_add4, 35);
    ELSE
        v_addr_4 := p_add4;
    END IF;

    b_found := check_invalid_char(p_add5);
    IF b_found = TRUE THEN
        v_addr_5 := parse_string(p_add5, 35);
    ELSE
        v_addr_5 := p_add5;
    END IF;

    b_found := check_invalid_char(p_postcode);
    IF b_found = TRUE THEN
        v_postcode := parse_string(p_postcode, 8);
    ELSE
        v_postcode := p_postcode;
    END IF;

    -- Generate the file line
    v_file_line := p_court || p_enf_no || p_total || p_judg_date || p_status || RPAD(NVL(p_canc_date,' '),8) || RPAD(v_name,70) || RPAD(v_addr_1,35) || RPAD(v_addr_2,35)
                    || RPAD(NVL(v_addr_3,' '),35) || RPAD(NVL(v_addr_4,' '),35)|| RPAD(NVL(v_addr_5,' '),35) || RPAD(NVL(v_postcode,' '),8) || RPAD(NVL(p_dob,' '),8);

    RETURN v_file_line;

END;

END rtl_export_pkg;
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."SDT_MCOL_MIG_PACK" IS
    /******************************************************************************************************************/
    /*                                                 P A C K A G E                                                  */
    /******************************************************************************************************************/

    /******************************************************************************************************************/
    /* Module     : SDT_MCOL_MIG_PACK.pck                                                                             */
    /* Description: Package used to store common procedures used to migrate data from CaseMan to MCOL                 */
    /*              as part of the CCBC SDT solution.                                                                 */
    /*                                                                                                                */
    /* Amendment History                                                                                              */
    /*                                                                                                                */
    /* Date         Name             Amendment                                                                        */
    /* ------------------------------------------------------------------------                                       */
    /*                                                                                                                */
    /******************************************************************************************************************/

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_clean_tables                                                                                  */
    /* DESCRIPTION  : Truncates all the migration tables ready for population                                         */
    /******************************************************************************************************************/
    PROCEDURE p_clean_tables;

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_populate_creditor_claims                                                                      */
    /* DESCRIPTION  : Populates the tmp_mcol_mig_cred_claims table                                                    */
    /******************************************************************************************************************/
    PROCEDURE p_populate_creditor_claims(
        p_cred_code             IN cases.cred_code%TYPE);

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_filter_creditor_claims                                                                        */
    /* DESCRIPTION  : Filters the creditor claims to be processed by looking for those with event activity            */
    /******************************************************************************************************************/
    PROCEDURE p_filter_creditor_claims;

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_delete_inactive_claims                                                                        */
    /* DESCRIPTION  : Deletes any records from tmp_mcol_mig_cred_claims with no activity in the last 3 years          */
    /******************************************************************************************************************/
    PROCEDURE p_delete_inactive_claims;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_parties                                                                             */
    /* DESCRIPTION  : Returns the number of Defendant and Claimant parties on a case record                           */
    /******************************************************************************************************************/
    FUNCTION f_get_count_parties(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_judgments                                                                           */
    /* DESCRIPTION  : Returns the number of Judgments to be migrated on a case                                        */
    /*                note that only one Judgment (the latest) per defendant can be migrated                          */
    /******************************************************************************************************************/
    FUNCTION f_get_count_judgments(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_warrants                                                                            */
    /* DESCRIPTION  : Returns the number of Warrants to be migrated on a case                                         */
    /*                We're only interested in home warrants (not foreign or reissued) with the type EXECUTION        */
    /******************************************************************************************************************/
    FUNCTION f_get_count_warrants(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_events                                                                              */
    /* DESCRIPTION  : Returns the number of Case Events to be migrated on a case                                      */
    /*                For 620 events, need to exclude those linked to final returns 147 and 156                       */
    /******************************************************************************************************************/
    FUNCTION f_get_count_events(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER;

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_validate_claim                                                                                */
    /* DESCRIPTION  : Validates the claim and writes a row to the tmp_mcol_mig_failures if needed                     */
    /******************************************************************************************************************/
    PROCEDURE p_validate_claim(
        p_case_number       IN cases.case_number%TYPE,
        p_cred_code         IN cases.cred_code%TYPE,
        p_write_db          IN BOOLEAN,
        p_valid             OUT BOOLEAN);

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_insert_claim_exception                                                                        */
    /* DESCRIPTION  : Inserts a row to the tmp_mcol_mig_failures table                                                */
    /******************************************************************************************************************/
    PROCEDURE p_insert_claim_exception(
        p_case_number       IN cases.case_number%TYPE,
        p_cred_code         IN cases.cred_code%TYPE,
        p_error             IN tmp_mcol_mig_failures.failure_reason%TYPE,
        p_write_db          IN BOOLEAN);

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_status_reset_event_required                                                                   */
    /* DESCRIPTION  : Indicates whether or not the case status has been changed via an event 72,73,74,75,76,78,79     */
    /*                but the status has since been reset to NULL.                                                    */
    /******************************************************************************************************************/
    FUNCTION f_status_reset_event_required(
        f_case_number       IN cases.case_number%TYPE) RETURN BOOLEAN;

END sdt_mcol_mig_pack;
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."SDT_MCOL_MIG_PACK" IS
    /******************************************************************************************************************/
    /*                                            P A C K A G E  B O D Y                                              */
    /******************************************************************************************************************/

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_clean_tables                                                                                  */
    /* DESCRIPTION  : Truncates all the migration tables ready for population                                         */
    /******************************************************************************************************************/
    PROCEDURE p_clean_tables
    IS
    BEGIN
        EXECUTE IMMEDIATE 'TRUNCATE TABLE mcol_mig_claim_data';
        EXECUTE IMMEDIATE 'TRUNCATE TABLE mcol_mig_party_data';
        EXECUTE IMMEDIATE 'TRUNCATE TABLE mcol_mig_judgment_data';
        EXECUTE IMMEDIATE 'TRUNCATE TABLE mcol_mig_warrant_data';
        EXECUTE IMMEDIATE 'TRUNCATE TABLE mcol_mig_event_data';
    END p_clean_tables;

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_populate_creditor_claims                                                                      */
    /* DESCRIPTION  : Populates the tmp_mcol_mig_cred_claims table                                                    */
    /******************************************************************************************************************/
    PROCEDURE p_populate_creditor_claims(
        p_cred_code             IN cases.cred_code%TYPE)
    IS

        TYPE ARRAY IS TABLE OF tmp_mcol_mig_cred_claims%ROWTYPE;
        l_data ARRAY;

        CURSOR c_cred_claims
        IS
            SELECT  c.case_number
                    ,c.date_of_issue
                    ,'N'
                    ,'N'
                    ,'N'
                    ,'N'
            FROM    cases c
            WHERE   NVL(c.cred_code,-1) = p_cred_code
            AND     c.admin_crt_code = 335;

    BEGIN

        -- Truncate the tmp_mcol_mig_cred_claims table
        EXECUTE IMMEDIATE 'TRUNCATE TABLE tmp_mcol_mig_cred_claims';

        OPEN c_cred_claims;
        LOOP
            -- Bulk collect all claims for the coded creditor
            FETCH c_cred_claims BULK COLLECT INTO l_data LIMIT 1000;

            -- Insert into the tmp_mcol_mig_cred_claims table
            FORALL i IN 1..l_data.COUNT
            INSERT INTO tmp_mcol_mig_cred_claims VALUES l_data(i);

            EXIT WHEN c_cred_claims%NOTFOUND;
        END LOOP;
        CLOSE c_cred_claims;

        -- Update all claims to indicate whether or not have been created in the last three years
        UPDATE  tmp_mcol_mig_cred_claims
        SET     created_in_range = 'Y'
        WHERE   date_of_issue > ADD_MONTHS(SYSDATE, -36);

        COMMIT;
    END p_populate_creditor_claims;


    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_filter_creditor_claims                                                                        */
    /* DESCRIPTION  : Filters the creditor claims to be processed by looking for those with event activity            */
    /******************************************************************************************************************/
    PROCEDURE p_filter_creditor_claims
    IS
    BEGIN
        -- Update all tmp_mcol_mig_cred_claims to state whether or not there has been any
        -- relevant case event activity in the last three years.
        UPDATE tmp_mcol_mig_cred_claims t
        SET    t.event_activity = 'Y'
        WHERE  t.created_in_range = 'N'
        AND EXISTS (SELECT  NULL
                    FROM    case_events ce
                    WHERE   ce.case_number = t.case_number
                    AND     ce.std_event_id IN  (30
                                                ,36
                                                ,38
                                                ,45
                                                ,49
                                                ,50
                                                ,52
                                                ,57
                                                ,60
                                                ,72
                                                ,73
                                                ,74
                                                ,75
                                                ,76
                                                ,78
                                                ,79
                                                ,132
                                                ,140
                                                ,150
                                                ,155
                                                ,160
                                                ,170
                                                ,174
                                                ,230
                                                ,240
                                                ,250
                                                ,251
                                                ,254
                                                ,380
                                                ,620)
                    AND     ce.deleted_flag = 'N'
                    AND     ce.event_date > ADD_MONTHS(SYSDATE, -36));

        COMMIT;

    END p_filter_creditor_claims;

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_delete_inactive_claims                                                                        */
    /* DESCRIPTION  : Deletes any records from tmp_mcol_mig_cred_claims with no activity in the last 3 years          */
    /******************************************************************************************************************/
    PROCEDURE p_delete_inactive_claims
    IS
    BEGIN
        DELETE FROM tmp_mcol_mig_cred_claims t
        WHERE   t.created_in_range = 'N'
        AND     t.event_activity = 'N';

        COMMIT;
    END p_delete_inactive_claims;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_parties                                                                             */
    /* DESCRIPTION  : Returns the number of Defendant and Claimant parties on a case record                           */
    /******************************************************************************************************************/
    FUNCTION f_get_count_parties(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER
    IS

        l_count     NUMBER;

    BEGIN

        SELECT COUNT(*) INTO l_count
        FROM    case_party_roles cpr
        WHERE   cpr.case_number = f_case_number
        AND     cpr.party_role_code IN ('DEFENDANT','CLAIMANT');

        -- Return the number of defendants and claimants + 1 which is for the national coded party solicitor
        RETURN l_count + 1;

    END f_get_count_parties;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_judgments                                                                           */
    /* DESCRIPTION  : Returns the number of Judgments to be migrated on a case                                        */
    /*                note that only one Judgment (the latest) per defendant can be migrated                          */
    /******************************************************************************************************************/
    FUNCTION f_get_count_judgments(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER
    IS

        l_count     NUMBER;

    BEGIN

        SELECT COUNT(*) INTO l_count
        FROM    judgments j
        WHERE   j.case_number = f_case_number
        AND     j.against_party_role_code = 'DEFENDANT'
        AND     j.judg_seq = (
                        SELECT  MAX(j2.judg_seq)
                        FROM    judgments j2
                        WHERE   j2.case_number = j.case_number
                        AND     j2.against_party_role_code = j.against_party_role_code
                        AND     j2.against_case_party_no = j.against_case_party_no);

        RETURN l_count;

    END f_get_count_judgments;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_warrants                                                                            */
    /* DESCRIPTION  : Returns the number of Warrants to be migrated on a case                                         */
    /*                We're only interested in home warrants (not foreign or reissued) with the type EXECUTION        */
    /******************************************************************************************************************/
    FUNCTION f_get_count_warrants(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER
    IS

        l_count     NUMBER;

    BEGIN

        SELECT COUNT(*) INTO l_count
        FROM    warrants w
        WHERE   w.case_number = f_case_number
        AND     w.local_warrant_number IS NULL
        AND     w.original_warrant_number IS NULL
        AND     w.warrant_type IN ('EXECUTION','CONTROL')
        AND     w.issued_by = 335
        AND     w.currently_owned_by = 335;

        RETURN l_count;

    END f_get_count_warrants;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_get_count_events                                                                              */
    /* DESCRIPTION  : Returns the number of Case Events to be migrated on a case                                      */
    /*                For 620 events, need to exclude those linked to final returns 147 and 156                       */
    /******************************************************************************************************************/
    FUNCTION f_get_count_events(
        f_case_number       IN cases.case_number%TYPE) RETURN NUMBER
    IS

        l_count         NUMBER;
        l_count_fr      NUMBER;
        l_bad_returns   NUMBER;

    BEGIN

        SELECT COUNT(*) INTO l_count
        FROM    case_events ce
        WHERE   ce.case_number = f_case_number
        AND     ce.deleted_flag = 'N'
        AND     ce.result IS NULL
        AND     ce.std_event_id IN (
                    SELECT  tm.std_event_id
                    FROM    tmp_mcol_mig_event_mapping tm
                    WHERE   tm.std_event_id != 620);

        SELECT COUNT(*) INTO l_count_fr
        FROM    case_events ce, warrants w
        WHERE   ce.case_number = f_case_number
        AND     ce.deleted_flag = 'N'
        AND     ce.std_event_id = 620
        AND     w.warrant_id (+)= ce.warrant_id
        AND     w.local_warrant_number IS NULL
        AND     w.original_warrant_number IS NULL
        AND     w.warrant_type IN ('EXECUTION','CONTROL');

        IF l_count_fr > 0 THEN

            -- Get number of 620 events linked to unwanted warrant returns 147 and 156
            SELECT COUNT(*) INTO l_bad_returns
            FROM    case_events ce, warrant_returns wr, warrants w
            WHERE   ce.case_number = f_case_number
            AND     ce.deleted_flag = 'N'
            AND     ce.std_event_id = 620
            AND     wr.event_seq(+) = ce.event_seq
            AND     wr.return_code IN ('147','156')
            AND     w.warrant_id (+)= ce.warrant_id
            AND     w.local_warrant_number IS NULL
            AND     w.original_warrant_number IS NULL
            AND     w.warrant_type IN ('EXECUTION','CONTROL');

        ELSE

            -- No final returns on the warrant, don't bother with the bad returns count
            l_bad_returns := 0;

        END IF;

        -- Check if need to add an additional event for the case status reset
        IF f_status_reset_event_required(f_case_number) = TRUE THEN
            l_count := l_count + 1;
        END IF;

        RETURN l_count + (l_count_fr - l_bad_returns);

    END f_get_count_events;

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_validate_claim                                                                                */
    /* DESCRIPTION  : Validates the claim and writes a row to the tmp_mcol_mig_failures if needed                     */
    /******************************************************************************************************************/
    PROCEDURE p_validate_claim(
        p_case_number       IN cases.case_number%TYPE,
        p_cred_code         IN cases.cred_code%TYPE,
        p_write_db          IN BOOLEAN,
        p_valid             OUT BOOLEAN)
    IS

        l_case_status           cases.status%TYPE;
        l_case_type             cases.case_type%TYPE;
        l_amount                cases.amount_claimed%TYPE;
        l_date                  cases.date_of_issue%TYPE;
        l_partic_length         NUMBER;
        --l_invalid_postcode        VARCHAR2(1);
        l_invalid_warrant       VARCHAR2(1);
        l_payee_length          NUMBER;
        l_ncp_length            NUMBER;
        l_invalid_party_name    VARCHAR2(1);
        l_number_claimants      NUMBER;
        l_number_defendants     NUMBER;

    BEGIN

        -- Assume case is valid from the start and remove any existing failures on the case
        p_valid := TRUE;
        IF p_write_db = TRUE THEN
            DELETE FROM tmp_mcol_mig_failures
            WHERE case_number = p_case_number;
        END IF;

        SELECT  c.status, c.case_type, c.amount_claimed, c.date_of_issue, length(c.particulars_of_claim)
        INTO    l_case_status, l_case_type, l_amount, l_date, l_partic_length
        FROM    cases c
        WHERE   c.case_number = p_case_number;

        --SELECT    DECODE(COUNT(*),0,'N','Y')
        --INTO  l_invalid_postcode
        --FROM      case_party_roles cpr, given_addresses ga
        --WHERE     cpr.case_number = p_case_number
        --AND       cpr.party_role_code = 'DEFENDANT'
        --AND       ga.party_id = cpr.party_id
        --AND       ga.address_type_code = 'SERVICE'
        --AND       ga.valid_to IS NULL
        --AND       ga.postcode IS NULL;

        SELECT  DECODE(COUNT(*),0,'N','Y')
        INTO    l_invalid_warrant
        FROM    warrants w
        WHERE   w.case_number = p_case_number
        AND     w.issued_by = 335
        AND     w.currently_owned_by = 335
        AND     w.local_warrant_number IS NULL
        AND     w.original_warrant_number IS NULL
        AND     w.defendant2 IS NOT NULL;

        SELECT  LENGTH(p.person_requested_name), LENGTH(p2.person_requested_name)
        INTO    l_payee_length, l_ncp_length
        FROM    coded_parties cp, parties p, party_to_party_relationship ptpr, parties p2
        WHERE   cp.code = p_cred_code
        AND     ptpr.party_a_id (+)= cp.party_id
        AND     ptpr.party_a_role_code (+)= 'SOLICITOR'
        AND     ptpr.party_b_role_code (+)= 'NCP PAYEE'
        AND     p.party_id (+)= ptpr.party_b_id
        AND     p2.party_id = cp.party_id;

        SELECT  DECODE(COUNT(*),0,'N','Y')
        INTO    l_invalid_party_name
        FROM    parties p, case_party_roles cpr
        WHERE   cpr.case_number = p_case_number
        AND     cpr.party_role_code IN ('DEFENDANT','CLAIMANT')
        AND     p.party_id = cpr.party_id
        AND     LENGTH(p.person_requested_name) > 60;

        SELECT  COUNT(*)
        INTO    l_number_claimants
        FROM    case_party_roles cpr, parties p, given_addresses ga
        WHERE   cpr.case_number = p_case_number
        AND     cpr.party_role_code = 'CLAIMANT'
        AND     p.party_id = cpr.party_id
        AND     ga.party_id = cpr.party_id;

        SELECT  COUNT(*)
        INTO    l_number_defendants
        FROM    case_party_roles cpr, parties p, given_addresses ga
        WHERE   cpr.case_number = p_case_number
        AND     cpr.party_role_code = 'DEFENDANT'
        AND     p.party_id = cpr.party_id
        AND     ga.party_id = cpr.party_id;

        -- Check case is not stuck in transfer limbo
        IF l_case_status = 'TRANSFERRED' THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'TRANSFER ISSUE'
                                    ,p_write_db);
        END IF;

        -- Check the case type - must be equal to CLAIM - SPEC ONLY
        IF  l_case_type != 'CLAIM - SPEC ONLY' THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'INVALID CLAIM TYPE'
                                    ,p_write_db);
        END IF;

        -- Amount claimed on the case cannot exceed 99,999.99
        IF  l_amount >= 100000 THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'INVALID AMOUNT CLAIMED'
                                    ,p_write_db);
        END IF;

        -- Date of Issue cannot be NULL
        IF  l_date IS NULL THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'BLANK ISSUE DATE'
                                    ,p_write_db);
        END IF;

        -- Particulars of Claim cannot exceed 1080 characters in length
        IF  l_partic_length > 1080 THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'INVALID PARTICULARS OF CLAIM'
                                    ,p_write_db);
        END IF;

        -- Defendant postcode cannot be NULL
        --IF    l_invalid_postcode = 'Y' THEN
        --  p_valid := FALSE;
        --  p_insert_claim_exception(p_case_number
        --                          ,p_cred_code
        --                          ,'MISSING DEFENDANT POSTCODE'
        --                          ,p_write_db);
        --END IF;

        -- Warrants cannot have two parties against recorded on them
        IF  l_invalid_warrant = 'Y' THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'WARRANT AGAINST TWO DEFENDANTS'
                                    ,p_write_db);
        END IF;

        -- NCP Payee party name is over 60 characters in length
        IF  l_payee_length > 60 THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'CREDITOR PAYEE NAME LENGTH > 60'
                                    ,p_write_db);
        END IF;

        -- NCP party name is over 60 characters in length
        IF  l_ncp_length > 60 THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'CREDITOR NAME LENGTH > 60'
                                    ,p_write_db);
        END IF;

        -- Claimant/Defendant parties exist on case with name > 60 characters in length
        IF  l_invalid_party_name = 'Y' THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'CLAIMANT/DEFENDANT NAME LENGTH > 60'
                                    ,p_write_db);
        END IF;

        -- There can only be one claimant party on the case
        IF  l_number_claimants != 1 THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'INVALID NUMBERS OF CLAIMANT PARTIES'
                                    ,p_write_db);
        END IF;

        -- There can only be one or two defendant parties on the case
        IF  l_number_defendants NOT IN (1,2) THEN
            p_valid := FALSE;
            p_insert_claim_exception(p_case_number
                                    ,p_cred_code
                                    ,'INVALID NUMBERS OF DEFENDANT PARTIES'
                                    ,p_write_db);
        END IF;

    END p_validate_claim;

    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
    /* NAME         : p_insert_claim_exception                                                                        */
    /* DESCRIPTION  : Inserts a row to the tmp_mcol_mig_failures table                                                */
    /******************************************************************************************************************/
    PROCEDURE p_insert_claim_exception(
        p_case_number       IN cases.case_number%TYPE,
        p_cred_code         IN cases.cred_code%TYPE,
        p_error             IN tmp_mcol_mig_failures.failure_reason%TYPE,
        p_write_db          IN BOOLEAN)
    IS

    BEGIN

        IF p_write_db = TRUE THEN

            -- Write to the tmp_mcol_mig_failures table
            INSERT INTO tmp_mcol_mig_failures
                (case_number
                ,cred_code
                ,failure_reason)
            VALUES
                (p_case_number
                ,p_cred_code
                ,p_error);

        ELSE
            -- Write to DBMS_OUTPUT
            dbms_output.put_line('Case ' || p_case_number || ' failed: ' || p_error);

        END IF;

    END p_insert_claim_exception;

    /******************************************************************************************************************/
    /* TYPE         : FUNCTION                                                                                        */
    /* NAME         : f_status_reset_event_required                                                                   */
    /* DESCRIPTION  : Indicates whether or not the case status has been changed via an event 72,73,74,75,76,78,79     */
    /*                but the status has since been reset to NULL.                                                    */
    /******************************************************************************************************************/
    FUNCTION f_status_reset_event_required(
        f_case_number       IN cases.case_number%TYPE) RETURN BOOLEAN
    IS

        l_case_status   cases.status%TYPE;
        l_status_set    VARCHAR2(1);
        l_reset_event   BOOLEAN;

    BEGIN

        l_reset_event := FALSE;

        -- Retrieve Case Status
        SELECT  status
        INTO    l_case_status
        FROM    cases
        WHERE   case_number = f_case_number;

        -- Check if a valid status changing event exists
        SELECT  DECODE(COUNT(*),0,'N','Y')
        INTO    l_status_set
        FROM    case_events
        WHERE   case_number = f_case_number
        AND     std_event_id IN (72,73,74,75,76,78,79)
        AND     deleted_flag = 'N';

        IF l_status_set = 'Y' AND l_case_status IS NULL THEN
            -- A status changing event exists, but the status is NULL so has been reset
            l_reset_event := TRUE;
        END IF;

        RETURN l_reset_event;

    END f_status_reset_event_required;

END sdt_mcol_mig_pack;
/



