    PROCEDURE p_insert_local_ae_events(p_ae_event_seq IN NUMBER,p_transfer_status OUT cmcs_transfer_status.ts_status%TYPE,p_debug IN CHAR DEFAULT 'N');


    /******************************************************************************************************************/
    /* TYPE         : PROCEDURE                                                                                       */
