FUNCTION f_pscheck(p_ps_date IN DATE, p_court_code NUMBER) RETURN VARCHAR2 IS

  CURSOR c1 IS
    SELECT MAX(TRUNC(item_date))
    FROM DCS
    WHERE admin_court_code = p_court_code;

  CURSOR c_ps (p_date IN DATE) IS
    SELECT 1
  FROM PAYMENT_SUMMARY
    WHERE TRUNC(dcs_date) = TRUNC(p_date)
  AND   admin_court_code = p_court_code
    AND   valid = 'Y';

  l_return NUMBER(1);
  l_date DATE;
  l_ps_date DATE;

BEGIN
  l_ps_date := p_ps_date;
  IF l_ps_date IS NULL THEN
    OPEN c1;
    FETCH c1 INTO l_date;
    CLOSE c1;

    /* cursor c1 will return null only if DCS is empty.
       DCS table is truncated by the End of Month process.
       If it is empty it is save to assume that the End Of Day was completed
       for the previous working day
    */

    IF l_date IS NULL THEN
      RETURN 'TRUE';
    END IF;

    l_ps_date := l_date;

  END IF;

  OPEN c_ps(l_ps_date);
  FETCH c_ps INTO l_return;
  IF c_ps%FOUND THEN
    CLOSE c_ps;
    RETURN 'TRUE';
  ELSE
    CLOSE c_ps;
    RETURN 'FALSE';
  END IF;

END f_pscheck;

PROCEDURE p_del_dsum_repno (p_court_code IN NUMBER, p_user_id IN REPORT_DATA.user_id%TYPE) IS
BEGIN
  DELETE FROM REPORT_DATA
  WHERE  report_type = 'DSUM'
  AND    user_id     = p_user_id
  AND  admin_court_code = p_court_code;
COMMIT;
END p_del_dsum_repno;


FUNCTION f_get_party_name (p_case_number IN VARCHAR2, p_reporting_party_role_code IN VARCHAR2, p_case_party_no IN NUMBER DEFAULT 1) RETURN VARCHAR2 IS

l_party_name  case_parties.name%TYPE;

CURSOR c_party_name IS
SELECT  DISTINCT name
FROM  case_parties
WHERE case_number = p_case_number
AND reporting_party_role_code = p_reporting_party_role_code
AND case_party_no = p_case_party_no;

BEGIN
  OPEN c_party_name;
  FETCH c_party_name INTO l_party_name;
  CLOSE c_party_name;
  RETURN l_party_name;
  EXCEPTION
    WHEN OTHERS THEN
      RETURN SQLCODE;

END f_get_party_name;

FUNCTION f_reporting_party_n_name
        (p_case_number IN CASES.CASE_NUMBER%TYPE,
     p_reporting_role_code IN PARTY_ROLES.REPORTING_ROLE_CODE%TYPE,
     p_number IN NUMBER) RETURN VARCHAR2 IS

     l_party_ctr NUMBER :=0;
   l_party_name PARTIES.PERSON_REQUESTED_NAME%TYPE :=NULL;

   CURSOR c_get_party_name IS
      SELECT PAR.PERSON_REQUESTED_NAME
    FROM CASE_PARTY_ROLES cpr,
         PARTIES par,
       PARTY_ROLES pr
    WHERE pr.reporting_role_code=p_reporting_role_code
    AND   pr.party_role_code = cpr.party_role_code
    AND   cpr.case_number = p_case_number
    AND   cpr.party_id = par.party_id
    ORDER BY DECODE(cpr.party_role_code,
                      'DEFENDANT','1A','DEBTOR','1B',
            'CLAIMANT','2A','CREDITOR','2B',
            'SOLICITOR','3A',
            cpr.party_role_code),
          cpr.case_party_no;
   BEGIN
      OPEN c_get_party_name;
      FOR l_party_ctr IN 1..p_number
    LOOP
       l_party_name :=NULL;
     FETCH c_get_party_name
     INTO l_party_name;
       EXIT WHEN c_get_party_name%NOTFOUND;
    END LOOP;
      CLOSE c_get_party_name;
    RETURN l_party_name;
   END f_reporting_party_n_name;

   FUNCTION f_party_role_short_code (p_party_role_code IN case_PARTIES.party_role_code%TYPE,
                                  p_case_party_no IN case_PARTIES.case_party_no%TYPE) RETURN VARCHAR IS
   BEGIN
      IF p_party_role_code IN  ('DEFENDANT','DEBTOR') THEN
         RETURN 'D'||p_case_party_no;
      ELSIF p_party_role_code IN ('CLAIMANT','CREDITOR') THEN
         RETURN 'C'||p_case_party_no;
      ELSE
       RETURN 'OP'||p_case_party_no;
      END IF;
   END f_party_role_short_code;

FUNCTION f_payee_party (p_ald_seq  number) RETURN NUMBER IS
  CURSOR c_check_payee_cp IS
   SELECT cp_payee_id
   FROM allowed_debts
   WHERE debt_seq = p_ald_seq
   and cp_payee_id is not null;

   CURSOR c_check_payee_ncp IS
    SELECT party_id
    FROM parties_no_cpr
    WHERE ald_seq = p_ald_seq
    AND address_type_code = 'CO PAYEE'
        and name is not null;

  CURSOR c_check_creditor_cp IS
   SELECT cp_creditor_id
   FROM allowed_debts
   WHERE debt_seq = p_ald_seq
   and cp_creditor_id is not null;


   CURSOR c_check_creditor_ncp IS
    SELECT party_id
    FROM parties_no_cpr
    WHERE ald_seq = p_ald_seq
    AND address_type_code = 'CO CRED'
        and name is not null;

        l_party_id parties.party_id%TYPE;

    BEGIN

    OPEN c_check_payee_cp;
    FETCH c_check_payee_cp
    INTO l_party_id;
    IF c_check_payee_cp%NOTFOUND THEN
       OPEN c_check_payee_ncp;
       FETCH c_check_payee_ncp
       INTO l_party_id;
       IF c_check_payee_ncp%NOTFOUND THEN
              open c_check_creditor_cp;
              fetch c_check_creditor_cp
              into l_party_id;
              IF c_check_creditor_cp%NOTFOUND THEN
                 open c_check_creditor_ncp;
                 fetch c_check_creditor_ncp
                 into l_party_id;
                 IF c_check_creditor_ncp%NOTFOUND THEN
                    l_party_id := null;
                 END IF;
                 CLOSE c_check_creditor_ncp;
              END IF;
              close c_check_creditor_cp;
           END IF;
       CLOSE c_check_payee_ncp;
    END IF;
    CLOSE c_check_payee_cp;

    RETURN l_party_id;

END f_payee_party;

FUNCTION f_payee_exists (p_ald_seq in number) RETURN VARCHAR2 IS
  CURSOR c_check_cp IS
   SELECT 'Y'
   FROM allowed_debts
   WHERE debt_seq = p_ald_seq
   and cp_payee_id is not null;

   CURSOR c_check_payee IS
    SELECT 'Y'
    FROM parties_no_cpr
    WHERE ald_seq = p_ald_seq
    AND address_type_code = 'CO PAYEE'
        and name is not null;

    l_dummy VARCHAR2(1);
    l_payee_exists VARCHAR2(1) :='N';

    BEGIN

    OPEN c_check_cp;
    FETCH c_check_cp
    INTO l_dummy;
    IF c_check_cp%FOUND THEN
       l_payee_exists := 'Y';
        ELSE
       OPEN c_check_payee;
       FETCH c_check_payee
       INTO l_dummy;
       IF c_check_payee%FOUND THEN
          l_payee_exists :='Y';
       END IF;
       CLOSE c_check_payee;

    END IF;
    CLOSE c_check_cp;

    RETURN l_payee_exists;
END f_payee_exists;


END sups_Reports_Pack;
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."SUPS_SCHEDULED_JOBS" is

    PROCEDURE cm_set_new_server_secret (new_expiry_date  IN VARCHAR2 DEFAULT TO_CHAR(SYSDATE+1,'YYYY-MM-DD HH24:MI:SS'));

    PROCEDURE cc_clear_document_store;

    PROCEDURE clear_report_queue (batchsize IN INTEGER);

    PROCEDURE clear_documents (batchsize IN INTEGER);

end sups_scheduled_jobs;
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."SUPS_SCHEDULED_JOBS" is

   set_raise_application_error BOOLEAN;

   procedure cm_set_new_server_secret (new_expiry_date  IN VARCHAR2 DEFAULT TO_CHAR(SYSDATE+1,'YYYY-MM-DD HH24:MI:SS'))
   as
      l_found_server_secret   NUMBER := 0;
      l_new_expiry_date       DATE;
      l_new_secret_main       VARCHAR2(4000);
      function f_new_secret return varchar2
      is
         l_current_length        NUMBER := 0;
         l_new_length            NUMBER := 128;
         l_new_secret            VARCHAR2(4000);
      begin
         for r_new_length in (select round(dbms_random.value(128,512),0) new_length from dual)
         loop
            l_new_length := r_new_length.new_length;
         end loop;
         l_new_secret := '{' ;
         while l_current_length < l_new_length
         loop
            l_current_length := l_current_length + 1;
            for r_next_hex in (select lpad(trim(to_char(round(dbms_random.value(0,255),0),'xx')),2,'0') next_hex from dual)
            loop
               if l_current_length = l_new_length
               then
                  l_new_secret := l_new_secret || '0x' || r_next_hex.next_hex || '}' ;
               else
                  l_new_secret := l_new_secret || '0x' || r_next_hex.next_hex || ':' ;
               end if;
            end loop;
         end loop;
         return l_new_secret;
      end f_new_secret;
   begin
      begin
         l_new_expiry_date := to_date(new_expiry_date,'YYYY-MM-DD HH24:MI:SS');
      exception
         when others then
            l_new_expiry_date := sysdate + 1;
      end;
      for r_server_secret in (select SERVER_SECRET_ID, EXPIRY_DATE, SECRET
                              from   server_secret)
      loop
         l_found_server_secret := 1;
         l_new_secret_main := f_new_secret;
         update server_secret set secret = l_new_secret_main,
                                  expiry_date = l_new_expiry_date
         where  server_secret_id = r_server_secret.SERVER_SECRET_ID;
      end loop;
      if l_found_server_secret = 0
      then
         l_new_secret_main := f_new_secret;
         insert into server_secret (SERVER_SECRET_ID, EXPIRY_DATE, SECRET)
         values (1,l_new_expiry_date,l_new_secret_main);
      end if;
      commit;
   end cm_set_new_server_secret;

/************************************************************************************************************\
* TYPE          : PROCEDURE                                                                                  *
* NAME          : cc_clear_document_store                                                                    *
* DESCRIPTION   : Identify all documents that are not permanently stored (dont have a value -1) and that     *
*               : the storage duration has expired (CREATED_DATE+STORAGE_DURATION) is younger than today's   *
*               : date.                                                                                      *
*               : delete all the content_store rows that the documents use                                   *
*               : delete all the document_store rows                                                         *
*               : delete all the report queue rows that refer to these documents                             *
*               :                                                                                            *
\************************************************************************************************************/
PROCEDURE cc_clear_document_store AS

    batchsize INTEGER := 200;

BEGIN

    -- Delete Report_queue rows
    clear_report_queue(batchsize);

    -- delete all "parent-less" document_store rows and content_store rows
    clear_documents(batchsize);

    -- if we do not reach here then this is probably because we have blown a rollback segment somewhere
    -- this procedure may need to be broken down into smaller commit blocks.
    COMMIT;

    dbms_output.put_line('Successfully completed cc_clear_document_store.');

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
        DBMS_OUTPUT.PUT_LINE('while executing procedure cc_clear_document_store as part of clear doc store job.');
        DBMS_OUTPUT.PUT_LINE('Rolling Back changes');
        ROLLBACK;
        -- re-raise exception so control.sh and autosys picks up the failure
        RAISE;

END cc_clear_document_store;

/************************************************************************************************************\
* TYPE          : PROCEDURE                                                                                  *
* NAME          : clear_report_queue                                                                         *
* DESCRIPTION   : Deletes any REPORT_QUEUE rows no longer referenced or have exceeded their retention period *
*               :                                                                                            *
\************************************************************************************************************/
PROCEDURE clear_report_queue (batchsize IN INTEGER) AS

    CURSOR  cur_rq1 IS
    SELECT RQ.ID
    FROM REPORT_QUEUE RQ
    WHERE  RQ.STORAGE_DURATION != -1
    AND    TRUNC(SYSDATE) > RQ.CREATED_DATE + RQ.STORAGE_DURATION;

    CURSOR  cur_rq2 IS
    SELECT RQ.ID
    FROM REPORT_QUEUE RQ
    WHERE RQ.TYPE in ('3','4')
    AND RQ.STORAGE_DURATION = -1
    AND NOT EXISTS (SELECT 1 FROM WP_OUTPUT W WHERE xmlsource_numcheck(W.XMLSOURCE) = RQ.DOCUMENT_ID)
    AND NOT EXISTS (SELECT 1 FROM REPORT_MAP M WHERE M.REPORT_QUEUE_ID = RQ.ID);

    i   INTEGER;

BEGIN

    i := 0;
    FOR rq1_rec IN cur_rq1 LOOP

        -- Delete the REPORT_QUEUE row and increment count
        DELETE FROM report_queue WHERE id = rq1_rec.id;
        i := i + 1;

        -- Perform a commit when the count reaches the batch size
        IF MOD(i, batchsize) = 0 THEN
            COMMIT;
        END IF;

    END LOOP;

    dbms_output.put_line('First REPORT_QUEUE delete: ' || i || ' records.');

    -- final commit to mop up any deletes that fell under the batchsize threshold
    COMMIT;

    i := 0;
    FOR rq2_rec IN cur_rq2 LOOP

        -- Delete the REPORT_QUEUE row and increment count
        DELETE FROM report_queue WHERE id = rq2_rec.id;
        i := i + 1;

        -- Perform a commit when the count reaches the batch size
        IF MOD(i, batchsize) = 0 THEN
            COMMIT;
        END IF;

    END LOOP;

    dbms_output.put_line('Second REPORT_QUEUE delete: ' || i || ' records.');

    -- final commit to mop up any deletes that fell under the batchsize threshold
    COMMIT;

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
        DBMS_OUTPUT.PUT_LINE('while executing procedure clear_report_queue as part of clear doc store job.');
        DBMS_OUTPUT.PUT_LINE('Rolling Back changes');
        ROLLBACK;
        -- re-raise exception so control.sh and autosys picks up the failure
        RAISE;

END clear_report_queue;

/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : clear_documents                                                                           *
* DESCRIPTION   : Deletes any DOCUMENT_STORE and CONTENT_STORE rows no longer referenced or have exceeded   *
*               : their retention period                                                                    *
*               :                                                                                           *
\***********************************************************************************************************/
PROCEDURE clear_documents (batchsize IN INTEGER) AS

    CURSOR  cur_ds IS
    SELECT D.ID, D.CONTENT_STORE_ID
    FROM DOCUMENT_STORE D
    WHERE NOT EXISTS (SELECT 1 FROM REPORT_QUEUE R WHERE R.DOCUMENT_ID = D.ID)
    AND   NOT EXISTS (SELECT 1 FROM WP_OUTPUT W WHERE xmlsource_numcheck(W.XMLSOURCE) = D.ID AND NVL(W.FINAL_IND,'N') = 'N'   );

    i   INTEGER;

BEGIN

    i := 0;
    FOR doc_rec IN cur_ds LOOP

        -- Delete the DOCUMENT_STORE and CONTENT_STORE rows and increment count
        DELETE FROM document_store WHERE id = doc_rec.id;
        DELETE FROM content_store WHERE id = TO_NUMBER(doc_rec.content_store_id);
        i := i + 1;

        -- Perform a commit when the count reaches the batch size
        IF MOD(i, batchsize) = 0 THEN
            COMMIT;
        END IF;

    END LOOP;

    dbms_output.put_line('DOCUMENT_STORE and CONTENT_STORE deletes: ' || i || ' records.');

    -- final commit to mop up any deletes that fell under the batchsize threshold
    COMMIT;

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('An error was encountered - '||SQLCODE||' -ERROR- '||SQLERRM);
        DBMS_OUTPUT.PUT_LINE('while executing procedure clear_documents as part of clear doc store job.');
        DBMS_OUTPUT.PUT_LINE('Rolling Back changes');
        ROLLBACK;
        -- re-raise exception so control.sh and autosys picks up the failure
        RAISE;

END clear_documents;

BEGIN
   set_raise_application_error := FALSE;
END sups_scheduled_jobs;
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."VALIDATE_DEFENCES_PKG" IS

PROCEDURE bc_de_u1( p_username IN VARCHAR2, p_court_code IN VARCHAR2, p_debug IN VARCHAR2, p_load_failed IN OUT NUMBER );

END; -- end of validate_defences_pkg
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."VALIDATE_DEFENCES_PKG" IS

/***********************************************************************************************************\
* TYPE          : FUNCTION                                                                                  *
* NAME          : f_case_invalid                                                                            *
* DESCRIPTION   : Checks to if the case referred to in the submitted defence exists in CASEMAN              *
*               : Returns TRUE if case cannot be found                                                      *
\***********************************************************************************************************/
FUNCTION f_case_invalid ( l_case_no  VARCHAR2) RETURN BOOLEAN IS

valid_case  VARCHAR2(8) := NULL;

BEGIN
    SELECT case_number
    INTO valid_case
    FROM cases
    WHERE case_number = l_case_no;

    RETURN FALSE;

    EXCEPTION
    WHEN NO_DATA_FOUND THEN
       RETURN TRUE;

END; -- end of f_case_invalid function

/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                  *
* NAME          : p_defendant_invalid                                                                       *
* DESCRIPTION   : Checks to if the defendant referred to in the submitted defence exists in CASEMAN         *
*               : Returns TRUE if defendant cannot be found                                                 *
\***********************************************************************************************************/
PROCEDURE p_defendant_invalid   (
                                l_case_no           IN  VARCHAR2,
                                l_defendant_id      IN  NUMBER,
                                lv_case_party_no    OUT VARCHAR2,
                                lv_reject_code      OUT VARCHAR2
                                ) IS

BEGIN
    SELECT  cpr.case_party_no
    INTO    lv_case_party_no
    FROM    case_party_roles cpr
    WHERE   cpr.case_number     = l_case_no
    AND     cpr.case_party_no   =  l_defendant_id
    AND     cpr.party_role_code = 'DEFENDANT';

    lv_reject_code := NULL; -- defendant found, so don't set reject code

    EXCEPTION
    WHEN NO_DATA_FOUND THEN
       lv_reject_code := 90; -- Quoted Defendant Id does not exist on system

END; -- end of p_defendant_invalid procedure

/***********************************************************************************************************\
* TYPE          : FUNCTION                                                                                  *
* NAME          : f_active_judgement                                                                        *
* DESCRIPTION   : Checks to see if there active judgement recorded against the defendant                    *
*               : Returns TRUE if judgement be found                                                        *
\***********************************************************************************************************/
FUNCTION f_active_judgement ( p_case_no  VARCHAR2, p_case_party_no VARCHAR2) RETURN BOOLEAN IS

nv_judgement_count NUMBER;

BEGIN
    SELECT COUNT(judg.judg_seq)
    INTO    nv_judgement_count
    FROM    judgments judg
    WHERE   judg.case_number = p_case_no
    AND     judg.against_party_role_code = 'DEFENDANT'
    AND     judg.against_case_party_no = p_case_party_no
    AND     (judg.status IS NULL OR  judg.status IN ('SATISFIED','CANCELLED'));

    IF nv_judgement_count > 0 THEN
    -- at least one judgement exists so
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;

    EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RETURN FALSE;
END; -- end of f_active_judgement function

/***********************************************************************************************************\
* TYPE          : FUNCTION                                                                                  *
* NAME          : f_case_stayed                                                                             *
* DESCRIPTION   : Checks to see if the case has been STAYED                                                 *
\***********************************************************************************************************/
FUNCTION f_case_stayed ( l_case_no  VARCHAR2) RETURN BOOLEAN IS

lv_valid_case  VARCHAR2(8) := NULL;

BEGIN
    SELECT  c.case_number
    INTO    lv_valid_case
    FROM    cases c
    WHERE   c.case_number = l_case_no
    AND     c.status = 'STAYED';

    -- case has been stayed
    RETURN TRUE;

    EXCEPTION
    WHEN NO_DATA_FOUND THEN
        -- case has not been stayed
        RETURN FALSE;
END;
/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : bc_de_u1                                                                         *
* DESCRIPTION   : Checks to see if the defences submitted via MCOL are valid                                *
*               : If the defence is valid, create a CASEMAN event and tell MCOL the defence has been        *
*               : accepted by CASEMAN                                                                       *
*               : If defence is not valid, do not create a event. Tell MCOL the defence has rejeced         *
*               : Returns TRUE if judgement be found                                                        *
\***********************************************************************************************************/

PROCEDURE bc_de_u1( p_username IN VARCHAR2, p_court_code IN VARCHAR2, p_debug IN VARCHAR2, p_load_failed IN OUT NUMBER ) IS

CURSOR  cur_defences IS
SELECT  dde.case_number,
        dde.type,
        dde.defendant_id,
        dde.defendant_addr_1,
        dde.defendant_addr_2,
        dde.defendant_addr_3,
        dde.defendant_addr_4,
        dde.defendant_postcode,
        dde.defendant_dob,
        dde.telephone_number,
        dde.email,
        dde.cust_file_sequence,
        dde.fee,
        dde.pdf_file_name,
        dde.print_now,
        dde.reject_code,
        dde.via_sdt,
        dde.validated
FROM    defence_doc_event dde
WHERE   validated = 'N'
FOR UPDATE OF dde.validated;

nv_reject_code  NUMBER          := NULL;
caseman_event   NUMBER          := 0;

mcol_type       VARCHAR2(2)     := NULL;
def_party_no    VARCHAR2(4)     := 0;
def_order_id    order_types.order_id%TYPE := NULL;

-- variable for error handling exception
nv_sql_code_num             NUMBER;              -- SQL Error Code Number.
cv_sql_err_mess             VARCHAR2(100);       -- SQL Error Message Text.
cv_error_loc                VARCHAR2(10)    := NULL;
cv_case_number              VARCHAR2(8)     := NULL;
cv_details                  case_events.details%TYPE := NULL;
def_file_loaded             VARCHAR2(1)     := 'N';

    BEGIN

        -- set application context
        SET_SUPS_APP_CTX(p_username, p_court_code,'BC_DE_U1' );

        DBMS_OUTPUT.PUT_LINE('**START** of defence validation ');

        FOR def_rec IN cur_defences
        LOOP
            nv_reject_code  :=  NULL;
            caseman_event   :=  NULL;
            mcol_type       :=  NULL;
            def_party_no    :=  NULL;
            def_file_loaded := 'N';
            cv_case_number  :=  def_rec.case_number;
            cv_details      := NULL;

            IF p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE('**START Defense validation **  Claim is '||def_rec.case_number||' Reject = '||nv_reject_code||' type is '||def_rec.type);
                DBMS_OUTPUT.PUT_LINE(' validated = '||def_rec.validated);

            END IF;

            CASE    def_rec.type
            WHEN 'AS' THEN
            -- validate Acknowledgement of Service event
                BEGIN
                    -- default to failed event
                    mcol_type := 'A0';

                    IF f_case_invalid ( cv_case_number ) THEN
                        cv_error_loc       := 'VAL_AO_CAS';
                        nv_reject_code     := 48; -- Quoted Case Number does not exist on system
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- verify the defendant exists
                        p_defendant_invalid
                        (
                        cv_case_number,
                        def_rec.defendant_id,
                        def_party_no,
                        nv_reject_code
                        );
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- passed validation so
                        -- set successful mcol_type
                        -- and caseman_event.
                        cv_error_loc       := 'VAL_AS_OK';
                        mcol_type      := 'AS';
                        caseman_event   := 38;
                        def_order_id    := 'CCBC_N9SDT';
                    END IF;

                END;
            WHEN 'DE' THEN
                -- validate defence event

                BEGIN
                    -- default to failed mcol event
                    mcol_type := 'E0';
                    IF f_case_invalid ( cv_case_number ) THEN
                        cv_error_loc       := 'VAL_EO_CAS';
                        nv_reject_code     := 48; -- Quoted Case Number does not exist on system
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- verify the defendant exists
                        p_defendant_invalid
                        (
                        cv_case_number,
                        def_rec.defendant_id,
                        def_party_no,
                        nv_reject_code
                        );
                    END IF;

                    IF  nv_reject_code IS NULL AND
                        f_active_judgement( cv_case_number, def_party_no ) THEN
                        -- active judgment has been found
                        cv_error_loc       := 'VAL_EO_JUG';
                        nv_reject_code     := 93; -- Active judgment found for defendant
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- passed validation so
                        -- set successful mcol_type
                        -- and caseman_event.
                        cv_error_loc    := 'VAL_DE_OK';
                        mcol_type       := 'DE';
                        caseman_event   := 50;
                        def_order_id    := 'CCBC_N9B';
                    END IF;
                END;
            WHEN 'DC' THEN
                -- Defence and Counterclaim event

                BEGIN
                    -- default to failed mcol event
                    mcol_type := 'D0';

                    IF f_case_invalid ( cv_case_number ) THEN
                        cv_error_loc       := 'VAL_DO_CAS';
                        nv_reject_code     := 48; -- Quoted Case Number does not exist on system
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- verify the defendant exists
                        p_defendant_invalid
                        (
                        cv_case_number,
                        def_rec.defendant_id,
                        def_party_no,
                        nv_reject_code
                        );
                    END IF;

                    IF  nv_reject_code IS NULL AND
                        f_active_judgement( cv_case_number, def_party_no ) THEN
                        -- active judgment has been found
                        cv_error_loc       := 'VAL_D0_JUG';
                        nv_reject_code     := 93; -- Active judgment found for defendant
                    END IF;

                    IF  nv_reject_code IS NULL AND
                        f_case_stayed( cv_case_number ) THEN
                        cv_error_loc       := 'VAL_DO_STA';
                        nv_reject_code     := 94; -- Case status is STAYED
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- passed validation so
                        -- set successful mcol_type
                        -- and caseman_event.
                        cv_error_loc       := 'VAL_DC_OK';
                        mcol_type      := 'DC';
                        caseman_event   := 52;
                        def_order_id    := 'CCBC_N9B';
                        IF  def_rec.fee     IS NOT NULL AND
                            def_rec.fee > 0 THEN
                            -- set event description
                            cv_details  := 'Fee Paid';
                        END IF;
                    END IF;
                END;
            WHEN 'PA' THEN
                -- part admission event
                BEGIN
                    -- default to failed mcol event
                    mcol_type := 'P0';

                    IF f_case_invalid ( cv_case_number ) THEN
                        cv_error_loc       := 'VAL_PO_CAS';
                        nv_reject_code     := 48; -- Quoted Case Number does not exist on system
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- verify the defendant exists
                        p_defendant_invalid
                        (
                        cv_case_number,
                        def_rec.defendant_id,
                        def_party_no,
                        nv_reject_code
                        );
                    END IF;

                    IF  nv_reject_code IS NULL AND
                        f_active_judgement( cv_case_number, def_party_no ) THEN
                        -- active judgment has been found
                        cv_error_loc       := 'VAL_P0_JUG';
                        nv_reject_code     := 93; -- Active judgment found for defendant
                    END IF;

                    IF nv_reject_code IS NULL THEN
                        -- passed validation so
                        -- set successful mcol_type
                        -- and caseman_event.
                        cv_error_loc       := 'VAL_PA_OK';
                        mcol_type      := 'PA';
                        caseman_event   := 60;
                        def_order_id    := 'CCBC_N9A';
                        IF  def_rec.fee     IS NOT NULL AND
                            def_rec.fee > 0 THEN
                            -- set event description
                            cv_details  := 'Fee Paid';
                        END IF;
                    END IF;
                END;
            ELSE
                -- unknown data table
                -- log an error message
                mcol_type      := def_rec.type;
                nv_reject_code := 96; -- invalid defence event type
            END CASE;

            IF p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE('Validated defence Claim is '||cv_case_number||' Reject = '||nv_reject_code||' type is '||mcol_type||' cust seq = '||def_rec.cust_file_sequence);
            END IF;

            IF nv_reject_code IS NULL THEN
                cv_error_loc := 'INS_EVNT';
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('adding defendant event for '||cv_case_number||' event '||caseman_event||' defendant '||def_rec.defendant_id);
                END IF;
                ccbc_events.insert_event_dbp
                    (
                    cv_case_number,
                    caseman_event,
                    def_rec.defendant_id,
                    'DEFENDANT',            -- party role code
                    '',                     -- requester
                    cv_details,             -- event details free text field
                    '',                     -- warrant id
                    '',                     -- judgement seq
                    '',                     -- vary seq
                    'N',                    --  deleted flag
                    ''                      -- result
                    );
                -- returned accepted record to mcol

                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('new def event id is '||ccbc_events.last_event_seq);
                    DBMS_OUTPUT.PUT_LINE('about to load defence document '||def_rec.pdf_file_name||' order id '||def_order_id||' mcol_type '||mcol_type);
                END IF; -- debug

                -- load the PDF Document associated with the event.
                                -- now try to load the MCOL PDF file
                -- Note: last_event_seq is a global populated with the event_seq
                -- by the ccbc_events.insert_event_dbp procedure
                -- load_document_for_event function will return Y or N
                document_load_pkg.load_document_for_event
                    (
                    cv_case_number,
                    def_rec.pdf_file_name,
                    ccbc_events.last_event_seq,
                    def_order_id,
                    p_debug,
                    def_file_loaded
                    );
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('load document into caseman result = '||def_file_loaded);
                END IF; -- debug

                IF def_file_loaded = 'N' THEN
                    -- increment the load_failed_count
                    -- if this count is non-zero, the
                    -- ccbc_mcol_interface pkg will exit with
                    -- a failure , so autosys will report
                    -- a failure which the operators need to
                    -- investigate
                    p_load_failed := p_load_failed + 1;
                END IF;

                -- caseman event has been added so set event date
                INSERT INTO mcol_data md
                    (
                    md.claim_number,
                    md.deft_id,
                    md.type,
                    md.event_date
                    )
                VALUES
                    (
                    cv_case_number,
                    def_rec.defendant_id,
                    mcol_type,
                    SYSDATE
                    );
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('accepted  '||SQL%ROWCOUNT);
                END IF; -- debug
            ELSE
                -- defence rejected, so record rejection in mcol data
                -- no caseman event is logged so do not set event date
                cv_error_loc := 'MCOL_INS';
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('inserting mcol data record for '||cv_case_number||' '||def_rec.defendant_id);
                END IF; -- debug
                INSERT INTO mcol_data md
                    (
                    md.claim_number,
                    md.deft_id,
                    md.type,
                    md.reject_code
                    )
                VALUES
                    (
                    cv_case_number,
                    def_rec.defendant_id,
                    mcol_type,
                    nv_reject_code
                    );
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('rejected  '||SQL%ROWCOUNT);
                END IF; -- debug
            END IF;


            -- add a record to the MCOL_PDF_TABLE

            INSERT INTO mcol_pdf_status
                (
                created_ts,
                pdf_file_name,
                loaded,
                printed,
                deleted,
                print_now,
                event_seq,
                case_number,
                order_id
                )
            VALUES
                (
                SYSTIMESTAMP,
                def_rec.pdf_file_name,
                def_file_loaded, -- this will be Y if validated and file has loaded successfully or N
                'N',
                'N',
                def_rec.print_now,           -- yes, for MCOL defence events. No for CCBC defence events
                decode(nv_reject_code,null, ccbc_events.last_event_seq,null),   -- NULL if rejected or event_seq if request is validated and loaded successfully
                def_rec.case_number,
                def_order_id
                );

            IF p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE('processed pdf status records '||SQL%ROWCOUNT);
            END IF; -- debug

            cv_error_loc       := 'UPD_DEF';
            UPDATE  defence_doc_event
            SET     validated = 'Y',
                    reject_code = nv_reject_code
            WHERE CURRENT OF cur_defences;

        END LOOP; -- finish processing current batch of defences
        COMMIT;
        DBMS_OUTPUT.PUT_LINE('** Finished validating defences ** ');

        /*------------------------------------------------------------------------------*
         *  Trap all errors and report them in the VALIDATE_ERRORS table, after         *
         * rolling back any incomplete inserts or updates.                              *
         *------------------------------------------------------------------------------*/
        EXCEPTION
        WHEN OTHERS THEN
            BEGIN
                nv_sql_code_num := SQLCODE;
                cv_sql_err_mess := substr(SQLERRM,1,100);
                DBMS_OUTPUT.PUT_LINE(nv_sql_code_num||' '||cv_sql_err_mess);
                ROLLBACK;
                IF cur_defences%ISOPEN THEN
                    CLOSE cur_defences;
                END IF;

                INSERT INTO validate_errors
                    (
                    module_id,
                    err_number,
                    err_date,
                    location,
                    description,
                    record_id
                    )
                VALUES
                    (
                    'BC_DE_U1',
                    nv_sql_code_num,
                    SYSDATE,
                    cv_error_loc,
                    cv_sql_err_mess,
                    cv_case_number
                    );
                COMMIT;
                RAISE;
            END;
    END; -- end of bc_de_u1
END; -- end of validate_defences_pkg
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."VALIDATE_SET_ASIDES_PKG" IS

PROCEDURE  bc_sa_u1( p_username IN VARCHAR2, p_court_code IN VARCHAR2, p_debug IN VARCHAR2, p_load_failed IN OUT NUMBER );

END; -- end of validate_set_asides_pkg
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."VALIDATE_SET_ASIDES_PKG" IS

/***********************************************************************************************************\
* TYPE          : FUNCTION                                                                                  *
* NAME          : f_case_invalid                                                                            *
* DESCRIPTION   : Checks to if the case referred to in the submitted defence exists in CASEMAN              *
*               : Returns TRUE if case cannot be found                                                      *
\***********************************************************************************************************/
FUNCTION f_case_invalid ( l_case_no  VARCHAR2) RETURN BOOLEAN IS

valid_case  VARCHAR2(8) := NULL;

BEGIN
    SELECT case_number
    INTO valid_case
    FROM cases
    WHERE case_number = l_case_no;

    RETURN FALSE;

    EXCEPTION
    WHEN NO_DATA_FOUND THEN
       RETURN TRUE;

END; -- end of f_case_invalid function

/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                  *
* NAME          : p_defendant_invalid                                                                       *
* DESCRIPTION   : Checks to if the defendant referred to in the submitted defence exists in CASEMAN         *
*               : Returns TRUE if defendant cannot be found                                                 *
\***********************************************************************************************************/
PROCEDURE p_defendant_invalid   (
                                l_case_no           IN  VARCHAR2,
                                l_defendant_id      IN  NUMBER,
                                lv_case_party_no    OUT NUMBER,
                                lv_reject_code      OUT VARCHAR2
                                ) IS

BEGIN

    SELECT  cpr.case_party_no
    INTO    lv_case_party_no
    FROM    case_party_roles cpr
    WHERE   cpr.case_number     = l_case_no
    AND     cpr.case_party_no   =  l_defendant_id
    AND     cpr.party_role_code = 'DEFENDANT';

    lv_reject_code := NULL; -- defendant found, so don't set reject code

    EXCEPTION
    WHEN NO_DATA_FOUND THEN
       lv_reject_code := 90; -- Quoted Defendant Id does not exist on system

END; -- end of p_defendant_invalid procedure

/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : f_get_judgement_seq                                                                       *
* DESCRIPTION   : Gets the sequence number of the latest ACTIVE or VARIED Judgement for a party             *                                                       *
*               : returns sequence_number or -1 if no ACTIVE or VARIED judgement is found                   *
*               : Also returns the MCOL_REFERENCE if one exists or NULL if not present                      *
\***********************************************************************************************************/
PROCEDURE p_get_judgement_seq
                        (
                        p_case_no           IN  VARCHAR2,
                        p_case_party_no     IN  NUMBER,
                        p_judgment_seq      OUT NUMBER,
                        p_mcol_judg_ref     OUT VARCHAR2,
                        p_reject_code       OUT VARCHAR2
                        ) IS

BEGIN

    p_judgment_seq := 0;
    p_mcol_judg_ref := NULL;

    -- note: since for CCBC cases, there can only be one active or
    -- varied judgment for each defendent, this will only ever return
    -- one record, even with the group by clause.

    SELECT  jg.judg_seq,
            jg.mcol_judg_ref
    INTO    p_judgment_seq,
            p_mcol_judg_ref
    FROM    judgments jg
    WHERE   jg.judg_seq =
            (SELECT MAX(judg1.judg_seq)
            FROM judgments judg1
            WHERE judg1.case_number                     = p_case_no
            AND judg1.against_case_party_no             = p_case_party_no
            AND judg1.against_party_role_code           = 'DEFENDANT'
            AND (judg1.status IS NULL or judg1.status   = 'VARIED'));



    p_reject_code := NULL;

    EXCEPTION
    WHEN NO_DATA_FOUND THEN
        -- no active or varied judgement found, so reject
        p_reject_code   := 97;
        p_judgment_seq := NULL;
        p_mcol_judg_ref := NULL;
END; -- end of p_get_judgement_seq procedure

/***********************************************************************************************************\
* TYPE          : FUNCTION                                                                                  *
* NAME          : f_check_for_sar_events                                                                    *
* DESCRIPTION   : check to see if there is a previous 160 set aside event already existing for the case     *
\***********************************************************************************************************/
FUNCTION f_check_for_sar_events
            (
            p_case_no       IN  VARCHAR2,
            p_case_party_no IN  VARCHAR2
            ) RETURN BOOLEAN IS

nv_event_id case_events.std_event_id%TYPE := 0;

BEGIN

    SELECT  distinct ce.std_event_id --
    INTO    nv_event_id
    FROM    case_events ce
    WHERE   ce.case_number      = p_case_no
    AND     ce.case_party_no    = p_case_party_no
    AND     ce.party_role_code  = 'DEFENDANT'
    AND     ce.std_event_id     = 160
    AND     ce.deleted_flag     = 'N';

    RETURN  TRUE;

    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RETURN FALSE;

END; -- end of f_check_for_sar_events
/***********************************************************************************************************\
* TYPE          : PROCEDURE                                                                                 *
* NAME          : bc_sa_u1                                                                                  *
* DESCRIPTION   : Checks to see if the set_asides submitted via MCOL are valid                              *
*               : If the defence is valid, create a CASEMAN event and tell MCOL the defence has been        *
*               : accepted by CASEMAN                                                                       *
*               : If defence is not valid, do not create a event. Tell MCOL the defence has rejeced         *
*               : Returns TRUE if judgement be found                                                        *
\***********************************************************************************************************/

PROCEDURE bc_sa_u1( p_username IN VARCHAR2, p_court_code IN VARCHAR2, p_debug IN VARCHAR2, p_load_failed IN OUT NUMBER ) IS

CURSOR  cur_set_asides IS
    SELECT  sar.case_number,
            sar.party_role_code,
            sar.defendant_id,
            sar.fee,
            sar.pdf_file_name,
            sar.cust_file_sequence,
            sar.reject_code,
            sar.validated,
            sar.via_sdt,
            sar.mcol_reference
    FROM    set_aside_requests sar
    WHERE   sar.validated = 'N'
    ORDER BY sar.case_number, sar.defendant_id
    FOR UPDATE OF sar.validated;

nv_reject_code  NUMBER          := NULL;
caseman_event   NUMBER          := 0;

sar_party_no        case_party_roles.case_party_no%TYPE := 0;
sar_case_number     cases.case_number%TYPE              := NULL;
sar_judgment_seq    judgments.judg_seq%TYPE             := 0;
sar_file_loaded     VARCHAR2(1)                         := 'N';
sar_requester       case_events.requester%TYPE          := NULL;

-- variable for error handling exception
nv_sql_code_num             NUMBER;              -- SQL Error Code Number.
cv_sql_err_mess             VARCHAR2(100);       -- SQL Error Message Text.
cv_error_loc                VARCHAR2(20)                        := NULL;
cv_judgment_ref             mcol_data.judgment_reference%TYPE   := NULL;

    BEGIN

        -- set application context
        SET_SUPS_APP_CTX(p_username, p_court_code,'BC_SA_U1' );

        DBMS_OUTPUT.PUT_LINE('**START** of set asides validation ');

        FOR sar_rec IN cur_set_asides
        LOOP
            nv_reject_code      :=  NULL;
            sar_judgment_seq    :=  NULL;
            sar_case_number     :=  sar_rec.case_number;
            sar_file_loaded     :=  'N';
            sar_requester       :=  NULL; -- requester type who made the set aside application

            IF p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE('** START Set Aside validation **  Claim is '  ||sar_rec.case_number
                                                                                    ||' Reject = '
                                                                                    ||nv_reject_code
                                                                                    ||' pdf_file_name is '||sar_rec.pdf_file_name);
                DBMS_OUTPUT.PUT_LINE(' validated = '||sar_rec.validated);
            END IF;

            -- check for invalid case
            IF f_case_invalid ( sar_rec.case_number ) THEN
                cv_error_loc       := 'SAR_CAS_FAIL';
                nv_reject_code     := 48; -- Quoted Case Number does not exist on system
            END IF;

            IF p_debug = 'Y' AND nv_reject_code IS NOT NULL THEN
                DBMS_OUTPUT.PUT_LINE('case '||sar_rec.case_number||' not  found, so rejecting with '||nv_reject_code);
            END IF;

            -- check that MCOL reference has been supplied
            IF sar_rec.mcol_reference IS NULL THEN
                cv_error_loc       := 'SAR_MIS_REF';
                nv_reject_code     := 99; -- missing MCOL case reference
            END IF;

            IF p_debug = 'Y' AND nv_reject_code IS NOT NULL THEN
                DBMS_OUTPUT.PUT_LINE('MCOL refeence not  found, so rejecting with '||nv_reject_code);
            END IF;

            -- validate the defendant
            IF  nv_reject_code IS NULL THEN
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('checking defendant');
                END IF;
                cv_error_loc       := 'SAR_DEF_CHK';
                p_defendant_invalid
                            (
                            sar_case_number,
                            sar_rec.defendant_id,
                            sar_party_no,
                            nv_reject_code
                            );
                IF p_debug = 'Y' THEN
                    IF  nv_reject_code IS NOT NULL THEN
                        DBMS_OUTPUT.PUT_LINE('Defendant '||sar_rec.defendant_id||' not  found, so rejecting with '||nv_reject_code);
                    ELSE
                        DBMS_OUTPUT.PUT_LINE('Defendant party no is'||sar_party_no);
                    END IF;
                END IF;
            END IF;

            -- set requester
            IF  sar_rec.party_role_code = 'DEFENDANT' THEN
                -- request for set aside from defendant
                sar_requester   :=  'PARTY_AGAINST';
            ELSE
                -- request for set aside from claimant
                sar_requester   :=  'PARTY_FOR';
            END IF;

            -- check for a VARIED/ACTIVE Judgement
            -- Note: The judgment to be set aside will always be
            -- vs the defendant, regardless of whether the claimant or
            -- defendant applied for the judgement to be set aside
            IF  nv_reject_code  IS NULL     THEN
                cv_error_loc       := 'SAR_JUG_CHK';
                p_get_judgement_seq
                        (
                        sar_case_number,
                        sar_rec.defendant_id,
                        sar_judgment_seq,
                        cv_judgment_ref,
                        nv_reject_code
                        );
                IF sar_judgment_seq = -1 THEN
                    -- no valid judgement found
                    nv_reject_code := 97;
                ELSIF cv_judgment_ref IS NULL THEN
                    -- we have a valid judgement without an
                    -- pre-existing mcol judgment reference, so create one
                    cv_judgment_ref := 'CM'||LPAD(TO_CHAR(sar_judgment_seq), 8, 0 );
                    DBMS_OUTPUT.PUT_LINE('created mcol reference of '||cv_judgment_ref);
                END IF;
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('defendant no is '||sar_rec.defendant_id);
                    DBMS_OUTPUT.PUT_LINE('Judgment seq is '||sar_judgment_seq);
                    DBMS_OUTPUT.PUT_LINE('Judgment ref is '||cv_judgment_ref);
                    DBMS_OUTPUT.PUT_LINE('Judgment nv_reject_code is '||nv_reject_code);
                END IF;
            END IF;

            -- check for previous set aside events
            IF  nv_reject_code  IS NULL AND
                f_check_for_sar_events( sar_case_number, sar_party_no)  THEN
                -- previous 160 event has been found so reject request
                nv_reject_code := 98;
                cv_error_loc       := 'SAR_EVT_FAIL';
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('160 event found, so rejecting with '||nv_reject_code);
                END IF;
            END IF;

            IF p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE('validated Set Aside  is ' ||sar_rec.case_number
                                                                ||' Reject = '
                                                                ||nv_reject_code
                                                                ||' pdf_file_name is '||sar_rec.pdf_file_name);
            END IF;

            IF nv_reject_code IS NULL THEN
                cv_error_loc := 'SAR_INS_EVNT';
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('adding Set Aside Request event for '||sar_case_number||' party '||sar_rec.party_role_code||' id '||sar_rec.defendant_id);
                END IF;

                -- create event in caseman using overloaded procedure
                -- with mcol_reference as the last parameter
                ccbc_events.insert_event_dbp
                        (
                        sar_case_number,
                        160,                -- std_event_id
                        sar_rec.defendant_id,
                        'DEFENDANT',
                        sar_requester,      -- requester
                        'Fee Paid',         -- details
                        '',                 -- warrant_number
                        sar_judgment_seq,  -- judgement_seq
                        '',
                        'N',
                        '',
                        sar_rec.mcol_reference
                        );

                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('new event id is '||ccbc_events.last_event_seq);
                    DBMS_OUTPUT.PUT_LINE('about to load document '||sar_rec.pdf_file_name);
                END IF; -- debug

                -- now try to load the MCOL PDF file
                -- Note: last_event_seq is a global populated with the event_seq
                -- by the ccbc_events.insert_event_dbp procedure
                -- load_document_for_event function will return Y or N
                document_load_pkg.load_document_for_event
                    (
                    sar_case_number,
                    sar_rec.pdf_file_name,
                    ccbc_events.last_event_seq,
                    'CCBC_N244',
                    p_debug,
                    sar_file_loaded
                    );
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('load document into caseman result = '||sar_file_loaded);
                END IF; -- debug

                IF sar_file_loaded = 'N' THEN
                    -- increment the load_failed_count
                    -- if this count is non-zero, the
                    -- ccbc_mcol_interface pkg will exit with
                    -- a failure , so autosys will report
                    -- a failure which the operators need to
                    -- investigate
                    p_load_failed := p_load_failed + 1;
                END IF;

                -- returned accepted record to mcol
                INSERT INTO mcol_data md
                    (
                    md.claim_number,
                    md.deft_id,
                    md.type,
                    md.event_date,
                    md.mcol_reference,
                    md.judgment_reference
                    )
                VALUES
                    (
                    sar_case_number,
                    sar_rec.defendant_id,
                    'X1',
                    SYSDATE,
                    sar_rec.mcol_reference,
                    cv_judgment_ref
                    );

            ELSE
                -- set aside request  rejected, so record rejection in mcol data
                -- no caseman event is logged so do not set event date
                cv_error_loc := 'MCOL_INS';
                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('rejecting Set Aside Request event for '||sar_case_number||' party '||sar_rec.party_role_code||' id '||sar_rec.defendant_id);
                END IF; -- debug
                INSERT INTO mcol_data md
                    (
                    md.claim_number,
                    md.deft_id,
                    md.type,
                    md.reject_code,
                    md.mcol_reference,
                    md.judgment_reference
                    )
                VALUES
                    (
                    sar_case_number,
                    sar_rec.defendant_id,
                    'X0',
                    nv_reject_code,
                    sar_rec.mcol_reference,
                    cv_judgment_ref
                    );
            END IF;

            IF  p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE(' Last Judgment Seq is  '||ccbc_events.last_event_seq);
            END IF;

            -- add a record to the MCOL_PDF_TABLE

            INSERT INTO mcol_pdf_status
                (
                created_ts,
                pdf_file_name,
                loaded,
                printed,
                deleted,
                print_now,
                event_seq,
                case_number,
                order_id
                )
            VALUES
                (
                SYSTIMESTAMP,
                sar_rec.pdf_file_name,
                sar_file_loaded, -- this will be Y if validated and file has loaded successfully or N
                'N',
                'N',
                'Y',
                decode(nv_reject_code,null, ccbc_events.last_event_seq,null),   -- NULL if rejected or event_seq if request is validated and loaded successfully
                sar_case_number,
                'CCBC_N244' -- order id
                );

            IF p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE('loaded pdf file records '||SQL%ROWCOUNT);
            END IF; -- debug

            cv_error_loc       := 'UPD_SAR';
            UPDATE  set_aside_requests
            SET     validated = 'Y',
                    reject_code = nv_reject_code -- this will be NULL if the record is valid.
            WHERE CURRENT OF cur_set_asides;

        END LOOP; -- finish processing current batch of set_asides
        COMMIT;
        DBMS_OUTPUT.PUT_LINE('** Finished validating set_asides ** ');

        /*------------------------------------------------------------------------------*
         *  Trap all errors and report them in the VALIDATE_ERRORS table, after         *
         * rolling back any incomplete inserts or updates.                              *
         *------------------------------------------------------------------------------*/
        EXCEPTION
        WHEN OTHERS THEN
            BEGIN
                nv_sql_code_num := SQLCODE;
                cv_sql_err_mess := substr(SQLERRM,1,100);
                DBMS_OUTPUT.PUT_LINE(nv_sql_code_num||' '||cv_sql_err_mess);
                ROLLBACK;
                IF cur_set_asides%ISOPEN THEN
                    CLOSE cur_set_asides;
                END IF;

                INSERT INTO validate_errors
                    (
                    module_id,
                    err_number,
                    err_date,
                    location,
                    description,
                    record_id
                    )
                VALUES
                    (
                    'BC_SA_U1',
                    nv_sql_code_num,
                    SYSDATE,
                    cv_error_loc,
                    cv_sql_err_mess,
                    sar_case_number
                    );
                COMMIT;
                RAISE;
            END;
    END; -- end of bc_sa_u1
END; -- end of validate_set_asides_pkg
/



  CREATE OR REPLACE PACKAGE "CASEMAN"."WFT_EXPORT_PKG" AS

/*------------------------------------------------------------------------------------------------------
|                                          Package Header
------------------------------------------------------------------------------------------------------*/

-- TO DO: procedures to run process for a single court in isolation and another to load all the CSV files in isolation

-- TO DO: Insert into TRANSFER_ERROR_LOG table

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_run_wft_export
| DESCRIPTION  : Runs the WFT Export job
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_run_wft_export (p_debug IN  VARCHAR2);

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_run_wft_export_single_court
| DESCRIPTION  : Runs the WFT Export job for a single court after the WFT records have been updated
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_run_wft_export_single_court (p_grouping_crt IN courts.wft_grouping_court%TYPE
                                        ,p_export_date  IN VARCHAR2
                                        ,p_debug IN  VARCHAR2);

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_delete_old_exports
| DESCRIPTION  : Deletes any exports that have passed their retention period
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_delete_old_exports;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_post_extract_updates
| DESCRIPTION  : Performs the post extract updates on the window_for_trial records
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_post_extract_updates;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_insert_csv_file
| DESCRIPTION  : Loads the WFT file contents into the report_queue, document_store, content_store
|                and the wft_exports tables
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_insert_csv_file (p_filename     IN VARCHAR2
                            ,p_grouping_crt IN courts.wft_grouping_court%TYPE
                            ,p_content_store_id IN content_store.id%TYPE
                            ,p_file_loaded  OUT VARCHAR2);

END wft_export_pkg;
/
CREATE OR REPLACE PACKAGE BODY "CASEMAN"."WFT_EXPORT_PKG" AS

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_write_to_blob
| DESCRIPTION  : Writes the CSV content to the CONTENT_STORE.DATA BLOB column
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_write_to_blob (p_destLob IN OUT BLOB, p_buffer IN VARCHAR2);

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_write_clob_to_blob
| DESCRIPTION  : Writes the CSV content to the CONTENT_STORE.DATA BLOB column
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_write_clob_to_blob (p_destLob IN OUT BLOB, p_buffer IN CLOB);

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : append_large_varchar
| DESCRIPTION  : Appends a varchar2 which when gets too big, gets written to a CLOB instead
------------------------------------------------------------------------------------------------------*/
PROCEDURE append_large_varchar(v_clob IN OUT NOCOPY CLOB, v_vc IN OUT NOCOPY VARCHAR2, v_app VARCHAR2);

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : get_csv_header
| DESCRIPTION  : Writes the standard file header
------------------------------------------------------------------------------------------------------*/
FUNCTION get_csv_header RETURN VARCHAR2;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_no_data_line
| DESCRIPTION  : Writes the no data line
------------------------------------------------------------------------------------------------------*/
FUNCTION get_no_data_line (p_code IN courts.code%TYPE) RETURN VARCHAR2;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_curr_crt_wft_line
| DESCRIPTION  : Writes a WFT record line for the current court
------------------------------------------------------------------------------------------------------*/
FUNCTION get_curr_crt_wft_line (p_crt_code IN courts.code%TYPE
                                  ,p_case_number IN cases.case_number%TYPE
                                  ,p_wft_id IN window_for_trial.wft_id%TYPE) RETURN CLOB;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_prev_crt_wft_line
| DESCRIPTION  : Writes a WFT record line for the previous court
------------------------------------------------------------------------------------------------------*/
FUNCTION get_prev_crt_wft_line (p_crt_code IN courts.code%TYPE
                                  ,p_case_number IN cases.case_number%TYPE
                                  ,p_wft_id IN window_for_trial.wft_id%TYPE) RETURN CLOB;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_log_error
| DESCRIPTION  : Writes an error message to the TRANSFER_ERROR_LOG table
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_log_error (p_court_code IN NUMBER, p_err IN VARCHAR2);

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_run_wft_export
| DESCRIPTION  : Runs the WFT Export job
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_run_wft_export (p_debug IN  VARCHAR2) IS

    CURSOR c_get_grouping_courts IS
    SELECT DISTINCT wft_grouping_court
    FROM courts
    WHERE caseman_inservice = 'Y'
    AND sups_centralised_flag = 'Y'
    AND wft_grouping_court IS NOT NULL
    ORDER BY wft_grouping_court;

    CURSOR c_get_courts_in_group (p_grouping_court NUMBER) IS
    SELECT code
    FROM courts
    WHERE caseman_inservice = 'Y'
    AND sups_centralised_flag = 'Y'
    AND  wft_grouping_court = p_grouping_court
    ORDER BY code;

    CURSOR c_get_current_wft_records (p_court_code NUMBER) IS
    SELECT wft_id, wft_case_number
    FROM window_for_trial
    WHERE wft_extracted_for_dm IS NULL
    AND  wft_current_court = p_court_code;

    CURSOR c_get_previous_wft_records (p_court_code NUMBER) IS
    SELECT wft_id, wft_case_number  FROM window_for_trial
    WHERE wft_extracted_for_dm IS NULL
    AND  wft_previous_court = p_court_code;

    l_prev_crt_count    NUMBER  := 0;
    l_curr_crt_count    NUMBER  := 0;
    l_loaded    VARCHAR2(1);
    l_wft_file_name VARCHAR2(30);
    l_tmp_str   VARCHAR2(2000);
    l_error    VARCHAR2(1) := 'N';

    l_dataLOB   BLOB;
    l_tempLOB   CLOB;

    l_content_store_id  content_store.id%TYPE;

BEGIN

    -- Delete wft export records older than x days (using SYSTEM_DATA item to hold retention period)
    p_delete_old_exports();

    -- Set audit context
    set_sups_app_ctx('CCBC_BATCH', 0, 'WFTExport' );

    FOR grp_crt IN c_get_grouping_courts LOOP

        BEGIN

            IF p_debug = 'Y' THEN
                DBMS_OUTPUT.PUT_LINE('Grouping Court: '||grp_crt.wft_grouping_court);
            END IF;

            -- Generate the file name
            SELECT grp_crt.wft_grouping_court||'WFT'||TO_CHAR(SYSDATE,'YYYYMMDD_HH24MI')||'.csv' INTO l_wft_file_name FROM dual;

            SELECT  content_sequence.NEXTVAL
            INTO    l_content_store_id
            FROM    dual;

            -- create a record with an empty blob into which the file will be loaded
            INSERT INTO content_store (id, data)
            VALUES ( l_content_store_id, EMPTY_BLOB() )
            RETURNING DATA INTO l_dataLOB;

            -- Write the file header
            l_tmp_str := get_csv_header();
            p_write_to_blob( l_dataLOB, l_tmp_str );

            FOR court_rec IN c_get_courts_in_group(grp_crt.wft_grouping_court) LOOP

                -- Get count of unextracted WFT records for the court
                SELECT COUNT(*) INTO l_prev_crt_count FROM window_for_trial WHERE wft_extracted_for_dm IS NULL AND wft_previous_court  = court_rec.code;
                SELECT COUNT(*) INTO l_curr_crt_count FROM window_for_trial WHERE wft_extracted_for_dm IS NULL AND wft_current_court = court_rec.code;

                IF p_debug = 'Y' THEN
                    DBMS_OUTPUT.PUT_LINE('Court: '||court_rec.code||' ('||l_prev_crt_count||' + '||l_curr_crt_count||') records');
                END IF;

                IF l_curr_crt_count > 0 THEN
                    -- Retrieve WFT Records for Current Court
                    FOR curr_wft_rec IN c_get_current_wft_records(court_rec.code) LOOP
                        l_tempLOB := get_curr_crt_wft_line(court_rec.code, curr_wft_rec.wft_case_number, curr_wft_rec.wft_id);
                        p_write_clob_to_blob(l_dataLOB, l_tempLOB);
                    END LOOP;
                END IF;

                IF l_prev_crt_count > 0 THEN
                    -- Retrieve WFT Records for Previous Court
                    FOR prev_wft_rec IN c_get_previous_wft_records(court_rec.code) LOOP
                        l_tempLOB := get_prev_crt_wft_line(court_rec.code, prev_wft_rec.wft_case_number, prev_wft_rec.wft_id);
                        p_write_clob_to_blob(l_dataLOB, l_tempLOB);
                    END LOOP;
                END IF;

                IF l_prev_crt_count = 0 AND l_curr_crt_count = 0 THEN
                    -- No records for this court
                    l_tmp_str := get_no_data_line(court_rec.code);
                    p_write_to_blob(l_dataLOB, l_tmp_str);
                END IF;

            END LOOP;

            -- Write the CSV file to the database
            l_loaded := 'N';
            p_insert_csv_file(l_wft_file_name, grp_crt.wft_grouping_court, l_content_store_id, l_loaded);

            IF l_loaded = 'N' THEN
                DBMS_OUTPUT.PUT_LINE('Loading of '||l_wft_file_name||' for court '||grp_crt.wft_grouping_court||' failed!');
                l_error := 'Y';
            ELSE
                DBMS_OUTPUT.PUT_LINE('Loading of '||l_wft_file_name||' for court '||grp_crt.wft_grouping_court||' complete');
            END IF;

        EXCEPTION
            WHEN OTHERS THEN
                ROLLBACK;
                l_error := 'Y';
                DBMS_OUTPUT.PUT_LINE('Loading of '||l_wft_file_name||' for court '||grp_crt.wft_grouping_court||' failed! ' || SQLERRM);
                p_log_error(grp_crt.wft_grouping_court, SQLERRM);
        END;

    END LOOP;

    -- Update the WFT records so are not processed again
    p_post_extract_updates();

    IF l_error = 'Y' THEN
        -- Error processing at least one of the Grouping Courts
        RAISE_APPLICATION_ERROR(-20001,'Exception generating WFT Export');
    END IF;

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('Error in p_run_wft_export: ' ||SQLERRM);
        ROLLBACK;
        RAISE;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_run_wft_export_single_court
| DESCRIPTION  : Runs the WFT Export job for a single court after the WFT records have been updated
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_run_wft_export_single_court (p_grouping_crt IN courts.wft_grouping_court%TYPE
                                        ,p_export_date  IN VARCHAR2
                                        ,p_debug IN  VARCHAR2) IS

    CURSOR c_get_courts_in_group IS
    SELECT code
    FROM courts
    WHERE caseman_inservice = 'Y'
    AND sups_centralised_flag = 'Y'
    AND  wft_grouping_court = p_grouping_crt
    ORDER BY code;

    CURSOR c_get_current_wft_records (p_court_code NUMBER) IS
    SELECT wft_id, wft_case_number
    FROM window_for_trial
    WHERE TRUNC(wft_extracted_for_dm) = TO_DATE(p_export_date,'DD-Mon-YYYY')
    AND  wft_current_court = p_court_code;

    CURSOR c_get_previous_wft_records (p_court_code NUMBER) IS
    SELECT wft_id, wft_case_number  FROM window_for_trial
    WHERE TRUNC(wft_extracted_for_dm) = TO_DATE(p_export_date,'DD-Mon-YYYY')
    AND  wft_previous_court = p_court_code;

    l_prev_crt_count    NUMBER  := 0;
    l_curr_crt_count    NUMBER  := 0;
    l_loaded    VARCHAR2(1);
    l_wft_file_name VARCHAR2(30);
    l_tmp_str   VARCHAR2(2000);
    l_error    VARCHAR2(1) := 'N';
    l_export_date   DATE;

    l_dataLOB   BLOB;
    l_tempLOB   CLOB;

    l_content_store_id  content_store.id%TYPE;

BEGIN

    -- Set audit context
    set_sups_app_ctx('CCBC_BATCH', 0, 'WFTExport' );

    l_export_date := TO_DATE(p_export_date,'DD-Mon-YYYY');

    IF p_debug = 'Y' THEN
        DBMS_OUTPUT.PUT_LINE('Grouping Court: '||p_grouping_crt);
    END IF;

    -- Generate the file name
    SELECT p_grouping_crt||'WFT'||TO_CHAR(l_export_date,'YYYYMMDD_HH24MI')||'.csv' INTO l_wft_file_name FROM dual;

    SELECT  content_sequence.NEXTVAL
    INTO    l_content_store_id
    FROM    dual;

    -- create a record with an empty blob into which the file will be loaded
    INSERT INTO content_store (id, data)
    VALUES ( l_content_store_id, EMPTY_BLOB() )
    RETURNING DATA INTO l_dataLOB;

    -- Write the file header
    l_tmp_str := get_csv_header();
    p_write_to_blob( l_dataLOB, l_tmp_str );

    FOR court_rec IN c_get_courts_in_group LOOP

        -- Get count of unextracted WFT records for the court
        SELECT COUNT(*) INTO l_prev_crt_count FROM window_for_trial WHERE TRUNC(wft_extracted_for_dm) = TRUNC(l_export_date) AND wft_previous_court  = court_rec.code;
        SELECT COUNT(*) INTO l_curr_crt_count FROM window_for_trial WHERE TRUNC(wft_extracted_for_dm) = TRUNC(l_export_date) AND wft_current_court = court_rec.code;

        IF p_debug = 'Y' THEN
            DBMS_OUTPUT.PUT_LINE('Court: '||court_rec.code||' ('||l_prev_crt_count||' + '||l_curr_crt_count||') records');
        END IF;

        IF l_curr_crt_count > 0 THEN
            -- Retrieve WFT Records for Current Court
            FOR curr_wft_rec IN c_get_current_wft_records(court_rec.code) LOOP
                l_tempLOB := get_curr_crt_wft_line(court_rec.code, curr_wft_rec.wft_case_number, curr_wft_rec.wft_id);
                p_write_clob_to_blob(l_dataLOB, l_tempLOB);
            END LOOP;
        END IF;

        IF l_prev_crt_count > 0 THEN
            -- Retrieve WFT Records for Previous Court
            FOR prev_wft_rec IN c_get_previous_wft_records(court_rec.code) LOOP
                l_tempLOB := get_prev_crt_wft_line(court_rec.code, prev_wft_rec.wft_case_number, prev_wft_rec.wft_id);
                p_write_clob_to_blob(l_dataLOB, l_tempLOB);
            END LOOP;
        END IF;

        IF l_prev_crt_count = 0 AND l_curr_crt_count = 0 THEN
            -- No records for this court
            l_tmp_str := get_no_data_line(court_rec.code);
            p_write_to_blob(l_dataLOB, l_tmp_str);
        END IF;

    END LOOP;

    -- Write the CSV file to the database
    l_loaded := 'N';
    p_insert_csv_file(l_wft_file_name, p_grouping_crt, l_content_store_id, l_loaded);

    IF l_loaded = 'N' THEN
        DBMS_OUTPUT.PUT_LINE('Loading of '||l_wft_file_name||' for court '||p_grouping_crt||' failed!');
        l_error := 'Y';
    ELSE
        DBMS_OUTPUT.PUT_LINE('Loading of '||l_wft_file_name||' for court '||p_grouping_crt||' complete');
    END IF;

    IF l_error = 'Y' THEN
        -- Error processing at least one of the Grouping Courts
        RAISE_APPLICATION_ERROR(-20001,'Exception generating WFT Export');
    END IF;

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('Error in p_run_wft_export_single_court: ' ||SQLERRM);
        ROLLBACK;
        RAISE;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_delete_old_exports
| DESCRIPTION  : Deletes any exports that have passed their retention period
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_delete_old_exports IS

    CURSOR c_get_old_exports (p_ret_period NUMBER) IS
    SELECT report_queue_id
    FROM wft_exports
    WHERE export_date <= TRUNC(SYSDATE - p_ret_period);

    l_rq_id report_queue.id%TYPE;
    l_retention_period NUMBER;

BEGIN

    -- Extract the retention period of the WFT documents
    SELECT item_value INTO l_retention_period
    FROM system_data WHERE item = 'WFT_DOC_RETENTION' AND admin_court_code = 0;

    FOR rec IN c_get_old_exports(l_retention_period) LOOP

        -- Update the REPORT_QUEUE record so that the output is deleted
        -- as part of the sups_sheduled_jobs.cc_clear_document_store() batch job
        UPDATE report_queue SET storage_duration = 1 WHERE id = rec.report_queue_id;

    END LOOP;

    -- Delete the out of date WFT_EXPORTS records
    DELETE FROM wft_exports
    WHERE export_date <= TRUNC(SYSDATE - l_retention_period);

    COMMIT;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_post_extract_updates
| DESCRIPTION  : Performs the post extract updates on the window_for_trial records
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_post_extract_updates IS

BEGIN

    UPDATE window_for_trial SET wft_extracted_for_dm = SYSDATE
    WHERE wft_extracted_for_dm IS NULL;

    COMMIT;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_insert_csv_file
| DESCRIPTION  : Loads the WFT file contents into the report_queue, document_store, content_store
|                and the wft_exports tables
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_insert_csv_file (p_filename     IN VARCHAR2
                            ,p_grouping_crt IN courts.wft_grouping_court%TYPE
                            ,p_content_store_id IN content_store.id%TYPE
                            ,p_file_loaded  OUT VARCHAR2) IS

    n_content_store_id  NUMBER;
    n_document_store_id NUMBER;
    n_report_id         NUMBER;
    v_mime_type         VARCHAR2(15) := 'text/csv';
    n_user_id           VARCHAR2(10 CHAR);
    n_court_id          VARCHAR2(3 CHAR);
    v_metadata          VARCHAR2(250);

BEGIN
    p_file_loaded := 'Y';

    -- get the user id and court id
    n_user_id   := 'CCBC_BATCH';
    n_court_id  := TO_CHAR(p_grouping_crt);

    -- get the report id immediately as its needed to record errors
    SELECT  report_queue_sequence.NEXTVAL
    INTO    n_report_id
    FROM    dual;

    SELECT document_sequence.NEXTVAL
    INTO n_document_store_id
    FROM dual;

    -- populate Document_store
    v_metadata := '<document-headers><document-header><type>Content-Disposition</type><value>attachment;filename='||p_filename||'</value></document-header></document-headers>';

    INSERT INTO document_store (id, user_id , court_id, mime_type, is_viewed, is_persistent, content_store_id, created_date, metadata)
    VALUES     ( n_document_store_id  ,n_user_id , n_court_id , v_mime_type ,'F', 'T', p_content_store_id, SYSDATE, TO_CLOB(v_metadata));

    -- populate report_queue
    INSERT INTO report_queue (id, parent_id, status , mime_type, type , parameters, user_id , court_id, created_date, storage_duration, is_parent, document_id, send_status, print_status)
    VALUES      (n_report_id, n_report_id, 2, v_mime_type , 0 , '<params />', n_user_id , n_court_id , SYSDATE,  -1, 0, n_document_store_id, 0, 0);

    -- populate wft_exports
    INSERT INTO wft_exports (court_code, export_date, report_queue_id, filename)
    VALUES      (p_grouping_crt, TRUNC(SYSDATE), n_report_id, p_filename);

    COMMIT;

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        p_file_loaded := 'N';
        DBMS_OUTPUT.PUT_LINE('Error in p_insert_csv_file for court '||n_court_id||': '||SQLERRM);
        p_log_error(p_grouping_crt, SQLERRM);

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_write_to_blob
| DESCRIPTION  : Writes the CSV content to the CONTENT_STORE.DATA BLOB column
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_write_to_blob (p_destLob IN OUT BLOB, p_buffer IN VARCHAR2) IS

    amt BINARY_INTEGER;
    l_buffer RAW(32000);

BEGIN

    DBMS_LOB.OPEN(p_destLob, DBMS_LOB.LOB_READWRITE);

    l_buffer := UTL_RAW.CAST_TO_RAW(p_buffer);
    amt := UTL_RAW.LENGTH(l_buffer);

    DBMS_LOB.WRITEAPPEND(p_destLob, amt, l_buffer);

    DBMS_LOB.CLOSE(p_destLob);

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('p_write_to_blob: ' ||SQLERRM);
        RAISE;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_write_clob_to_blob
| DESCRIPTION  : Writes the CSV content to the CONTENT_STORE.DATA BLOB column
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_write_clob_to_blob (p_destLob IN OUT BLOB, p_buffer IN CLOB) IS

    v_offset NUMBER DEFAULT 1;
    v_amount NUMBER DEFAULT 4096;
    v_amountwrite NUMBER;
    v_buffer VARCHAR2(4096 CHAR);

BEGIN

    DBMS_LOB.OPEN(p_destLob, DBMS_LOB.LOB_READWRITE);

    BEGIN
    LOOP
        DBMS_LOB.READ (lob_loc => p_buffer,
                       amount  => v_amount,
                       offset  => v_offset,
                       buffer  => v_buffer);

        v_amountwrite := UTL_RAW.LENGTH (r => UTL_RAW.CAST_TO_RAW(c => v_buffer));

        DBMS_LOB.WRITEAPPEND( p_destLob, v_amountwrite, UTL_RAW.CAST_TO_RAW(v_buffer) );

        v_offset := v_offset + v_amount;
        v_amount := 4096;
    END LOOP;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            NULL;
    END;

    DBMS_LOB.CLOSE(p_destLob);

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('p_write_clob_to_blob: ' ||SQLERRM);
        RAISE;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : append_large_varchar
| DESCRIPTION  : Appends a varchar2 which when gets too big, gets written to a CLOB instead
------------------------------------------------------------------------------------------------------*/
PROCEDURE append_large_varchar(v_clob IN OUT NOCOPY CLOB, v_vc IN OUT NOCOPY VARCHAR2, v_app VARCHAR2) IS
BEGIN
    v_vc := v_vc || v_app;
EXCEPTION
    WHEN VALUE_ERROR THEN
        IF v_clob IS NULL THEN
            v_clob := v_vc;
        ELSE
            DBMS_LOB.APPEND(v_clob, v_vc);
        END IF;
        v_vc := v_app;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_csv_header
| DESCRIPTION  : Writes the standard file header
------------------------------------------------------------------------------------------------------*/
FUNCTION get_csv_header RETURN VARCHAR2 IS

    pv_file_line VARCHAR2(500);

BEGIN

    pv_file_line := 'CLAIM NUMBER,any ZDIARYMAIN CLAIMANT,any ZDIARYMAIN DEFENDANT,Track,DAYS,HOURS,MINUTES,From,To,COURT,' ||
                    'STATUS,OUTCOME DATE,JUDGES NAME,REASON FOR ADJOURNMENT,CMC FLAG,CMC DATE,NOTES,EXCLUDED DATES'||CHR(13);

    RETURN pv_file_line;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_no_data_line
| DESCRIPTION  : Writes the no data line
------------------------------------------------------------------------------------------------------*/
FUNCTION get_no_data_line (p_code IN courts.code%TYPE) RETURN VARCHAR2 IS

    pv_file_line VARCHAR(500);

BEGIN

    SELECT 'No_records_retrieved_for_ ' || name || ',,,,,,,,,,,,,,,,,' || CHR(13)
    INTO pv_file_line
    FROM courts
    WHERE code = p_code;

    RETURN pv_file_line;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_curr_crt_wft_line
| DESCRIPTION  : Writes a WFT record line for the current court
------------------------------------------------------------------------------------------------------*/
FUNCTION get_curr_crt_wft_line (p_crt_code IN courts.code%TYPE
                                  ,p_case_number IN cases.case_number%TYPE
                                  ,p_wft_id IN window_for_trial.wft_id%TYPE) RETURN CLOB IS

    CURSOR  c_get_exclusions IS
    SELECT  TO_CHAR( wfe.wfe_exclusion_date,'DD/MM/YYYY')||'; '
    FROM    wft_exclusions wfe, window_for_trial w
    WHERE   wfe.wfe_wft_case_number = w.wft_case_number
    AND     w.wft_case_number = p_case_number
    AND     w.wft_id = p_wft_id
    AND     wfe.wfe_wft_id = w.wft_id
    AND     w.wft_current_court=p_crt_code;

    TYPE t_exclusions IS TABLE OF VARCHAR2(15);
    lst_exclusions t_exclusions;

    pv_file_line VARCHAR(4000);
    l_curr_crt_excl_count   NUMBER;
    pc_CLOB CLOB;

BEGIN

    pc_CLOB := NULL;

    SELECT
        w.wft_case_number ||',"'||
        (SELECT dc.person_requested_name FROM parties dc, window_for_trial wc, case_party_roles cpc, courts coc
            WHERE wc.wft_case_number    = cpc.case_number
            AND   wc.wft_case_number    = w.wft_case_number
            AND   wc.wft_id         = w.wft_id
            AND   dc.party_id       = cpc.party_id
            AND   cpc.party_role_code   = 'CLAIMANT'
            AND   cpc.case_party_no     = 1
            AND   wc.wft_current_court       = coc.code
            AND   wc.wft_current_court  = p_crt_code) ||'","' ||
        (SELECT dc.person_requested_name FROM parties dc, window_for_trial wc, case_party_roles cpc, courts coc
            WHERE wc.wft_case_number    = cpc.case_number
            AND   wc.wft_case_number    = w.wft_case_number
            AND   wc.wft_id         = w.wft_id
            AND   dc.party_id       = cpc.party_id
            AND   cpc.party_role_code   = 'DEFENDANT'
            AND   cpc.case_party_no     = 1
            AND   wc.wft_current_court       = coc.code
            AND   wc.wft_current_court  = p_crt_code) ||'",' ||
        DECODE(w.wft_track,'MULTI','Multi','FAST','Fast',w.wft_track) ||',' ||
        TO_CHAR(w.wft_estimated_days) ||',' ||
        TO_CHAR(w.wft_estimated_hours) ||',' ||
        TO_CHAR(w.wft_estimated_mins) ||',' ||
        TO_CHAR(w.wft_start_date,'DD/MM/YYYY') ||',' ||
        TO_CHAR(w.wft_end_date,'DD/MM/YYYY') ||',' ||
        DECODE(co.code, 238, 'KINGS LYNN', co.name) ||',' ||
        w.wft_status ||',' ||
        TO_CHAR(w.wft_outcome_date,'DD/MM/YYYY') ||',' ||
        w.wft_judges_name ||',' ||
        w.wft_reason_for_adj ||',' ||
        w.wft_case_manage_conf_flag ||',' ||
        TO_CHAR(w.wft_case_manage_conf_date,'DD/MM/YYYY') ||',"' ||
        w.wft_notes ||'",'
    INTO pv_file_line
    FROM  window_for_trial w, courts co
    WHERE w.wft_current_court       = co.code
    AND   w.wft_current_court   = p_crt_code
    AND   w.wft_case_number = p_case_number
    AND   w.wft_id = p_wft_id
    ORDER BY w.wft_case_number, w.wft_id;

    -- Retrieve WFT Exclusions Date Count (Current Court)
    SELECT  COUNT(*) INTO l_curr_crt_excl_count
    FROM    wft_exclusions wfe, window_for_trial w
    WHERE   wfe.wfe_wft_case_number = w.wft_case_number
    AND     w.wft_case_number = p_case_number
    AND     w.wft_id = p_wft_id
    AND     wfe.wfe_wft_id = w.wft_id
    AND     w.wft_current_court = p_crt_code;

    -- If exclusion dates exist, extract them
    IF l_curr_crt_excl_count > 0 THEN
        OPEN c_get_exclusions;
        FETCH c_get_exclusions
        BULK COLLECT INTO lst_exclusions;

        FOR i IN 1..lst_exclusions.COUNT
        LOOP
            append_large_varchar(pc_CLOB, pv_file_line, lst_exclusions(i));
        END LOOP;

        lst_exclusions.DELETE;
        CLOSE c_get_exclusions;
    END IF;

    append_large_varchar(pc_CLOB, pv_file_line, ',' || CHR(13));
    pc_CLOB := pc_CLOB || pv_file_line;

    RETURN pc_CLOB;

END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : FUNCTION
| NAME         : get_prev_crt_wft_line
| DESCRIPTION  : Writes a WFT record line for the previous court
------------------------------------------------------------------------------------------------------*/
FUNCTION get_prev_crt_wft_line (p_crt_code IN courts.code%TYPE
                                  ,p_case_number IN cases.case_number%TYPE
                                  ,p_wft_id IN window_for_trial.wft_id%TYPE) RETURN CLOB IS

    CURSOR  c_get_exclusions IS
    SELECT  TO_CHAR( wfe.wfe_exclusion_date,'DD/MM/YYYY')||'; '
    FROM    wft_exclusions wfe, window_for_trial w
    WHERE   wfe.wfe_wft_case_number = w.wft_case_number
    AND     w.wft_case_number = p_case_number
    AND     w.wft_id = p_wft_id
    AND     wfe.wfe_wft_id = w.wft_id
    AND     w.wft_previous_court=p_crt_code;

    TYPE t_exclusions IS TABLE OF VARCHAR2(15);
    lst_exclusions t_exclusions;

    pv_file_line VARCHAR(4000);
    l_prev_crt_excl_count   NUMBER;
    pc_CLOB CLOB;

BEGIN

    pc_CLOB := NULL;

    SELECT
        w.wft_case_number || ',"' ||
        (SELECT dc.person_requested_name FROM parties dc, window_for_trial wc, case_party_roles cpc, courts coc
            WHERE wc.wft_case_number    = cpc.case_number
            AND   wc.wft_case_number    = w.wft_case_number
            AND   wc.wft_id         = w.wft_id
            AND   dc.party_id       = cpc.party_id
            AND   cpc.party_role_code   = 'CLAIMANT'
            AND   cpc.case_party_no     = 1
            AND   wc.wft_previous_court       = coc.code
            AND   wc.wft_previous_court = p_crt_code) || '","' ||
        (SELECT dc.person_requested_name FROM parties dc, window_for_trial wc, case_party_roles cpc, courts coc
            WHERE wc.wft_case_number    = cpc.case_number
            AND   wc.wft_case_number    = w.wft_case_number
            AND   wc.wft_id         = w.wft_id
            AND   dc.party_id       = cpc.party_id
            AND   cpc.party_role_code   = 'DEFENDANT'
            AND   cpc.case_party_no     = 1
            AND   wc.wft_previous_court       = coc.code
            AND   wc.wft_previous_court = p_crt_code) || '",' ||
        DECODE(w.wft_track,'MULTI','Multi','FAST','Fast',w.wft_track) || ',' ||
        TO_CHAR(w.wft_estimated_days) || ',' ||
        TO_CHAR(w.wft_estimated_hours) || ',' ||
        TO_CHAR(w.wft_estimated_mins) || ',' ||
        TO_CHAR(w.wft_start_date,'DD/MM/YYYY') || ',' ||
        TO_CHAR(w.wft_end_date,'DD/MM/YYYY') || ',' ||
        DECODE(co.code, 238, 'KINGS LYNN', co.name) || ',' ||
        'TRANSFERRED' || ',' ||
        TO_CHAR(w.wft_outcome_date,'DD/MM/YYYY') || ',' ||
        w.wft_judges_name || ',' ||
        w.wft_reason_for_adj || ',' ||
        w.wft_case_manage_conf_flag || ',' ||
        TO_CHAR(w.wft_case_manage_conf_date,'DD/MM/YYYY') || ',"' ||
        w.wft_notes||'",'
    INTO pv_file_line
    FROM  window_for_trial w, courts co
    WHERE w.wft_previous_court       = co.code
    AND   w.wft_previous_court  = p_crt_code
    AND   w.wft_case_number = p_case_number
    AND   w.wft_id = p_wft_id
    ORDER BY w.wft_case_number, w.wft_id;

    -- Retrieve WFT Exclusions Date Count (Previous Court)
    SELECT  COUNT(*) INTO l_prev_crt_excl_count
    FROM    wft_exclusions wfe, window_for_trial w
    WHERE   wfe.wfe_wft_case_number = w.wft_case_number
    AND     w.wft_case_number = p_case_number
    AND     w.wft_id = p_wft_id
    AND     wfe.wfe_wft_id = w.wft_id
    AND     w.wft_previous_court = p_crt_code;

    -- If exclusion dates exist, extract them and build them into a string
    IF l_prev_crt_excl_count > 0 THEN
        OPEN c_get_exclusions;
        FETCH c_get_exclusions
        BULK COLLECT INTO lst_exclusions;

        FOR i IN 1..lst_exclusions.COUNT
        LOOP
            append_large_varchar(pc_CLOB, pv_file_line, lst_exclusions(i));
        END LOOP;

        lst_exclusions.DELETE;
        CLOSE c_get_exclusions;
    END IF;

    append_large_varchar(pc_CLOB, pv_file_line, ',' || CHR(13));
    pc_CLOB := pc_CLOB || pv_file_line;

    RETURN pc_CLOB;
END;

/*------------------------------------------------------------------------------------------------------
| TYPE         : PROCEDURE
| NAME         : p_log_error
| DESCRIPTION  : Writes an error message to the TRANSFER_ERROR_LOG table
------------------------------------------------------------------------------------------------------*/
PROCEDURE p_log_error (p_court_code IN NUMBER, p_err IN VARCHAR2) IS

BEGIN

    INSERT INTO transfer_error_log
    (transfer_date, transfer_type, sending_court, case_number, error_message)
    VALUES
    (TRUNC(SYSDATE), NULL, p_court_code, NULL, p_err);

    COMMIT;
END;

END wft_export_pkg;
/


